# ---------------------------------------------------------------------------
# Email utility  -  Gmail SMTP
# Env vars: MAIL_USERNAME, MAIL_PASSWORD
# Falls back silently if not configured  -  never crashes the app
# ---------------------------------------------------------------------------

def send_email(to_addresses, subject, html_body, text_body=None, attachments=None):
    """
    Send email via Brevo (HTTP API)  -  works on Railway (no SMTP port restrictions).
    Env var: BREVO_API_KEY
    to_addresses: str (single) or list of str.
    attachments: optional list of local file paths to attach (e.g. sample
                 scorecard JPG). Each file is read and base64-encoded into
                 the Brevo payload. Missing files are skipped with a warning
                 rather than failing the whole send.
    Returns True on success, False on failure.
    """
    import urllib.request
    import json as _json
    import base64 as _base64

    api_key = os.getenv('BREVO_API_KEY', '')
    if not api_key:
        app.logger.warning('[email] BREVO_API_KEY not set  -  skipping send')
        return False

    if isinstance(to_addresses, str):
        to_addresses = [to_addresses]

    sender_email = os.getenv('MAIL_USERNAME', CONTACT_EMAIL)
    # Safety net: if MAIL_USERNAME is a freemail address, override with support@shutterleague.com
    _freemail_domains = ('gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'live.com')
    if any(sender_email.lower().endswith('@' + d) for d in _freemail_domains):
        app.logger.warning(f'[email] MAIL_USERNAME is freemail ({sender_email}) — overriding with support@shutterleague.com')
        sender_email = 'support@shutterleague.com'
    # Strip [Shutter League] prefix — square brackets trigger spam filters
    import re as _re
    clean_subject = _re.sub(r'^\[Shutter League\]\s*', 'Shutter League — ', subject)

    payload = {
        'sender':     {'name': PLATFORM_NAME, 'email': sender_email},
        'replyTo':    {'name': PLATFORM_NAME, 'email': sender_email},
        'to':         [{'email': addr} for addr in to_addresses],
        'subject':    clean_subject,
        'htmlContent': html_body,
    }
    if text_body:
        payload['textContent'] = text_body

    if attachments:
        attachment_list = []
        for file_path in attachments:
            try:
                with open(file_path, 'rb') as f:
                    content_b64 = _base64.b64encode(f.read()).decode('ascii')
                attachment_list.append({
                    'content': content_b64,
                    'name':    os.path.basename(file_path),
                })
            except Exception as _attach_err:
                app.logger.warning(f'[email] Could not attach {file_path}: {_attach_err}')
        if attachment_list:
            payload['attachment'] = attachment_list

    data = _json.dumps(payload).encode('utf-8')
    req  = urllib.request.Request(
        'https://api.brevo.com/v3/smtp/email',
        data=data,
        headers={
            'accept':       'application/json',
            'content-type': 'application/json',
            'api-key':      api_key,
        },
        method='POST',
    )

    try:
        with urllib.request.urlopen(req, timeout=15) as resp:
            if resp.status in (200, 201):
                app.logger.info(f'[email] Sent "{subject}" to {to_addresses}')
                return True
            else:
                body = resp.read().decode()
                app.logger.error(f'[email] Brevo returned {resp.status}: {body}')
                return False
    except Exception as e:
        app.logger.error(f'[email] Failed to send "{subject}": {e}')
        return False



