@app.route('/auth/google/callback')
def auth_google_callback():
    try:
        token = google.authorize_access_token()
    except Exception as e:
        err = str(e)
        app.logger.warning(f'[google_oauth] callback error: {err}')
        if 'mismatching_state' in err or 'MismatchingState' in err or 'state' in err.lower():
            flash('Sign-in interrupted — please try signing in again.', 'error')
        else:
            flash('Google sign-in failed. Please try again.', 'error')
        return redirect(url_for('login'))
    userinfo = token.get('userinfo') or google.userinfo()
    google_id = userinfo.get('sub')
    email     = userinfo.get('email', '').lower().strip()
    name      = userinfo.get('name', '')

    if not google_id or not email:
        flash('Google sign-in failed  -  no email returned. Please try again.', 'error')
        return redirect(url_for('login'))

    # Find existing user by google_id or email
    user = User.query.filter_by(google_id=google_id).first()
    if not user:
        user = User.query.filter_by(email=email).first()

    if user:
        # Existing user  -  update google_id if not set
        if not user.google_id:
            user.google_id = google_id
        user.last_login = datetime.utcnow()
        db.session.commit()
        login_user(user, remember=True)
        if not getattr(user, 'onboarding_complete', True):
            return redirect(url_for('onboarding'))
        # Check if this user is an approved judge -- send to jury dashboard
        judge_check = db.session.execute(
            db.text("SELECT id FROM judges WHERE user_id = :uid AND status = 'approved'"),
            {'uid': user.id}
        ).fetchone()
        if judge_check:
            return redirect(url_for('judge_dashboard'))
        if not getattr(user, 'interests_complete', False):
            return redirect(url_for('onboarding_interests'))
        # Redirect to stored next URL if available
        post_next = session.pop('post_login_next', None)
        if post_next:
            return redirect(post_next)
        return redirect(url_for('dashboard'))
    else:
        # New user — check allowlist before creating account
        if not is_email_allowed(email):
            flash('Registration is currently by invitation only. Contact us to request access.', 'error')
            return redirect(url_for('login'))
        # New user  -  create account, send to onboarding
        import re
        base_username = re.sub(r'[^a-zA-Z0-9_]', '', name.replace(' ', '_').lower()) or 'photographer'
        username = base_username
        suffix = 1
        while User.query.filter_by(username=username).first():
            username = f'{base_username}{suffix}'
            suffix += 1

        user = User(
            email=email,
            username=username,
            full_name=name,
            google_id=google_id,
            onboarding_complete=False,
            agreed_at=datetime.utcnow(),
            is_active=True,
        )
        db.session.add(user)
        db.session.commit()
        try:
            _ref_code = request.cookies.get('sl_ref')
            if _ref_code:
                _ref_row = db.session.execute(
                    db.text('SELECT user_id FROM referral_codes WHERE code = :c'),
                    {'c': _ref_code}
                ).fetchone()
                if _ref_row and _ref_row[0] != user.id:
                    _existing = db.session.execute(
                        db.text('SELECT id FROM referrals WHERE referred_user_id = :uid'),
                        {'uid': user.id}
                    ).fetchone()
                    _referrer_count = db.session.execute(
                        db.text('SELECT COUNT(*) FROM referrals WHERE referrer_id = :rid'),
                        {'rid': _ref_row[0]}
                    ).scalar() or 0
                    if not _existing and _referrer_count < 10:
                        db.session.execute(
                            db.text('INSERT INTO referrals (referrer_id, referred_user_id, code_used) '
                                    'VALUES (:rid, :nid, :code)'),
                            {'rid': _ref_row[0], 'nid': user.id, 'code': _ref_code}
                        )
                        db.session.execute(
                            db.text('UPDATE users SET referred_discount = TRUE WHERE id = :uid'),
                            {'uid': user.id}
                        )
                        db.session.commit()
                        app.logger.info(f'[referral] google signup: referrer={_ref_row[0]} referred={user.id}')
                    elif _referrer_count >= 10:
                        app.logger.info(f'[referral] cap reached for referrer={_ref_row[0]} — skipping')
        except Exception as _rgo:
            app.logger.error(f'[referral] auth_google_callback hook: {_rgo}')
        login_user(user, remember=True)
        return redirect(url_for('onboarding'))


@app.route('/onboarding', methods=['GET', 'POST'])
@login_required
def onboarding():
    if getattr(current_user, 'onboarding_complete', True):
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        country = request.form.get('country', '').strip()
        state   = request.form.get('state', '').strip()
        city    = request.form.get('city', '').strip()
        agreed  = request.form.get('agreed')
        terms   = request.form.get('terms')

        if not country or not state or not city:
            flash('Please select your country, state/province, and city.', 'error')
            return redirect(url_for('onboarding'))

        # For countries without detailed state/city data, State and City
        # come from free-text inputs — validate + normalise, and log for
        # admin review (mirrors GenreSuggestion's 'Other' genre pattern).
        if not has_detailed_location_data(country):
            _state_norm = _validate_location_text(state)
            _city_norm  = _validate_location_text(city)
            if not _state_norm or not _city_norm:
                flash('Please enter a valid state/province and city (letters, spaces, hyphens, and apostrophes only).', 'error')
                return redirect(url_for('onboarding'))
            state, city = _state_norm, _city_norm
            _log_location_suggestion(current_user.id, country, state, city)

        if not agreed:
            flash('Please accept the Member Agreement to continue.', 'error')
            return redirect(url_for('onboarding'))
        if not terms:
            flash('Please accept the Terms & Conditions to continue.', 'error')
            return redirect(url_for('onboarding'))

        now = datetime.utcnow()
        current_user.country             = country
        current_user.state               = state
        current_user.city                = city
        current_user.agreed_at           = now
        current_user.terms_accepted_at   = now
        current_user.terms_version       = TERMS_VERSION
        current_user.signup_ip           = request.remote_addr
        current_user.onboarding_complete = True
        db.session.commit()
        try:
            send_welcome_email(current_user)
        except Exception as _we:
            app.logger.warning('[welcome_email] Error: ' + str(_we))
        flash('Welcome to Shutter League! Your account is ready.', 'success')
        # Go to interests flow before dashboard
        return redirect(url_for('onboarding_interests'))

    try:
        _ref_discount_ob = db.session.execute(
            db.text('SELECT referred_discount FROM users WHERE id = :uid'),
            {'uid': current_user.id}
        ).scalar() or False
    except Exception:
        _ref_discount_ob = False
    return render_template('onboarding.html',
        countries          = get_countries(),
        location_data_json = json.dumps(_dash_loc()),
        referred_discount  = _ref_discount_ob,
    )


@app.route('/onboarding-interests', methods=['GET', 'POST'])
@login_required
def onboarding_interests():
    """
    Post-onboarding interest capture — genre, frequency, motivation.
    Fires once after the welcome/KYC onboarding screen.
    Mandatory: exactly 3 genres required (predefined or custom 'Other' entries).
    Skipped if interests_complete is already True.
    """
    # Skip if already done or onboarding not yet complete
    if not getattr(current_user, 'onboarding_complete', False):
        return redirect(url_for('onboarding'))
    if getattr(current_user, 'interests_complete', False):
        post_next = session.pop('post_login_next', None)
        return redirect(post_next or url_for('dashboard'))

    STANDARD_GENRES = ['Wildlife', 'Street', 'Landscape', 'People', 'Wedding',
                       'Macro', 'Drone & Aerial', 'Creative']

    if request.method == 'POST':
        import json as _json
        genre_interests    = request.form.get('genre_interests', '').strip()
        shooting_frequency = request.form.get('shooting_frequency', '').strip()
        primary_motivation = request.form.get('primary_motivation', '').strip()

        # Validate genre_interests is a JSON array of exactly 3 non-empty strings
        try:
            _genres = _json.loads(genre_interests) if genre_interests else []
            if not isinstance(_genres, list):
                _genres = []
            _genres = [g.strip() for g in _genres if isinstance(g, str) and g.strip()][:3]
        except Exception:
            _genres = []

        if len(_genres) != 3:
            flash('Please select exactly 3 genres to continue.', 'error')
            return redirect(url_for('onboarding_interests'))

        # Log any custom ('Other') genres not in the standard list for admin review
        for _g in _genres:
            if _g not in STANDARD_GENRES:
                try:
                    db.session.add(GenreSuggestion(user_id=current_user.id, suggested_genre=_g[:60]))
                except Exception as _gse:
                    app.logger.warning(f'[genre_suggestion] {_gse}')

        genre_interests = _json.dumps(_genres)

        current_user.genre_interests    = genre_interests
        current_user.shooting_frequency = shooting_frequency[:30] if shooting_frequency else None
        current_user.primary_motivation = primary_motivation[:40] if primary_motivation else None
        current_user.interests_complete = True
        db.session.commit()
        app.logger.info(
            f'[onboarding_interests] user={current_user.id} '
            f'genres={genre_interests} freq={shooting_frequency} motivation={primary_motivation}'
        )

        # Item D — this is the FIRST point a brand-new user has both city
        # (set in /onboarding) and genres (just set above) confirmed. The
        # other two priority-discovery call sites (GPS confirm, settings
        # update) only cover users CHANGING an existing city — new signups
        # never hit either, so their city/genre combos sat waiting for the
        # weekly general sweep with no priority. Mirrors that same pattern.
        if current_user.city and current_user.city != 'Other':
            try:
                from engine.seasonal_discovery import enqueue_priority_combo
                for _g in _genres:
                    if _g:
                        enqueue_priority_combo(db.session, current_user.city, _g)
            except Exception as _disc_err:
                app.logger.warning(f'[onboarding_interests] priority discovery enqueue failed: {_disc_err}')

        post_next = session.pop('post_login_next', None)
        return redirect(post_next or url_for('dashboard'))

    return render_template('onboarding_interests.html')



@app.route('/login', methods=['GET', 'POST'])
def login():
    if current_user.is_authenticated:
        # Judge already logged in -- send to jury dashboard
        _jc = db.session.execute(
            db.text("SELECT id FROM judges WHERE user_id = :uid AND status = 'approved'"),
            {'uid': current_user.id}
        ).fetchone()
        if _jc:
            return redirect(url_for('judge_dashboard'))
        return redirect(url_for('dashboard'))


    # Store ?next= in session on GET so Google OAuth callback can redirect
    # correctly after login. Email/password path reads request.args directly.
    # Google OAuth goes to /auth/google without ?next= so we cache it here.
    if request.method == 'GET':
        _next = request.args.get('next', '').strip()
        if _next:
            session['post_login_next'] = _next

    if request.method == 'POST':
        email    = request.form.get('email', '').strip().lower()
        password = request.form.get('password', '')

        if not email or not password:
            flash('Please enter your email and password.', 'error')
            return render_template('login.html')

        user = User.query.filter_by(email=email).first()

        if not user or not user.password_hash:
            flash('Invalid email or password.', 'error')
            return render_template('login.html')

        if not check_password_hash(user.password_hash, password):
            flash('Invalid email or password.', 'error')
            return render_template('login.html')

        if not user.is_active:
            flash('This account has been deactivated.', 'error')
            return render_template('login.html')

        user.last_login = datetime.utcnow()
        db.session.commit()
        login_user(user, remember=True)

        next_url = request.args.get('next')
        if next_url:
            return redirect(next_url)
        if user.role == 'admin':
            return redirect(url_for('admin_dashboard'))
        # Check if this user is an approved judge -- send to jury dashboard
        judge_check = db.session.execute(
            db.text("SELECT id FROM judges WHERE user_id = :uid AND status = 'approved'"),
            {'uid': user.id}
        ).fetchone()
        if judge_check:
            return redirect(url_for('judge_dashboard'))
        if getattr(user, 'onboarding_complete', False) and not getattr(user, 'interests_complete', False):
            return redirect(url_for('onboarding_interests'))
        return redirect(url_for('dashboard'))

    return render_template('login.html')


