@app.route('/forgot-password', methods=['GET', 'POST'])
def forgot_password():
    if request.method == 'POST':
        step  = int(request.form.get('step', 1))
        email = request.form.get('email', '').strip().lower()
        if step == 1:
            user = User.query.filter_by(email=email).first()
            if not user:
                flash('No account found with that email address.', 'error')
                return render_template('forgot_password.html', step=1)
            if not user.security_question:
                flash('This account has no security question set. Please contact support.', 'error')
                return render_template('forgot_password.html', step=1)
            return render_template('forgot_password.html', step=2, email=email,
                                   security_question=user.security_question)
        elif step == 2:
            user   = User.query.filter_by(email=email).first()
            answer = request.form.get('security_answer', '').strip().lower()
            if not user or user.security_answer != answer:
                flash('Incorrect answer. Please try again.', 'error')
                return render_template('forgot_password.html', step=2, email=email,
                                       security_question=user.security_question if user else '')
            return render_template('forgot_password.html', step=3, email=email)
        elif step == 3:
            new_pw  = request.form.get('new_password', '')
            confirm = request.form.get('confirm_password', '')
            user    = User.query.filter_by(email=email).first()
            if not user:
                flash('Session expired. Please start again.', 'error')
                return redirect(url_for('forgot_password'))
            if len(new_pw) < 8:
                flash('Password must be at least 8 characters.', 'error')
                return render_template('forgot_password.html', step=3, email=email)
            if new_pw != confirm:
                flash('Passwords do not match.', 'error')
                return render_template('forgot_password.html', step=3, email=email)
            user.password_hash = generate_password_hash(new_pw)
            db.session.commit()
            flash('Password reset successfully. Please log in with your new password.', 'success')
            return redirect(url_for('login'))
    return render_template('forgot_password.html', step=1)


@app.route('/mission')
@login_required
def mission():
    """Mission Details — Screen 2 of the assignment sequence.
    Powered by Photo School curriculum — same lesson as dashboard card.
    """
    progress_data    = _build_progress_data(current_user)
    active_challenge = _get_active_challenge()

    # ── Get today's curriculum lesson (same as dashboard) ────────────────
    lesson = None
    try:
        lesson = _get_curriculum_lesson(current_user, progress_data)
    except Exception as _le:
        app.logger.warning(f'[mission curriculum] {_le}')

    # ── Weather (same as dashboard) ──────────────────────────────────────
    _weather = {'state': 'green', 'condition': 'Any light works',
                'message': None, 'window': None}
    try:
        _wx_city = getattr(current_user, 'city', '') or ''
        if _wx_city:
            _weather = _get_weather(_wx_city)
    except Exception as _we:
        app.logger.warning(f'[mission weather] {_we}')

    # ── Build assignment object from lesson ──────────────────────────────
    _dim_mobile = {
        'dod': 'Technical', 'dm': 'Timing', 'aq': 'Visual Impact',
        'wonder': 'Wonder', 'disruption': 'Disruption'
    }
    _best_time_map = {
        'dod': '6:00 – 9:00 AM', 'dm': '6:00 – 9:00 AM',
        'aq':  '6:00 – 8:00 AM', 'wonder': 'Any time',
        'disruption': '5:00 – 7:00 PM'
    }

    # Tips per dimension — 4 specific tips aligned to curriculum principle
    _tips_map = {
        'dod': [
            'Name the one thing that made this shot hard before you raise the camera',
            'Find the position you would normally avoid — that is the one to take',
            'Physical difficulty shows in the image — get closer, lower, or earlier',
            'The harder the shot, the more the frame earns its score',
        ],
        'dm': [
            'Build the frame before the moment arrives — position first, wait second',
            'Read the scene for five minutes without shooting',
            'The geometry and the gesture must both be right simultaneously',
            'Stay with the scene — the decisive moment is rarely the first one',
        ],
        'aq': [
            'Name the emotion before you raise the camera — then expose for it',
            'Light determines the feeling before the subject does',
            'Find one strong light source and let it do the work',
            'The specific emotion is more powerful than a general sense of mood',
        ],
        'wonder': [
            'Walk slowly — the subject is not rare, the seeing is',
            'Photograph what everyone else walks past',
            'Go lower, higher, or closer than feels natural',
            'The unremarkable corner is often the interesting one',
        ],
        'disruption': [
            'Every subject has a default photograph — refuse it',
            'Put your subject off-centre deliberately',
            'Leave more empty space than feels right',
            'The uncomfortable frame is usually the interesting one',
        ],
    }

    if lesson:
        _focus_key  = lesson['dim']
        _title      = lesson['title']
        _desc       = lesson['principle']
        _assignment = lesson['assignment']
        _tips       = _tips_map.get(_focus_key, _tips_map['dm'])
        _best_time  = _best_time_map.get(_focus_key, '6:00 – 9:00 AM')
        _weather_str = _weather.get('condition') or 'Any light works'
        _focus_label = _dim_mobile.get(_focus_key, 'Timing')
        _genre       = lesson.get('mission_genre') or 'Wildlife'

        # Master — only on master days
        _master = None
        if lesson.get('show_master') and lesson.get('master'):
            _master = (
                lesson['master'],
                '',  # bio slot — not used in mission_detail
                lesson.get('master_quote', ''),
                lesson.get('master_quote', ''),
            )
    else:
        # Fallback — no progress data yet
        _focus_key   = progress_data.get('weakest', 'dm') if progress_data else 'dm'
        _title       = 'Today\'s Assignment'
        _desc        = 'One frame. Make it count.'
        _assignment  = 'Find one subject. Build the frame before the moment arrives.'
        _tips        = _tips_map.get(_focus_key, _tips_map['dm'])
        _best_time   = _best_time_map.get(_focus_key, '6:00 – 9:00 AM')
        _weather_str = _weather.get('condition') or 'Any light works'
        _focus_label = _dim_mobile.get(_focus_key, 'Timing')
        _genre       = 'Wildlife'
        _master      = None

    # ── Indoor override — if user chose an indoor option, swap assignment text ──
    # ?indoor=portraits or ?indoor=stilllife arrives from the dashboard red-weather card.
    # Replaces the outdoor assignment with the lesson's indoor_assignment text.
    _indoor = request.args.get('indoor') or None
    if _indoor and lesson and lesson.get('indoor_assignment'):
        _assignment = lesson['indoor_assignment']
        _title = _title + ' — indoors'

    # ── Reference image — Tier 1: community (exact), Tier 2: Pixabay, ─────
    # ── Tier 3: community (genre-only) ─────────────────────────────────────
    # Tier 1: a community photo matching BOTH genre AND dimension
    # (score >= 8.5). This genre filter is the actual root-cause fix — the
    # old query only filtered by dimension, and its fallback dropped even
    # that, showing literally the highest-scoring public photo on the whole
    # platform regardless of genre. That's how a Wildlife lesson once
    # showed a street protest photo as its reference image. Every tier
    # below still filters by genre for this same reason — only the
    # dimension match loosens, never the genre match.
    # Tier 2: no genre+dimension community photo yet -> live Pixabay search
    # using genre + dimension keywords (engine/stock_images.py), instead of
    # the old "show anything" fallback.
    # Tier 3: still nothing (Pixabay cache miss, background fetch still
    # pending, or the cache table itself unreachable) -> broaden to any
    # genre-matched community photo at 8.0+, dropping the dimension
    # requirement only. Genuinely empty only when this platform has no
    # public 8.0+ photo at all yet in that genre — at that point the
    # template's dark placeholder is the honest answer, not a bug.
    # commons_file (curriculum_data.py) is a separate, deliberately
    # genre-agnostic system for illustrating a principle with an iconic
    # historical photo — not touched here.
    _benchmark   = None
    _pixabay_url = None
    try:
        _benchmark = (Image.query
                      .filter_by(status='scored', is_public=True, is_flagged=False)
                      .filter(Image.mission_dimension == _focus_key,
                              Image.genre == _genre,
                              Image.score >= 8.5,
                              Image.user_id != current_user.id,
                              Image.thumb_url != None)
                      .order_by(Image.score.desc())
                      .first())
    except Exception as _bench_err:
        app.logger.warning(f'[mission benchmark] {_bench_err}')

    if not _benchmark:
        try:
            from engine.stock_images import get_cached_reference_image
            _pixabay_url = get_cached_reference_image(db.session, _genre, _focus_key)
            if not _pixabay_url:
                # No cached candidate yet — kick off the slow DDI-vetting
                # pipeline in the background (it calls Claude Vision and can
                # take several seconds per candidate, so it must never run
                # inline here). This request still falls through to the
                # next tier; the next request for this combo will see the
                # cached result once the background thread finishes.
                threading.Thread(
                    target=_refresh_pixabay_reference_in_background,
                    args=(_genre, _focus_key),
                    daemon=True
                ).start()
        except Exception as _pix_err:
            app.logger.warning(f'[mission pixabay fallback] {_pix_err}')

    if not _benchmark and not _pixabay_url:
        # Tier 3: neither an exact genre+dimension benchmark nor a Pixabay
        # reference is available (cache miss, background fetch still
        # pending, or the cache itself is unreachable) — broaden to any
        # genre-matched platform photo at 8.0+ rather than fall through to
        # the dark placeholder. Reuses the `benchmark` template slot (Tier
        # 1's <img> block in mission_detail.html), so no template change is
        # needed — the hero just shows a less precisely-matched real
        # photograph (genre only, not the specific lesson dimension)
        # instead of nothing.
        try:
            _benchmark = (Image.query
                          .filter_by(status='scored', is_public=True, is_flagged=False)
                          .filter(Image.genre == _genre,
                                  Image.score >= 8.0,
                                  Image.user_id != current_user.id,
                                  Image.thumb_url != None)
                          .order_by(Image.score.desc())
                          .first())
        except Exception as _bench2_err:
            app.logger.warning(f'[mission benchmark tier3] {_bench2_err}')

    class _Assignment:
        title        = _title
        description  = _desc
        assignment   = _assignment
        tips         = _tips
        best_time    = _best_time
        weather      = _weather_str
        focus_label  = _focus_label
        genre        = _genre
        dimension    = _focus_key
        principle_id = lesson['principle_id'] if lesson else None

    return render_template('mission_detail.html',
                           assignment=_Assignment(),
                           master=_master,
                           benchmark=_benchmark,
                           pixabay_reference_url=_pixabay_url,
                           progress_data=progress_data,
                           active_challenge=active_challenge,
                           weather=_weather)


def _refresh_pixabay_reference_in_background(genre, dimension):
    """
    Background worker for the Mission page's Pixabay reference-image
    fallback. Runs in its own thread — needs its own app context, matching
    the existing _force_rescore_in_background pattern in this file.

    Calls engine.stock_images.refresh_reference_cache(), which searches
    Pixabay for several candidates and runs each through the real DDI
    engine (auto_score()) until one scores >= 8.5, then caches that one.
    Nothing below that bar is ever cached — same standard the community
    benchmark query already enforces, so a Mission reference image can
    never be lower quality than a community submission would be.
    """
    with app.app_context():
        try:
            from engine.stock_images import refresh_reference_cache
            cached = refresh_reference_cache(db.session, genre, dimension)
            app.logger.info(f'[mission pixabay refresh] {genre}/{dimension}: cached={cached}')
        except Exception as _refresh_err:
            app.logger.warning(f'[mission pixabay refresh] {genre}/{dimension} failed: {_refresh_err}')


