@app.route('/welcome')
@login_required
def first_login_welcome():
    """Welcome screen for first-time users — shown instead of dashboard
    when user has no images and onboarding is complete.
    """
    # If user already has images, send them to dashboard
    image_count = Image.query.filter_by(user_id=current_user.id).count()
    if image_count > 0:
        return redirect(url_for('dashboard'))

    upload_credits = db.session.execute(
        db.text('SELECT upload_credits_balance FROM users WHERE id = :uid'),
        {'uid': current_user.id}
    ).scalar() or 3

    # Check if referred
    _ref = db.session.execute(
        db.text('SELECT referred_by FROM users WHERE id = :uid'),
        {'uid': current_user.id}
    ).scalar()

    return render_template('first_login.html',
                           upload_credits_balance=upload_credits,
                           referral_applied=bool(_ref),
                           referred_price=180)


@app.route('/dashboard')
@login_required
def dashboard():
    # Approved judges should not see the photographer dashboard
    if current_user.role != 'admin':
        _jc = db.session.execute(
            db.text("SELECT id FROM judges WHERE user_id = :uid AND status = 'approved'"),
            {'uid': current_user.id}
        ).fetchone()
        if _jc:
            return redirect(url_for('judge_dashboard'))
    page  = request.args.get('page', 1, type=int)
    query = request.args.get('q', '').strip()
    if current_user.role == 'admin':
        images_q = Image.query
    else:
        images_q = Image.query.filter_by(user_id=current_user.id)
    total_images = images_q.count()
    if query and total_images >= 20:
        images_q = images_q.filter(
            db.or_(
                Image.asset_name.ilike(f'%{query}%'),
                Image.genre.ilike(f'%{query}%'),
                Image.subject.ilike(f'%{query}%'),
                Image.location.ilike(f'%{query}%'),
                Image.photographer_name.ilike(f'%{query}%'),
            )
        )
    images = (images_q.order_by(Image.created_at.desc())
              .paginate(page=page, per_page=12, error_out=False))
    user_filter = {} if current_user.role == 'admin' else {'user_id': current_user.id}
    stats = {
        'total': total_images,
        'scored': Image.query.filter_by(status='scored', **user_filter).count(),
        'avg_score': db.session.query(db.func.avg(Image.score))
                       .filter(Image.user_id==current_user.id, Image.score!=None).scalar() or 0,
        'best_score': db.session.query(db.func.max(Image.score))
                        .filter(Image.user_id==current_user.id).scalar() or 0,
    }
    # Peer rating widget data
    rating_widget = None
    if current_user.role != 'admin' and getattr(current_user, 'is_subscribed', False):
        credits          = current_user.rating_credits or 0
        lifetime_given   = current_user.lifetime_ratings_given or 0
        unlocks_earned   = lifetime_given // 5
        unlocks_used     = PeerPoolEntry.query.filter_by(user_id=current_user.id).count()
        unlocks_pending  = unlocks_earned - unlocks_used  # earned but not yet assigned to an image
        credits_to_next  = 5 - (lifetime_given % 5) if lifetime_given % 5 != 0 else (0 if lifetime_given > 0 else 5)
        images_in_pool   = Image.query.filter_by(user_id=current_user.id, is_in_peer_pool=True).count()
        images_with_peer = Image.query.filter(
            Image.user_id == current_user.id,
            Image.peer_rating_count > 0
        ).count()
        # Best candidate for pool entry (highest DDI, not already in pool, scored)
        pool_candidate = None
        if unlocks_pending > 0:
            pool_candidate = (Image.query
                .filter_by(user_id=current_user.id, status='scored', is_in_peer_pool=False)
                .filter(Image.score != None, Image.is_flagged == False, Image.needs_review == False)
                .order_by(Image.score.desc())
                .first())
        rating_widget = {
            'credits':          credits,
            'lifetime_given':   lifetime_given,
            'unlocks_earned':   unlocks_earned,
            'unlocks_pending':  unlocks_pending,
            'credits_to_next':  credits_to_next,
            'images_in_pool':   images_in_pool,
            'images_with_peer': images_with_peer,
            'pool_candidate':   pool_candidate,
        }

    # Free tier context for upgrade nudge
    free_tier = None
    if current_user.role != 'admin' and not getattr(current_user, 'is_subscribed', False):
        # Use lifetime counter for gate display — reflects true usage, not current image count
        _lifetime = getattr(current_user, 'total_uploads_ever', None)
        if _lifetime is None:
            _lifetime = Image.query.filter(Image.user_id == current_user.id).count()
            try:
                db.session.execute(
                    db.text("UPDATE users SET total_uploads_ever = :n WHERE id = :uid AND total_uploads_ever IS NULL"),
                    {'n': _lifetime, 'uid': current_user.id}
                )
                db.session.commit()
            except Exception:
                pass
        total_count = _lifetime
        # Compute shadow rank — position by avg DDI score across all public scored users
        _shadow_rank = None
        _shadow_tier = None
        if total_count > 0:
            try:
                _rank_row = db.session.execute(db.text("""
                    SELECT rank FROM (
                        SELECT user_id,
                               RANK() OVER (ORDER BY AVG(score) DESC) AS rank
                        FROM images
                        WHERE status = 'scored'
                          AND score IS NOT NULL
                          AND score > 0
                          AND is_flagged = FALSE
                        GROUP BY user_id
                    ) ranked
                    WHERE user_id = :uid
                """), {'uid': current_user.id}).fetchone()
                if _rank_row:
                    _shadow_rank = int(_rank_row.rank)
                # Best tier from scored images
                _best = db.session.query(db.func.max(Image.score)).filter(
                    Image.user_id == current_user.id,
                    Image.score != None
                ).scalar()
                if _best:
                    _shadow_tier = get_tier(float(_best))
            except Exception:
                pass
        free_tier = {
            'used':        total_count,
            'limit':       FREE_IMAGE_LIMIT,
            'remaining':   max(0, FREE_IMAGE_LIMIT - total_count),
            'shadow_rank': _shadow_rank,
            'shadow_tier': _shadow_tier,
        }

    # -- POTY top-6 tracker --------------------------------------------------
    # Live top-6 average per genre for the current user.
    # Deleted images intentionally not excluded  -  per contest rules, deletions
    # do not improve POTY standing. Calculated from all scored images.
    poty_tracker = None
    if current_user.role != 'admin' and getattr(current_user, 'is_subscribed', False):
        scored_images = (Image.query
            .filter_by(user_id=current_user.id, status='scored')
            .filter(Image.score != None)
            .order_by(Image.genre, Image.score.desc())
            .all())

        # Group by normalised genre
        from engine.scoring import normalise_genre
        genre_data = {}
        for img in scored_images:
            g = normalise_genre(img.genre) if img.genre else 'Other'
            if g not in genre_data:
                genre_data[g] = []
            genre_data[g].append(img)

        # Build per-genre summary: top-6 avg, count, top-6 images
        # Rules:
        # - Current scores are stored on 0-10 scale (e.g. 8.4)
        # - Legacy beta scores > 10.0 were stored on 0-100 scale — divide by 10
        # - Minimum 6 scored images in a genre before avg is displayed
        # - Minimum 24 images to qualify for POTY prizes
        POTY_MIN_IMAGES  = 24
        POTY_MIN_FOR_AVG = 6
        from decimal import Decimal, ROUND_HALF_UP

        def _norm(s):
            # Normalise to 0-10 scale
            if s is None: return None
            return round(s / 10, 2) if s > 10.0 else s

        genre_rows = []
        for genre, imgs in sorted(genre_data.items()):
            for img in imgs:
                img._ns = _norm(img.score)
            imgs_desc     = sorted(imgs, key=lambda x: x._ns or 0, reverse=True)
            top6          = imgs_desc[:6]
            has_enough    = len(imgs) >= POTY_MIN_FOR_AVG
            if has_enough and top6:
                _raw      = sum(i._ns for i in top6) / len(top6)
                top6_avg  = float(Decimal(str(_raw)).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP))
            else:
                top6_avg  = None
            genre_rows.append({
                'genre':         genre,
                'count':         len(imgs),
                'top6_avg':      top6_avg,
                'top6_images':   top6,
                'has_enough':    has_enough,
                'qualifies':     len(imgs) >= POTY_MIN_IMAGES,
                'bar_pct':       min(100, int((top6_avg / 10) * 100)) if top6_avg else 0,
                'images_needed': max(0, POTY_MIN_FOR_AVG - len(imgs)),
            })

        # Genres with avg first (desc), then by count
        genre_rows.sort(key=lambda x: (x['top6_avg'] is not None, x['top6_avg'] or 0, x['count']), reverse=True)

        best_avg      = next((r['top6_avg'] for r in genre_rows if r['top6_avg'] is not None), None)
        active_genres = len([r for r in genre_rows if r['count'] > 0])
        total_scored  = sum(r['count'] for r in genre_rows)

        poty_tracker = {
            'genre_rows':     genre_rows,
            'best_avg':       best_avg,
            'active_genres':  active_genres,
            'total_scored':   total_scored,
            'min_images':     POTY_MIN_IMAGES,
        }

    # Weekly challenge banner
    active_challenge = _get_active_challenge()

    # Zone notification data -- all pages, not just current
    zone3_flagged = Image.query.filter(
        Image.user_id == current_user.id,
        Image.needs_review == True,
        Image.judge_referral == True,
        Image.is_flagged == False,
        Image.peer_avg_score != None,
        Image.peer_rating_count >= 5
    ).all() if current_user.role != 'admin' else []
    zone2_pending = Image.query.filter_by(
        user_id=current_user.id, peer_review_pending=True, needs_review=False, is_flagged=False
    ).all() if not current_user.role == 'admin' else []

    # Contest wins -- images with published results
    contest_wins = []
    if current_user.role != 'admin':
        contest_wins = Image.query.filter_by(
            user_id=current_user.id,
            contest_result_status='published'
        ).filter(Image.judge_final_score != None).order_by(
            Image.judge_final_score.desc()
        ).all()

    # POTY welcome banner
    show_poty_banner = not getattr(current_user, 'poty_banner_dismissed', False)
    show_portfolio_banner = (
        current_user.role != 'admin' and
        not getattr(current_user, 'portfolio_banner_dismissed', False) and
        not getattr(current_user, 'portfolio_public', False)
    )

    # Contest announcement banners — active banners matching user audience
    _is_sub = getattr(current_user, 'is_subscribed', False)
    _ann_q  = ContestAnnouncement.query.filter_by(banner_active=True)
    if current_user.role != 'admin':
        if _is_sub:
            _ann_q = _ann_q.filter(
                ContestAnnouncement.audience.in_(['all', 'subscribers'])
            )
        else:
            _ann_q = _ann_q.filter(
                ContestAnnouncement.audience.in_(['all', 'non_subscribers'])
            )
    contest_banners = _ann_q.order_by(ContestAnnouncement.created_at.desc()).all()

    # RAW pending -- images flagged for verification not yet verified or disqualified
    raw_pending = Image.query.filter(
        Image.user_id == current_user.id,
        Image.raw_verification_required == True,
        Image.raw_verified == False,
        Image.raw_disqualified == False
    ).all() if current_user.role != 'admin' else []

    # ── Scoring flash notifications ──────────────────────────────────────────
    # Pick up any pending scoring flash messages and clear them
    if current_user.is_subscribed:
        try:
            _flash_imgs = Image.query.filter(
                Image.user_id == current_user.id,
                Image.scoring_flash.isnot(None)
            ).all()
            for _fi in _flash_imgs:
                flash(
                    f'Your image "{_fi.asset_name or _fi.original_filename}" '
                    f'evaluated {_fi.score:.2f} ({_fi.tier}) — {_fi.scoring_flash}',
                    'success'
                )
                _fi.scoring_flash = None
            if _flash_imgs:
                db.session.commit()
        except Exception as _fle:
            app.logger.error(f'[scoring_flash] {_fle}')

    # ── Wallet HUD (Sprint 4) ─────────────────────────────────────────────
    # Investor doc 16d: points balance + progress + 6-6-12 clock
    wallet_hud = None
    if current_user.is_subscribed:
        _pts_bal  = round(getattr(current_user, 'points_balance', 0.0) or 0.0, 1)
        _pts_life = round(getattr(current_user, 'points_lifetime_earned', 0.0) or 0.0, 1)
        _res_mo   = getattr(current_user, 'residency_months', 0) or 0
        # 6-6-12: need 6 subscribed months + 6 scored images in a genre to appear on standings
        # need 24 scored images in a genre to qualify for prizes
        _total_scored = Image.query.filter_by(
            user_id=current_user.id, status='scored'
        ).filter(Image.score.isnot(None)).count()
        # Clock: months remaining to hit 6-month gate
        _months_to_gate = max(0, 6 - _res_mo)
        # Images remaining to hit 6-image minimum in best genre
        _best_genre_count = 0
        if poty_tracker and poty_tracker.get('genre_rows'):
            _best_genre_count = max((r['count'] for r in poty_tracker['genre_rows']), default=0)
        _imgs_to_gate = max(0, 6 - _best_genre_count)
        # Official rank status
        _officially_ranked = (_res_mo >= 6 and _best_genre_count >= 6)
        # Tier jump progress — next bonus threshold
        _last_tier = getattr(current_user, 'tier_jump_last_tier', None)
        _tier_order = ['Rookie','Shooter','Contender','Craftsman','Maverick','Master','Grandmaster','Legend']
        _next_tier = None
        if _last_tier and _last_tier in _tier_order:
            _idx = _tier_order.index(_last_tier)
            if _idx < len(_tier_order) - 1:
                _next_tier = _tier_order[_idx + 1]
        wallet_hud = {
            'balance':          _pts_bal,
            'lifetime':         _pts_life,
            'residency_months': _res_mo,
            'months_to_gate':   _months_to_gate,
            'imgs_to_gate':     _imgs_to_gate,
            'officially_ranked': _officially_ranked,
            'total_scored':     _total_scored,
            'last_tier':        _last_tier,
            'next_tier':        _next_tier,
        }
    # ── End Wallet HUD ────────────────────────────────────────────────────

    # DDI Progress (same data as profile page)
    progress_data = _build_progress_data(current_user)

    # ── Photo School — curriculum lesson + weather ────────────────────────
    _lesson = None
    _weather = {'state': 'green', 'condition': '', 'message': None, 'window': None,
                'temp_c': None, 'humidity': None}
    _mission_due = False
    _mission_done = False  # default for admin users — assigned inside non-admin block below
    if current_user.role != 'admin':
        try:
            _lesson = _get_curriculum_lesson(current_user, progress_data)
        except Exception as _le:
            app.logger.warning(f'[curriculum_lesson] {_le}')
        try:
            _wx_city = getattr(current_user, 'city', '') or ''
            if _wx_city:
                _weather = _get_weather(_wx_city)
        except Exception as _we:
            app.logger.warning(f'[weather] {_we}')
        # Mission due — open mission upload within last 7 days still pending/processing
        try:
            _due_cutoff = datetime.utcnow() - timedelta(days=7)
            _due_img = (Image.query
                        .filter_by(user_id=current_user.id)
                        .filter(Image.mission_dimension.isnot(None),
                                Image.created_at >= _due_cutoff,
                                Image.status.in_(['pending', 'processing']))
                        .order_by(Image.created_at.desc())
                        .first())
            if _due_img:
                _mission_due = True
        except Exception as _mde:
            app.logger.warning(f'[mission_due] {_mde}')
        # Mission done today — scored mission image completed successfully today
        # NOTE: do NOT filter on scoring_flash — it is cleared to None on first
        # dashboard load (by the flash pickup loop above). Use the per-dimension
        # score column directly: the scoring thread writes this before setting
        # scoring_flash, so it persists in the DB regardless of flash state.
        _mission_done = False
        try:
            # IST midnight, expressed back in UTC for comparison against created_at
            # (created_at is stored in UTC). Using utcnow().replace(hour=0) directly
            # anchors "today" to UTC midnight (05:30 IST) — between 12:00 AM and
            # 5:30 AM IST, a new IST day has begun but UTC has not rolled over yet,
            # so the old boundary stretched back into *yesterday* (IST), letting a
            # mission completed last night show as stale "done" carryover into the
            # new day instead of correctly resetting to not-done.
            _ist_now = datetime.utcnow() + timedelta(hours=5, minutes=30)
            _today_start = _ist_now.replace(hour=0, minute=0, second=0, microsecond=0) - timedelta(hours=5, minutes=30)
            # Check the score column matching THIS image's own mission_dimension,
            # not a single hardcoded column — a Wonder or DoD mission must be
            # judged on wonder_score / dod_score, not disruption_score.
            _mdd_dim_col_map = {
                'dod': 'dod_score', 'dm': 'dm_score', 'aq': 'aq_score',
                'wonder': 'wonder_score', 'disruption': 'disruption_score',
            }
            _today_mission_imgs = (Image.query
                         .filter_by(user_id=current_user.id, status='scored')
                         .filter(Image.mission_dimension.isnot(None),
                                 Image.created_at >= _today_start)
                         .order_by(Image.created_at.desc())
                         .all())
            for _cand in _today_mission_imgs:
                _col = _mdd_dim_col_map.get(_cand.mission_dimension)
                _val = getattr(_cand, _col, None) if _col else None
                if _val is not None and _val >= 5.0:
                    _mission_done = True
                    break
        except Exception as _mdd:
            app.logger.warning(f'[mission_done] {_mdd}')
    # ── End Photo School ──────────────────────────────────────────────────

    # Mentor reviews — for notif strip
    mentor_reviews = []
    if current_user.role != 'admin':
        try:
            _reviews = db.session.execute(db.text("""
                SELECT ms.id, ms.image_id, ms.review_text, ms.reviewed_at,
                       i.asset_name, i.thumb_url, i.genre,
                       mp.display_name AS mentor_name
                FROM mentor_sessions ms
                JOIN images i        ON i.id  = ms.image_id
                JOIN mentor_profiles mp ON mp.slug = ms.mentor_slug
                WHERE ms.user_id = :uid
                  AND ms.status  = 'reviewed'
                  AND ms.dashboard_dismissed IS NOT TRUE
                ORDER BY ms.reviewed_at DESC
                LIMIT 5
            """), {'uid': current_user.id}).fetchall()
            mentor_reviews = [dict(r._mapping) for r in _reviews]
        except Exception as _mre:
            app.logger.error(f'[dashboard_mentor_reviews] {_mre}')

    # referred_discount is a migration-only column — not in ORM model, must read directly
    try:
        _ref_discount = db.session.execute(
            db.text('SELECT referred_discount FROM users WHERE id = :uid'),
            {'uid': current_user.id}
        ).scalar() or False
    except Exception:
        _ref_discount = False

    # Fetch version numbers for all images on this page (migration-only column)
    _img_ids = [img.id for img in images.items]
    _version_map = {}
    if _img_ids:
        try:
            _vrows = db.session.execute(db.text(
                "SELECT id, parent_image_id, version_number FROM images WHERE id = ANY(:ids)"
            ), {'ids': _img_ids}).fetchall()
            for r in _vrows:
                if r[1]:  # has parent_image_id = is an edited version
                    _version_map[r[0]] = r[2] or 2  # version_number, default 2
        except Exception as _ve:
            app.logger.warning(f'[dashboard] version_map: {_ve}')

    # ── Annual Excellence Award — months active this season ──────────────────
    # 2026 shortened season: Sep 1 – Dec 31. All other years: Jan 1 – Dec 31.
    try:
        _now = datetime.utcnow()
        if _now.year == 2026:
            _season_start = datetime(2026, 9, 1)
        else:
            _season_start = datetime(_now.year, 1, 1)
        _months_active = db.session.execute(db.text(
            "SELECT COUNT(DISTINCT DATE_TRUNC('month', created_at)) "
            "FROM images WHERE user_id = :uid AND is_public = TRUE "
            "AND created_at >= :season_start AND score IS NOT NULL"
        ), {'uid': current_user.id, 'season_start': _season_start}).scalar() or 0
        _season_start_label = '1 September 2026' if _now.year == 2026 else '1 January'
        _pre_season         = (_now.year == 2026 and _now < datetime(2026, 9, 1))
    except Exception as _mae:
        app.logger.warning(f'[dashboard] months_active: {_mae}')
        _months_active = 0
        _season_start_label = '1 September 2026'
        _pre_season         = True

    # Hero carousel for dashboard banner — random high-scoring public image per visit
    # Same query as index.html carousel but random order so it changes on every refresh
    try:
        _dash_carousel = (Image.query
                          .filter(Image.status=='scored', Image.score!=None,
                                  Image.is_public==True, Image.is_flagged==False,
                                  Image.tier.in_(['Legend','Grandmaster','Master']),
                                  Image.score>=8.5,
                                  Image.thumb_url!=None,
                                  Image.width > Image.height)
                          .order_by(db.func.random())
                          .limit(1).first())
    except Exception:
        _dash_carousel = None

    # Fetch upload_credits_balance — backfill if 0/NULL for partial free-tier users
    # upload_credits_balance is a migration-only column (DEFAULT 0) — never backfilled
    # for users who joined before the column existed. If they still have remaining
    # free evaluations, set the column to the correct value and persist.
    _ucb_val = db.session.execute(
        db.text('SELECT upload_credits_balance FROM users WHERE id = :uid'),
        {'uid': current_user.id}
    ).scalar()
    if free_tier and (_ucb_val is None or _ucb_val == 0) and free_tier['remaining'] > 0:
        _ucb_val = free_tier['remaining']
        try:
            db.session.execute(
                db.text('UPDATE users SET upload_credits_balance = :n WHERE id = :uid'),
                {'n': _ucb_val, 'uid': current_user.id}
            )
            db.session.commit()
        except Exception as _ucb_e:
            app.logger.warning(f'[upload_credits_backfill] {_ucb_e}')
    _ucb_val = _ucb_val or 0

    # ── Dashboard location advisory — real seasonal content, same source    ──
    # ── data as the scorecard's "What's happening near you", just a         ──
    # ── lighter single-match version for the sidebar widget. Falls back to  ──
    # ── the existing generic placeholder in dashboard.html if no match.     ──
    _dash_advisory = None
    try:
        if current_user.city:
            from engine.seasonal_calendar import get_dashboard_advisory, get_primary_genre as _gpg2
            _adv_genre = _gpg2(current_user)
            _dash_advisory = get_dashboard_advisory(
                db.session, current_user.city, _adv_genre or 'Wildlife', datetime.utcnow().month
            )
    except Exception as _dae:
        app.logger.warning(f'[dashboard] advisory: {_dae}')

    # ── P6: Peer eval notifications — images owned by current user evaluated in last 24hrs ──
    # Deduplicated by image_id — show most recent eval per image, max 3 banners.
    _peer_eval_notifications = []
    try:
        from models import PeerRating as _PR
        from datetime import timedelta as _td24
        _since = datetime.utcnow() - _td24(hours=24)
        _all_notifs = (
            _PR.query
            .join(Image, _PR.image_id == Image.id)
            .filter(
                Image.user_id == current_user.id,
                _PR.rated_at >= _since,
            )
            .order_by(_PR.rated_at.desc())
            .all()
        )
        # Deduplicate: one notification per image, most recent eval wins
        # Only show if rating has actual comments (what_struck populated)
        _seen_images = set()
        for _n in _all_notifs:
            if _n.image_id not in _seen_images and (_n.what_struck or '').strip():
                _peer_eval_notifications.append(_n)
                _seen_images.add(_n.image_id)
            if len(_peer_eval_notifications) >= 3:
                break
    except Exception as _pen:
        app.logger.warning(f'[dashboard] peer_eval_notifications: {_pen}')

    # ── Peer evaluation queue for dashboard (Session 112 — direct query) ────────
    _peer_queue = []
    if getattr(current_user, 'is_subscribed', False) and current_user.role != 'admin':
        try:
            from models import RatingAssignment as _RA
            from datetime import timedelta as _td
            from sqlalchemy import text as _sqlt
            # Only exclude images the user has *submitted* a rating for.
            # Expired/skipped assignments re-enter the pool — prevents depletion.
            _already = db.session.query(_RA.image_id).filter(
                _RA.rater_id == current_user.id,
                _RA.status   == 'submitted'
            ).subquery()
            _eligible = Image.query.join(
                User, Image.user_id == User.id
            ).filter(
                Image.status      == 'scored',
                Image.is_public   == True,
                Image.is_flagged  == False,
                Image.needs_review == False,
                Image.score       != None,
                Image.genre       != None,
                Image.user_id     != current_user.id,
                User.is_subscribed == True,
                Image.id.notin_(_already),
            ).order_by(
                Image.peer_rating_count.asc().nullsfirst(),
                Image.scored_at.desc()
            ).limit(9).all()
            for _img in _eligible[:3]:
                try:
                    # Reuse existing non-submitted assignment if present (unique constraint)
                    _existing = _RA.query.filter_by(
                        rater_id=current_user.id,
                        image_id=_img.id
                    ).first()
                    if _existing:
                        _existing.status     = 'started'
                        _existing.started_at = datetime.utcnow()
                        _existing.expires_at = datetime.utcnow() + _td(hours=72)
                        db.session.flush()
                        try:
                            db.session.execute(db.text(
                                "UPDATE rating_assignments SET genre=:g WHERE id=:id"
                            ), {'g': _img.genre, 'id': _existing.id})
                        except Exception:
                            pass
                        _peer_queue.append(_existing)
                    else:
                        _a = _RA(
                            rater_id   = current_user.id,
                            image_id   = _img.id,
                            status     = 'started',
                            tier_slot  = 'any',
                            started_at = datetime.utcnow(),
                            expires_at = datetime.utcnow() + _td(hours=72),
                        )
                        db.session.add(_a)
                        db.session.flush()
                        try:
                            db.session.execute(db.text(
                                "UPDATE rating_assignments SET genre=:g WHERE id=:id"
                            ), {'g': _img.genre, 'id': _a.id})
                        except Exception:
                            pass
                        _peer_queue.append(_a)
                except Exception as _pq_assign_err:
                    app.logger.warning(f'[dashboard] peer queue assignment error image={_img.id}: {_pq_assign_err}')
                    db.session.rollback()
            if _peer_queue:
                db.session.commit()
        except Exception as _pqe:
            app.logger.warning(f'[dashboard] peer queue: {_pqe}')

    # ── Eye of Judge — calibration trend (shows when ≥5 peer evals submitted) ──
    _eye_of_judge = None
    _peer_ratings_given = getattr(current_user, 'lifetime_ratings_given', 0) or 0
    if _peer_ratings_given >= 5 and getattr(current_user, 'is_subscribed', False):
        try:
            from models import PeerRating as _PRJ
            _judge_ratings = (
                _PRJ.query
                .filter(
                    _PRJ.rater_id == current_user.id,
                    _PRJ.delta_from_ddi != None,
                )
                .order_by(_PRJ.rated_at.desc())
                .limit(10)
                .all()
            )
            if len(_judge_ratings) >= 3:
                _ratings_asc = list(reversed(_judge_ratings))
                _deltas       = [abs(r.delta_from_ddi) for r in _ratings_asc]
                _peer_scores  = [round(r.peer_ll_score, 1) for r in _ratings_asc]
                _engine_scores= [round(r.peer_ll_score - r.delta_from_ddi, 1) for r in _ratings_asc]
                _avg_delta    = round(sum(_deltas) / len(_deltas), 2)
                _half         = len(_deltas) // 2
                _early_avg    = sum(_deltas[:_half]) / _half if _half else _avg_delta
                _late_avg     = sum(_deltas[_half:]) / (len(_deltas) - _half) if _half else _avg_delta
                _improving    = _late_avg < _early_avg
                _eye_of_judge = {
                    'count':         _peer_ratings_given,
                    'avg_delta':     _avg_delta,
                    'deltas':        _deltas,
                    'peer_scores':   _peer_scores,
                    'engine_scores': _engine_scores,
                    'improving':     _improving,
                }
        except Exception as _eje:
            app.logger.warning(f'[dashboard] eye_of_judge: {_eje}')

    return render_template('dashboard.html', images=images, stats=stats,
                           carousel_images=[_dash_carousel] if _dash_carousel else [],
                           query=query, search_enabled=(total_images >= 20),
                           rating_widget=rating_widget, free_tier=free_tier,
                           poty_tracker=poty_tracker,
                           active_challenge=active_challenge,
                           zone3_flagged=zone3_flagged,
                           zone2_pending=zone2_pending,
                           contest_wins=contest_wins,
                           show_poty_banner=show_poty_banner,
                           contest_banners=contest_banners,
                           raw_pending=raw_pending,
                           wallet_hud=wallet_hud,
                           progress_data=progress_data,
                           show_portfolio_banner=show_portfolio_banner,
                           mentor_reviews=mentor_reviews,
                           referral_code=get_or_create_referral_code(current_user),
                           referral_stats=get_referral_stats(current_user),
                           referral_url=(os.getenv('SITE_URL','https://shutterleague.com') + '/ref/' + (get_or_create_referral_code(current_user) or '')),
                           referred_discount=_ref_discount,
                           _months_active=_months_active,
                           _season_start_label=_season_start_label,
                           _pre_season=_pre_season,
                           upload_credits_balance=_ucb_val,
                           countries=get_countries(),
                           location_data_json=json.dumps(_dash_loc()),
                           lesson=_lesson,
                           weather=_weather,
                           mission_due=_mission_due,
                           mission_done=_mission_done,
                           dash_advisory=_dash_advisory,
                           peer_queue=_peer_queue,
                           peer_eval_notifications=_peer_eval_notifications,
                           tier_rank=TIER_RANK,
                           eye_of_judge=_eye_of_judge,
                           peer_ratings_given=_peer_ratings_given,
                           last_eval_result=session.get('last_eval_result'))


# ---------------------------------------------------------------------------
# My Gallery — user's full image history with search/filter
# ---------------------------------------------------------------------------

@app.route('/my-gallery')
@login_required
def my_gallery():
    """User's complete image history — all uploads, with scores, edit/delete access."""
    page    = request.args.get('page', 1, type=int)
    query   = request.args.get('q', '').strip()
    genre   = request.args.get('genre', '').strip()
    sort    = request.args.get('sort', 'newest').strip()

    images_q = Image.query.filter_by(user_id=current_user.id)

    if query:
        images_q = images_q.filter(
            db.or_(
                Image.asset_name.ilike(f'%{query}%'),
                Image.genre.ilike(f'%{query}%'),
                Image.subject.ilike(f'%{query}%'),
                Image.location.ilike(f'%{query}%'),
            )
        )
    if genre:
        images_q = images_q.filter(Image.genre.ilike(f'%{genre}%'))

    if sort == 'score_desc':
        images_q = images_q.filter(Image.score != None).order_by(Image.score.desc())
    elif sort == 'score_asc':
        images_q = images_q.filter(Image.score != None).order_by(Image.score.asc())
    elif sort == 'oldest':
        images_q = images_q.order_by(Image.created_at.asc())
    else:  # newest
        images_q = images_q.order_by(Image.created_at.desc())

    images = images_q.paginate(page=page, per_page=24, error_out=False)

    total = Image.query.filter_by(user_id=current_user.id).count()
    scored = Image.query.filter_by(user_id=current_user.id, status='scored').count()
    best = db.session.query(db.func.max(Image.score)).filter(
        Image.user_id == current_user.id, Image.score != None
    ).scalar() or 0
    avg = db.session.query(db.func.avg(Image.score)).filter(
        Image.user_id == current_user.id, Image.score != None
    ).scalar() or 0

    # Distinct genres for filter dropdown
    genre_rows = db.session.query(Image.genre).filter(
        Image.user_id == current_user.id,
        Image.genre != None
    ).distinct().all()
    genres = sorted([r[0] for r in genre_rows if r[0]])

    stats = {
        'total': total, 'scored': scored,
        'best': round(best, 2), 'avg': round(avg, 2),
    }
    return render_template('my_gallery.html',
                           images=images, stats=stats, genres=genres,
                           query=query, genre=genre, sort=sort,
                           tier_rank=TIER_RANK)


