def _build_progress_data(user):
    """Returns progress dict for profile dashboard, or None if < 5 scored images."""
    scored = (Image.query
              .filter_by(user_id=user.id, status='scored')
              .filter(Image.score.isnot(None),
                      Image.is_flagged.isnot(True),
                      Image.needs_review.isnot(True))
              .order_by(Image.scored_at.asc())
              .all())

    if len(scored) < 5:
        return None

    dim_labels = {
        'dod': 'Depth of Difficulty', 'disruption': 'Disruption',
        'dm': 'Decisive Moment', 'wonder': 'Wonder Factor', 'aq': 'Aesthetic Quality'
    }
    dim_fields = {
        'dod': 'dod_score', 'disruption': 'disruption_score',
        'dm': 'dm_score', 'wonder': 'wonder_score', 'aq': 'aq_score'
    }

    avgs = {}
    for d in dim_fields:
        vals = [getattr(img, dim_fields[d]) for img in scored
                if getattr(img, dim_fields[d]) is not None]
        avgs[d] = round(sum(vals) / len(vals), 2) if vals else 0.0

    trend_imgs = scored[-10:]
    trend = [{'label': f'#{i+1}', 'tier': img.tier or get_tier(img.score), 'score': img.score}
             for i, img in enumerate(trend_imgs)]

    # Per-dimension trend + pill — last 8 images, for dashboard sparkline charts
    # Pill logic: first-half vs second-half average (matches scorecard _trend_pill)
    dim_trend_imgs = scored[-8:]
    dim_trends = {}
    dim_pills  = {}

    def _dash_pill(vals):
        clean = [v for v in vals if v is not None]
        if len(clean) < 3:
            return 'steady'
        mid    = len(clean) // 2
        first  = sum(clean[:mid]) / mid
        second = sum(clean[mid:]) / (len(clean) - mid)
        diff   = second - first
        if diff > 0.3:
            return 'up'
        if diff < -0.3:
            return 'down'
        return 'steady'

    def _dash_spark(values, width=300, height=28):
        """Pre-compute SVG polyline points string in Python — avoids Jinja2 loop scoping."""
        clean = [v for v in values if v is not None]
        if len(clean) < 2:
            return '', []
        mn, mx = min(clean), max(clean)
        rng = mx - mn if mx != mn else 1.0
        step = width / (len(clean) - 1)
        pts = []
        for i, v in enumerate(clean):
            x = round(i * step, 1)
            y = round(height - ((v - mn) / rng) * (height - 2) - 1, 1)
            pts.append({'x': x, 'y': y})
        polyline = ' '.join(f"{p['x']},{p['y']}" for p in pts)
        return polyline, pts

    dim_sparklines = {}  # pre-computed SVG points per dimension
    for d, field in dim_fields.items():
        raw  = [getattr(img, field) for img in dim_trend_imgs]
        vals = [round(v, 1) if v is not None else None for v in raw]
        dim_trends[d] = vals
        dim_pills[d]  = _dash_pill(vals)
        polyline, pts = _dash_spark(vals)
        dim_sparklines[d] = {'polyline': polyline, 'points': pts}

    # Mission upload indices per dimension — which positions in the last-8 window
    # were mission uploads. Used by dashboard sparklines to render gold dot overlay.
    dim_mission_indices = {}
    for d in dim_fields:
        dim_mission_indices[d] = [
            i for i, img in enumerate(dim_trend_imgs)
            if getattr(img, 'mission_dimension', None) == d
        ]

    strongest = max(avgs, key=avgs.get)
    weakest   = min(avgs, key=avgs.get)

    from collections import Counter
    genre_counts = Counter(img.genre for img in scored if img.genre)
    top_genre = genre_counts.most_common(1)[0][0] if genre_counts else None

    avg_score = round(sum(img.score for img in scored) / len(scored), 2)

    # ── Percentile — within same league ────────────────────────────────────
    overall_pct     = None
    genre_pct       = None
    genre_pct_label = None
    league_label    = None
    tier_avg_dims   = {}
    try:
        _user_track = getattr(user, 'subscription_track', None) or                       getattr(user, 'camera_track', None) or None
        _track_labels = {'camera': 'Camera', 'mobile': 'Mobile',
                         'learning': 'Learning', 'mentor': 'Mentor'}
        league_label = _track_labels.get(_user_track, 'Camera')

        _league_q = [Image.status == 'scored', Image.score.isnot(None),
                     Image.is_flagged.isnot(True), Image.needs_review.isnot(True)]
        if _user_track in ('camera', 'mobile'):
            _league_q.append(Image.camera_track == _user_track)

        _all = (Image.query.filter(*_league_q)
                .with_entities(Image.score, Image.genre, Image.camera_track,
                               Image.dod_score, Image.disruption_score,
                               Image.dm_score, Image.wonder_score, Image.aq_score)
                .all())

        if _all and avg_score:
            _all_scores = [float(r.score) for r in _all]
            _below = sum(1 for s in _all_scores if s < avg_score)
            overall_pct = max(1, round((1 - _below / len(_all_scores)) * 100))

            if top_genre:
                from engine.scoring import normalise_genre as _ng
                _genre_scores = [float(r.score) for r in _all
                                 if _ng(r.genre) == _ng(top_genre)]
                if _genre_scores and len(_genre_scores) >= 3:
                    _bg = sum(1 for s in _genre_scores if s < avg_score)
                    _gp = max(1, round((1 - _bg / len(_genre_scores)) * 100))
                    if _gp < 100:
                        genre_pct = _gp
                        genre_pct_label = top_genre

            # Tier average per dimension
            _cur_tier = get_tier(avg_score)
            _tier_imgs = (Image.query
                .filter(Image.status == 'scored', Image.score.isnot(None),
                        Image.tier == _cur_tier, Image.is_flagged.isnot(True))
                .with_entities(Image.dod_score, Image.disruption_score,
                               Image.dm_score, Image.wonder_score, Image.aq_score)
                .limit(500).all())
            _fd = {'dod': 'dod_score', 'disruption': 'disruption_score',
                   'dm': 'dm_score', 'wonder': 'wonder_score', 'aq': 'aq_score'}
            for _d, _f in _fd.items():
                _vals = [getattr(r, _f) for r in _tier_imgs if getattr(r, _f) is not None]
                tier_avg_dims[_d] = round(sum(_vals) / len(_vals), 1) if _vals else None
    except Exception as _pe:
        import logging
        logging.getLogger(__name__).warning(f'[progress_data percentile] {_pe}')

    # ── Tier progress ───────────────────────────────────────────────────────
    _tier_order = ['Rookie','Shooter','Contender','Craftsman','Maverick',
                   'Master','Grandmaster','Legend']
    _tier_bounds = {'Rookie':(0,4),'Shooter':(4,5),'Contender':(5,6),
                    'Craftsman':(6,7),'Maverick':(7,8),'Master':(8,9),
                    'Grandmaster':(9,9.7),'Legend':(9.7,10)}
    _cur_tier = get_tier(avg_score)
    _prev_tier = (_tier_order[max(0, _tier_order.index(_cur_tier)-1)]
                  if _cur_tier in _tier_order else None)
    _next_tier = (_tier_order[min(len(_tier_order)-1, _tier_order.index(_cur_tier)+1)]
                  if _cur_tier in _tier_order else None)
    _bounds = _tier_bounds.get(_cur_tier, (0, 10))
    _tier_pct = int(min(100, max(0,
        (avg_score - _bounds[0]) / max(0.01, _bounds[1] - _bounds[0]) * 100)))

    return {
        'count':          len(scored),
        'avg_tier':       get_tier(avg_score),
        'avg_score':      avg_score,
        'dim_avgs':       avgs,
        'dim_labels':     dim_labels,
        'trend':          trend,
        'dim_trends':     dim_trends,
        'dim_pills':      dim_pills,
        'dim_sparklines':      dim_sparklines,
        'dim_mission_indices': dim_mission_indices,
        'strongest':      strongest,
        'weakest':        weakest,
        'top_genre':      top_genre,
        'overall_pct':    overall_pct,
        'genre_pct':      genre_pct,
        'genre_pct_label': genre_pct_label,
        'league_label':   league_label,
        'tier_avg_dims':  tier_avg_dims,
        'tier_pct':       _tier_pct,
        'prev_tier':      _prev_tier,
        'next_tier':      _next_tier,
    }


