# Curriculum: 15 principles × 5 dimensions × 3 depth levels
# Photo School curriculum data — see curriculum_data.py (extracted Session 95)
from curriculum_data import _CURRICULUM, _CURRICULUM_BY_ID

# Dimension order and default progression
_DIM_KEYS      = ['dod', 'disruption', 'dm', 'wonder', 'aq']
_DIM_LABELS    = {'dod': 'Depth of Difficulty', 'disruption': 'Disruption',
                  'dm': 'Decisive Moment', 'wonder': 'Wonder Factor', 'aq': 'Affective Quotient'}
_DIM_SHORT     = {'dod': 'Technical', 'disruption': 'Disruption',
                  'dm': 'Timing', 'wonder': 'Wonder', 'aq': 'Visual Impact'}

# Valid mission genres matching platform genres
_VALID_MISSION_GENRES = [
    'Wildlife', 'Street', 'Nature', 'Landscape', 'People',
    'Documentary', 'Macro', 'Creative', 'Drone', 'Wedding', 'Fashion',
]


def _get_weather(city):
    """
    Fetch current weather for a city via Open-Meteo (free, no key).
    Returns dict with: temp_c, humidity, precip_prob, wind_kph,
                       weather_code, condition, state ('green'|'amber'|'red'),
                       message, window
    Falls back to neutral green if fetch fails — never crashes dashboard.
    """
    import urllib.request as _ur
    import urllib.parse
    import json as _json

    _NEUTRAL = {
        'temp_c': None, 'humidity': None, 'precip_prob': None,
        'wind_kph': None, 'weather_code': None,
        'condition': 'Weather unavailable',
        'state': 'green',
        'message': None,
        'window': None,
    }

    if not city:
        return _NEUTRAL

    try:
        # Step 1 — geocode city to lat/lon
        geo_url = (
            'https://geocoding-api.open-meteo.com/v1/search'
            f'?name={urllib.parse.quote(city)}&count=1&language=en&format=json'
        )
        with _ur.urlopen(geo_url, timeout=4) as _r:
            _geo = _json.loads(_r.read())
        if not _geo.get('results'):
            return _NEUTRAL
        lat = _geo['results'][0]['latitude']
        lon = _geo['results'][0]['longitude']

        # Step 2 — current weather + tomorrow's daily precipitation probability
        wx_url = (
            f'https://api.open-meteo.com/v1/forecast'
            f'?latitude={lat}&longitude={lon}'
            f'&current=temperature_2m,relative_humidity_2m,'
            f'precipitation_probability,wind_speed_10m,weather_code'
            f'&daily=precipitation_probability_max,weather_code'
            f'&wind_speed_unit=kmh&timezone=auto&forecast_days=2'
        )
        with _ur.urlopen(wx_url, timeout=4) as _r:
            _wx = _json.loads(_r.read())

        cur       = _wx.get('current', {})
        temp_c    = cur.get('temperature_2m')
        humidity  = cur.get('relative_humidity_2m')
        precip    = cur.get('precipitation_probability', 0) or 0
        wind_kph  = cur.get('wind_speed_10m', 0) or 0
        wcode     = cur.get('weather_code', 0) or 0
        # Tomorrow's forecast — daily[1] is tomorrow (daily[0] is today)
        _daily         = _wx.get('daily', {})
        _tmrw_precip   = (_daily.get('precipitation_probability_max') or [0, 0])[1] or 0
        _tmrw_wcode    = (_daily.get('weather_code') or [0, 0])[1] or 0
        _tmrw_is_bad   = _tmrw_precip >= 50 or _tmrw_wcode in (
            51,53,55,61,63,65,66,67,80,81,82,95,96,99,73,75,77
        )

        # Weather code groups (WMO standard)
        # 0-1: clear, 2-3: partly cloudy, 45-48: fog
        # 51-67: drizzle/rain, 71-77: snow, 80-82: showers
        # 95-99: thunderstorm, hail
        _is_storm    = wcode in (95, 96, 99)
        _is_hail     = wcode in (96, 99)
        _is_snow_hvy = wcode in (73, 75, 77)
        _is_snow_lt  = wcode in (71, 72)
        _is_rain     = wcode in (51,53,55,61,63,65,66,67,80,81,82)
        _is_fog      = wcode in (45, 48)

        # Heat index (simplified Steadman approximation)
        heat_index = temp_c
        if temp_c is not None and humidity is not None and temp_c >= 27:
            heat_index = (
                -8.784695 + 1.61139411 * temp_c
                + 2.3385489 * humidity
                - 0.14611605 * temp_c * humidity
                - 0.012308094 * temp_c ** 2
                - 0.016424828 * humidity ** 2
                + 0.002211732 * temp_c ** 2 * humidity
                + 0.00072546 * temp_c * humidity ** 2
                - 0.000003582 * temp_c ** 2 * humidity ** 2
            )

        # Determine state
        if _is_storm or _is_hail:
            state   = 'red'
            condition = 'Thunderstorm'
            message = (
                f'{city} · Thunderstorm warning. Do not go out today. '
                f'Rain is forecast tomorrow too — keep yourself covered, check the forecast before heading out.' if _tmrw_is_bad else
                f'{city} · Thunderstorm warning. Do not go out today. Your outdoor mission waits for tomorrow.'
            )
            window  = None
        elif _is_snow_hvy:
            state   = 'red'
            condition = 'Heavy snow'
            message = f'{city} · Heavy snow. Outdoor mission paused — or embrace it if you are equipped.'
            window  = None
        elif _is_rain and precip >= 70:
            state   = 'red'
            condition = f'Rain · {precip}% chance'
            message = (
                f'{city} · Heavy rain likely today. '
                f'Rain is forecast tomorrow too — keep yourself covered, check the forecast before heading out.' if _tmrw_is_bad else
                f'{city} · Heavy rain likely today. Outdoor mission best saved for tomorrow.'
            )
            window  = None
        elif heat_index is not None and heat_index >= 42:
            state   = 'red'
            condition = f'{round(temp_c)}°C · Humidity {humidity}%'
            message = f'{city} · Feels like {round(heat_index)}°C with humidity. Do not shoot outdoors — dangerous conditions.'
            window  = None
        elif heat_index is not None and heat_index >= 35:
            state   = 'amber'
            condition = f'{round(temp_c)}°C · Humidity {humidity}%'
            message = f'{city} · Feels like {round(heat_index)}°C. Go before 9am or after 5pm. Take water.'
            window  = 'Early morning only'
        elif wind_kph >= 50:
            state   = 'amber'
            condition = f'Wind {round(wind_kph)} km/h'
            message = f'{city} · Strong winds today — difficult for drone and macro. Other genres: exercise caution.'
            window  = 'Sheltered locations only'
        elif _is_rain and precip >= 40:
            state   = 'amber'
            condition = f'Rain likely · {precip}%'
            message = f'{city} · Rain likely. Check your window — go early or plan for indoor alternatives.'
            window  = 'Check timing'
        elif _is_snow_lt:
            state   = 'green'
            condition = 'Light snow'
            message = f'{city} · Light snow — a rare opportunity for landscape and street photographers. Dress warm.'
            window  = 'Now'
        elif _is_fog:
            state   = 'green'
            condition = 'Fog'
            message = f'{city} · Fog this morning — ideal for atmospheric landscape and street work. Go now, it lifts by mid-morning.'
            window  = 'Now — lifts by mid-morning'
        else:
            state   = 'green'
            _temp_str = f'{round(temp_c)}°C' if temp_c is not None else ''
            condition = f'{_temp_str} · Clear' if _temp_str else 'Clear'
            message = None
            window  = None

        return {
            'temp_c':       round(temp_c) if temp_c is not None else None,
            'humidity':     humidity,
            'precip_prob':  precip,
            'wind_kph':     round(wind_kph),
            'weather_code': wcode,
            'condition':    condition,
            'state':        state,
            'message':      message,
            'window':       window,
        }

    except Exception as _wx_err:
        app.logger.warning(f'[weather] {city}: {_wx_err}')
        return _NEUTRAL


def _get_curriculum_lesson(user, progress_data):
    """
    Select today's Photo School lesson for this user.

    Logic:
    1. Identify weakest dimension from progress_data (or 'dm' default)
    2. Get active mission genre: user.mission_genre or primary genre
    3. Read curriculum_state from user record
    4. Find first untaught principle at current depth for weakest dimension
    5. If all taught at current depth — advance depth, start again
    6. Alternate master days

    Returns dict with all fields needed by dashboard template, or None if
    user has no progress data yet (< 5 images).
    """
    import json as _json

    # Resolve weakest dimension
    weakest = 'dm'
    if progress_data:
        weakest = progress_data.get('weakest', 'dm')

    # Resolve mission genre — read via raw SQL (migration-only column, not in ORM model)
    mission_genre = None
    try:
        mission_genre = db.session.execute(
            db.text('SELECT mission_genre FROM users WHERE id = :uid'),
            {'uid': user.id}
        ).scalar()
    except Exception:
        pass
    if not mission_genre or mission_genre not in _VALID_MISSION_GENRES:
        # Fall back to primary genre from genre_interests
        try:
            from engine.seasonal_calendar import get_primary_genre as _gpg
            mission_genre = _gpg(user) or 'Wildlife'
        except Exception:
            mission_genre = 'Wildlife'
    if mission_genre not in _VALID_MISSION_GENRES:
        mission_genre = 'Wildlife'

    # Load curriculum state
    raw_state = None
    try:
        raw_state = db.session.execute(
            db.text('SELECT curriculum_state FROM users WHERE id = :uid'),
            {'uid': user.id}
        ).scalar()
    except Exception:
        pass

    try:
        state = raw_state if isinstance(raw_state, dict) else (_json.loads(raw_state) if raw_state else {})
    except Exception:
        state = {}

    # Ensure all dims exist in state
    for _d in _DIM_KEYS:
        if _d not in state:
            state[_d] = {'depth': 1, 'taught': []}

    if 'last_had_master' not in state:
        state['last_had_master'] = False

    # Find the right principle for weakest dim
    dim_state  = state[weakest]
    cur_depth  = dim_state.get('depth', 1)
    taught     = set(dim_state.get('taught', []))

    # Get principles for this dim at current depth
    candidates = [p for p in _CURRICULUM
                  if p['dim'] == weakest and p['depth'] == cur_depth]

    # Find first untaught
    lesson = None
    for p in candidates:
        if p['id'] not in taught:
            lesson = p
            break

    # All taught at this depth — advance
    if lesson is None:
        cur_depth = cur_depth + 1 if cur_depth < 3 else 1
        state[weakest]['depth'] = cur_depth
        state[weakest]['taught'] = []
        candidates = [p for p in _CURRICULUM
                      if p['dim'] == weakest and p['depth'] == cur_depth]
        lesson = candidates[0] if candidates else None

    if lesson is None:
        return None

    # Alternate master days
    show_master = (not state['last_had_master']) and bool(lesson.get('master'))

    # Get genre-specific assignment
    assignment = lesson['assignments'].get(mission_genre,
                 lesson['assignments'].get('Wildlife', ''))

    return {
        'principle_id':     lesson['id'],
        'dim':              weakest,
        'dim_label':        _DIM_LABELS.get(weakest, weakest),
        'dim_short':        _DIM_SHORT.get(weakest, weakest),
        'depth':            lesson['depth'],
        'title':            lesson['title'],
        'principle':        lesson['principle'],
        'assignment':       assignment,
        'indoor_assignment': lesson.get('indoor_assignment', ''),
        'commons_file':     lesson.get('commons_file'),
        'commons_caption':  lesson.get('commons_caption'),
        'show_master':      show_master,
        'master':           lesson.get('master') if show_master else None,
        'master_quote':     lesson.get('master_quote') if show_master else None,
        'mission_genre':    mission_genre,
    }


def _advance_curriculum(user_id, principle_id, dim):
    """
    Mark a principle as taught after a mission-linked upload.
    Called from the upload route when mission_dimension is set.
    Safe — swallows all errors.
    """
    import json as _json
    try:
        raw = db.session.execute(
            db.text('SELECT curriculum_state FROM users WHERE id = :uid'),
            {'uid': user_id}
        ).scalar()
        state = raw if isinstance(raw, dict) else (_json.loads(raw) if raw else {})
        for _d in _DIM_KEYS:
            if _d not in state:
                state[_d] = {'depth': 1, 'taught': []}
        if 'last_had_master' not in state:
            state['last_had_master'] = False

        if dim in state:
            taught = state[dim].get('taught', [])
            if principle_id not in taught:
                taught.append(principle_id)
            state[dim]['taught'] = taught

        # Toggle master flag
        state['last_had_master'] = not state.get('last_had_master', False)

        db.session.execute(
            db.text('UPDATE users SET curriculum_state = :s WHERE id = :uid'),
            {'s': _json.dumps(state), 'uid': user_id}
        )
        db.session.commit()
    except Exception as _ce:
        app.logger.warning(f'[curriculum_advance] {_ce}')
        db.session.rollback()


@app.route('/mission-genre', methods=['POST'])
@login_required
def set_mission_genre():
    """
    Set or clear the user's mission genre override.
    POST body: genre=Wildlife (or 'engine' to clear)
    """
    genre = request.form.get('genre', '').strip()
    if genre == 'engine' or genre not in _VALID_MISSION_GENRES:
        genre = None
    try:
        db.session.execute(
            db.text('UPDATE users SET mission_genre = :g WHERE id = :uid'),
            {'g': genre, 'uid': current_user.id}
        )
        db.session.commit()
    except Exception as _mg_e:
        db.session.rollback()
        app.logger.warning(f'[mission_genre] {_mg_e}')
    return redirect(url_for('dashboard'))


@app.route('/profile', methods=['GET', 'POST'])
@login_required
def profile():
    images_used = Image.query.filter_by(user_id=current_user.id).count()

    if request.method == 'POST':
        action = request.form.get('action')

        # -- Update profile details ----------------------------------------
        if action == 'update_profile':
            new_username  = request.form.get('username', '').strip()
            new_full_name = request.form.get('full_name', '').strip()

            if not new_username:
                flash('Username cannot be empty.', 'error')
                return redirect(url_for('profile'))

            existing = User.query.filter_by(username=new_username).first()
            if existing and existing.id != current_user.id:
                flash('That username is already taken.', 'error')
                return redirect(url_for('profile'))

            current_user.username  = new_username
            current_user.full_name = new_full_name
            db.session.commit()
            flash('Profile updated successfully.', 'success')
            return redirect(url_for('profile'))

        # -- Update active location (replaces Item B GPS travel detection) --
        elif action == 'update_location':
            new_country = request.form.get('country', '').strip()
            new_state   = request.form.get('state', '').strip()
            new_city    = request.form.get('city', '').strip()
            _next       = request.form.get('next', '').strip()
            _redirect_to = url_for('dashboard') if _next == 'dashboard' else url_for('profile')

            if not new_country or not new_state or not new_city:
                flash('Please select a country, state/province, and city.', 'error')
                return redirect(_redirect_to)

            # For countries without detailed state/city data, State and City
            # come from free-text inputs — validate + normalise, and log for
            # admin review (mirrors GenreSuggestion's 'Other' genre pattern).
            if not has_detailed_location_data(new_country):
                _state_norm = _validate_location_text(new_state)
                _city_norm  = _validate_location_text(new_city)
                if not _state_norm or not _city_norm:
                    flash('Please enter a valid state/province and city (letters, spaces, hyphens, and apostrophes only).', 'error')
                    return redirect(_redirect_to)
                new_state, new_city = _state_norm, _city_norm
                _log_location_suggestion(current_user.id, new_country, new_state, new_city)

            old_city = current_user.city or ''
            current_user.country = new_country
            current_user.state   = new_state
            current_user.city    = new_city
            # Clear any stale Item B GPS-drift state — Active Location is now authoritative
            current_user.pending_location_update = None
            current_user.last_gps_city = None
            current_user.last_gps_city_since = None
            db.session.commit()

            # Item D — if this city has no seasonal data yet, queue priority
            # discovery for the user's genre interests (same pattern as
            # confirm_location_update / Item B).
            if new_city and new_city != old_city and new_city != 'Other':
                try:
                    from engine.seasonal_discovery import enqueue_priority_combo
                    from engine.seasonal_calendar import get_primary_genre
                    genres = []
                    try:
                        genres = json.loads(current_user.genre_interests or '[]')[:3]
                    except Exception:
                        pass
                    if not genres:
                        genres = [get_primary_genre(current_user) or 'Wildlife']
                    for _g in genres:
                        if _g:
                            enqueue_priority_combo(db.session, new_city, _g)
                except Exception as _disc_err:
                    app.logger.warning(f'[update_location] priority discovery enqueue failed: {_disc_err}')

            if new_city == 'Other':
                flash(
                    f'Active location updated to {new_state}, {new_country}. '
                    f"We don't have detailed local data for this area yet — "
                    f"\"near you\" advice may be limited.", 'success'
                )
            else:
                flash(f'Active location updated to {new_city}.', 'success')
            return redirect(_redirect_to)

        # -- Change password -----------------------------------------------
        elif action == 'change_password':
            current_pw = request.form.get('current_password', '')
            new_pw     = request.form.get('new_password', '')
            confirm_pw = request.form.get('confirm_password', '')

            if not check_password_hash(current_user.password_hash, current_pw):
                flash('Current password is incorrect.', 'error')
                return redirect(url_for('profile'))
            if len(new_pw) < 8:
                flash('New password must be at least 8 characters.', 'error')
                return redirect(url_for('profile'))
            if new_pw != confirm_pw:
                flash('New passwords do not match.', 'error')
                return redirect(url_for('profile'))

            current_user.password_hash = generate_password_hash(new_pw)
            db.session.commit()
            flash('Password updated. Please log in again with your new password.', 'success')
            logout_user()
            return redirect(url_for('login'))

    progress_data = _build_progress_data(current_user)
    _ref_code  = get_or_create_referral_code(current_user)
    _ref_stats = get_referral_stats(current_user)
    _site_url  = os.getenv('SITE_URL', 'https://shutterleague.com')
    _ref_url   = f'{_site_url}/ref/{_ref_code}' if _ref_code else None

    # Location data for the Active Location dropdown (same structure as /onboarding)
    _loc = {}
    for _s, _c in INDIA_STATES_CITIES.items():
        _loc.setdefault('India', {})[_s] = _c
    for _country, _states in WORLD_LOCATIONS.items():
        _loc[_country] = _states

    return render_template('profile.html', images_used=images_used, progress_data=progress_data,
                           referral_code=_ref_code, referral_stats=_ref_stats, referral_url=_ref_url,
                           countries=get_countries(), location_data_json=json.dumps(_loc))


# ---------------------------------------------------------------------------
# Account deletion — DPDP Act 2023 compliance (right to erasure)
# ---------------------------------------------------------------------------

@app.route('/account/delete', methods=['GET', 'POST'])
@login_required
def account_delete():
    """GET: Show confirmation page. POST: Execute deletion."""
    if current_user.role == 'admin':
        flash('Admin accounts cannot be self-deleted. Contact another admin.', 'error')
        return redirect(url_for('profile'))

    if request.method == 'GET':
        image_count = Image.query.filter_by(user_id=current_user.id).count()
        return render_template('account_delete_confirm.html', image_count=image_count)

    # POST — execute deletion
    if current_user.role == 'admin':
        flash('Admin accounts cannot be self-deleted.', 'error')
        return redirect(url_for('profile'))

    confirmation = request.form.get('confirmation', '').strip()
    if confirmation != 'DELETE':
        flash('Please type DELETE (in capitals) to confirm account deletion.', 'error')
        return redirect(url_for('account_delete'))

    user_id      = current_user.id
    user_email   = current_user.email
    user_name    = current_user.full_name or current_user.username
    user_track   = getattr(current_user, 'subscription_track', None)

    # Log out before deletion so session is clean
    logout_user()

    try:
        user = User.query.get(user_id)
        if not user:
            return redirect(url_for('index'))

        image_ids = [img.id for img in user.images]

        # 1. CalibrationNotes
        try:
            from models import CalibrationNote
            CalibrationNote.query.filter_by(admin_id=user_id).delete()
            if image_ids:
                CalibrationNote.query.filter(
                    CalibrationNote.image_id.in_(image_ids)
                ).delete(synchronize_session=False)
        except Exception as _e:
            app.logger.warning(f'[self_delete] calibration notes: {_e}')

        # 2. ImageReports
        try:
            ImageReport.query.filter_by(reporter_id=user_id).delete()
            if image_ids:
                ImageReport.query.filter(
                    ImageReport.image_id.in_(image_ids)
                ).delete(synchronize_session=False)
        except Exception as _e:
            app.logger.warning(f'[self_delete] image reports: {_e}')

        # 3. Peer ratings given + received
        try:
            PeerRating.query.filter_by(rater_id=user_id).delete()
            if image_ids:
                PeerRating.query.filter(
                    PeerRating.image_id.in_(image_ids)
                ).delete(synchronize_session=False)
        except Exception as _e:
            app.logger.warning(f'[self_delete] peer ratings: {_e}')

        # 4. Rating assignments
        try:
            RatingAssignment.query.filter_by(rater_id=user_id).delete()
            if image_ids:
                RatingAssignment.query.filter(
                    RatingAssignment.image_id.in_(image_ids)
                ).delete(synchronize_session=False)
        except Exception as _e:
            app.logger.warning(f'[self_delete] rating assignments: {_e}')

        # 5. Peer pool entries
        try:
            PeerPoolEntry.query.filter_by(user_id=user_id).delete()
            if image_ids:
                PeerPoolEntry.query.filter(
                    PeerPoolEntry.image_id.in_(image_ids)
                ).delete(synchronize_session=False)
        except Exception as _e:
            app.logger.warning(f'[self_delete] peer pool: {_e}')

        # 6. Contest entries
        try:
            ContestEntry.query.filter_by(user_id=user_id).delete()
        except Exception as _e:
            app.logger.warning(f'[self_delete] contest entries: {_e}')

        # 7. Open contest entries
        try:
            OpenContestEntry.query.filter_by(user_id=user_id).delete()
        except Exception as _e:
            app.logger.warning(f'[self_delete] open contest entries: {_e}')

        # 8. BOW submissions
        try:
            from models import BowSubmission
            BowSubmission.query.filter_by(user_id=user_id).delete()
        except Exception as _e:
            app.logger.warning(f'[self_delete] bow submissions: {_e}')

        # 9. POTY entries
        try:
            db.session.execute(
                db.text('DELETE FROM poty_entries WHERE user_id = :uid'),
                {'uid': user_id}
            )
            db.session.execute(
                db.text('DELETE FROM poty_entry_images WHERE entry_id IN '
                        '(SELECT id FROM poty_entries WHERE user_id = :uid)'),
                {'uid': user_id}
            )
        except Exception as _e:
            app.logger.warning(f'[self_delete] poty entries: {_e}')

        # 10. RAW submissions + scored_phash_cache
        try:
            if image_ids:
                db.session.execute(
                    db.text('DELETE FROM raw_submissions WHERE image_id = ANY(:ids)'),
                    {'ids': image_ids}
                )
            db.session.execute(
                db.text('DELETE FROM scored_phash_cache WHERE user_id = :uid'),
                {'uid': user_id}
            )
        except Exception as _e:
            app.logger.warning(f'[self_delete] raw/cache: {_e}')

        # 11. Images + R2 cleanup
        for img in list(user.images):
            if img.thumb_url:
                try:
                    key = img.thumb_url.split(r2.R2_PUBLIC_URL + '/')[-1]
                    r2.delete_file(key)
                except Exception:
                    pass
            if img.card_url:
                try:
                    key = img.card_url.split(r2.R2_PUBLIC_URL + '/')[-1]
                    r2.delete_file(key)
                except Exception:
                    pass
            db.session.delete(img)

        # 12. Delete user record
        db.session.delete(user)
        db.session.commit()

        app.logger.info(
            f'[self_delete] user_id={user_id} email={user_email} '
            f'track={user_track} — permanently deleted'
        )

        # Send farewell confirmation email
        try:
            _site = os.getenv('SITE_URL', 'https://shutterleague.com')
            send_email(
                to_addresses=[user_email],
                subject='Your Shutter League account has been deleted',
                html_body=(
                    '<!DOCTYPE html><html><head><meta charset="UTF-8"></head>'
                    '<body style="margin:0;padding:0;background:#F5F0E8;font-family:Georgia,serif;">'
                    '<table width="100%" cellpadding="0" cellspacing="0" style="background:#F5F0E8;padding:32px 16px;">'
                    '<tr><td align="center">'
                    '<table width="560" cellpadding="0" cellspacing="0" style="background:#ffffff;border:1px solid #E0D8C8;border-radius:8px;overflow:hidden;max-width:560px;width:100%;">'
                    '<tr><td style="background:#1a1a18;padding:20px 28px 16px;">'
                    '<p style="margin:0;font-family:Courier New,monospace;font-size:15px;font-weight:700;letter-spacing:3px;color:#C8A84B;text-transform:uppercase;">Shutter League</p>'
                    '</td></tr>'
                    '<tr><td style="padding:28px 28px 24px;">'
                    '<h2 style="font-size:20px;font-weight:700;color:#1a1a18;margin:0 0 16px;">Account deleted</h2>'
                    '<p style="font-size:16px;line-height:1.7;color:#4A4840;margin:0 0 14px;">Hi ' + user_name + ',</p>'
                    '<p style="font-size:16px;line-height:1.7;color:#4A4840;margin:0 0 14px;">'
                    'Your Shutter League account and all associated data have been permanently deleted. '
                    'This action cannot be undone.</p>'
                    '<p style="font-size:16px;line-height:1.7;color:#4A4840;margin:0 0 14px;">'
                    'What was deleted: your profile, all uploaded images, scores, standings, and personal data.</p>'
                    '<p style="font-size:15px;line-height:1.7;color:#4A4840;margin:0 0 24px;">'
                    'If you did not request this deletion or believe it was made in error, '
                    'please contact us immediately at '
                    '<a href="mailto:' + CONTACT_EMAIL + '" style="color:#C8A84B;">' + CONTACT_EMAIL + '</a>.</p>'
                    '<p style="font-size:15px;color:#8a8070;margin:0;">&#8212; Shutter League</p>'
                    '</td></tr>'
                    '<tr><td style="border-top:1px solid #E0D8C8;padding:12px 28px;">'
                    '<p style="margin:0;font-size:15px;color:#8a8070;">Shutter League &nbsp;&#183;&nbsp; '
                    '<a href="' + _site + '" style="color:#C8A84B;">shutterleague.com</a></p>'
                    '</td></tr>'
                    '</table></td></tr></table></body></html>'
                ),
                text_body=(
                    'Hi ' + user_name + ',\n\n'
                    'Your Shutter League account and all associated data have been permanently deleted.\n\n'
                    'What was deleted: your profile, all uploaded images, scores, standings, and personal data.\n\n'
                    'If you did not request this or believe it was made in error, '
                    'contact us at ' + CONTACT_EMAIL + '\n\n'
                    '-- Shutter League'
                )
            )
        except Exception as _email_err:
            app.logger.warning(f'[self_delete] farewell email failed: {_email_err}')

        # Notify admin
        try:
            send_email(
                to_addresses=[ADMIN_EMAIL],
                subject=f'[Admin] Account self-deleted — {user_email}',
                html_body=(
                    '<div style="font-family:Courier New,monospace;max-width:560px;margin:0 auto;padding:32px;">'
                    '<p style="color:#C8A84B;font-weight:700;">ACCOUNT SELF-DELETED</p>'
                    '<p>User: ' + user_name + ' (' + user_email + ')<br>'
                    'User ID: ' + str(user_id) + '<br>'
                    'Track: ' + (user_track or 'none') + '</p>'
                    '<p style="color:#8a8070;">All data permanently deleted per DPDP Act 2023 right to erasure.</p>'
                    '</div>'
                )
            )
        except Exception:
            pass

    except Exception as _del_err:
        db.session.rollback()
        app.logger.error(f'[self_delete] failed for user_id={user_id}: {_del_err}')
        # User is already logged out — redirect to home with generic message
        return redirect(url_for('index'))

    return redirect(url_for('account_deleted'))


@app.route('/account/deleted')
def account_deleted():
    """Landing page shown after successful account deletion."""
    return render_template('account_deleted.html')



def _check_upload_quota(user):
    """
    Returns a user-facing message string if `user` is currently blocked from
    uploading (free-tier lifetime limit used up, dormant-track pause, or a
    subscribed track's monthly limit reached) — or None if they're clear.

    Pure logic only, no flash/redirect/jsonify here — the /upload route
    decides how to respond, since GET and POST need slightly different
    response shapes (GET always redirects with a flash; POST also supports
    a JSON response for XHR submissions).

    Mirrors exactly the checks that used to live inline in the POST branch
    of /upload, extracted so the SAME check also runs on GET — this blocks
    the upload FORM itself for a free user who's out of quota, rather than
    letting them fill it out and submit before finding out.
    """
    _plan = getattr(user, 'subscription_plan', None) or ''
    if user.role == 'admin' or _plan in ('beta', 'uat'):
        return None  # UAT/beta/admin — unlimited, skip all quota checks

    from datetime import date as _date
    today   = _date.today()
    _track  = getattr(user, 'subscription_track', None) or ''
    _is_sub = getattr(user, 'is_subscribed', False)

    if not _is_sub:
        # Free tier — 3 lifetime assessments per user_id + referral bonus
        # Uses total_uploads_ever — never decremented on delete.
        # Deleting images does NOT restore free slots.
        _lifetime = getattr(user, 'total_uploads_ever', None)
        if _lifetime is None:
            # total_uploads_ever is NULL — repair it now from current image count.
            # Using current count is safe here: if it's NULL the user predates the
            # migration and has never had the gate enforced, so current count is
            # the best available proxy. Once set it is never decremented.
            _lifetime = Image.query.filter(Image.user_id == user.id).count()
            try:
                db.session.execute(
                    db.text("UPDATE users SET total_uploads_ever = :n WHERE id = :uid AND total_uploads_ever IS NULL"),
                    {'n': _lifetime, 'uid': user.id}
                )
                db.session.commit()
            except Exception:
                pass
        _bonus = getattr(user, 'referral_bonus_uploads', 0) or 0
        if _lifetime >= (FREE_IMAGE_LIMIT + _bonus):
            _limit_shown = FREE_IMAGE_LIMIT + _bonus

            # Build a short account of where the limit went, so the message
            # explains itself instead of looking broken when someone has
            # deleted down to fewer photos than their lifetime limit (e.g.
            # "The Class (7.12) · 2 photographs uploaded and deleted
            # earlier" rather than a flat "you're out of slots" sitting
            # next to a near-empty gallery). Deleted entries only exist
            # from the upload_history_log migration (v80) onward — deletes
            # from before that aren't logged, since the old hard-delete
            # left nothing behind to reconstruct after the fact.
            _current_imgs = (Image.query
                              .filter(Image.user_id == user.id)
                              .order_by(Image.created_at.asc())
                              .limit(_limit_shown)
                              .all())
            _current_parts = [
                (f'{_img.asset_name or "Untitled"} ({_img.score:.2f})' if _img.score is not None
                 else (_img.asset_name or 'Untitled'))
                for _img in _current_imgs
            ]
            try:
                _deleted_count = db.session.execute(
                    db.text("SELECT COUNT(*) FROM upload_history_log WHERE user_id = :uid"),
                    {'uid': user.id}
                ).scalar() or 0
            except Exception:
                _deleted_count = 0

            _account_parts = []
            if _current_parts:
                _account_parts.append(', '.join(_current_parts))
            if _deleted_count:
                _account_parts.append(
                    f'{_deleted_count} photograph{"s" if _deleted_count != 1 else ""} '
                    f'uploaded and deleted earlier'
                )
            _account_clause = f' {" · ".join(_account_parts)}.' if _account_parts else ''

            return (f'You have used your {_limit_shown} free assessments.{_account_clause} '
                    'Deleting images does not restore free slots — '
                    'upgrade to Mobile or Camera League (₹200/mo) to keep uploading.')
        return None

    if _track == 'dormant':
        # Dormant mode — rank preserved, 0 uploads
        return ('Your subscription is in Dormant mode. Uploads are paused. '
                'Reactivate your Mobile or Camera subscription to resume.')

    if _track in ('mobile', 'camera', 'learning'):
        # Subscribed tracks — check monthly count
        month_start = datetime(today.year, today.month, 1)
        month_count = Image.query.filter(
            Image.user_id == user.id,
            Image.created_at >= month_start,
        ).count()
        if _track == 'mobile':
            MOBILE_IMAGE_LIMIT = 8
            if month_count >= MOBILE_IMAGE_LIMIT:
                return (f'You have used all {MOBILE_IMAGE_LIMIT} Mobile images for this month. '
                        'Your quota resets on the 1st of next month.')
        elif _track == 'camera':
            CAMERA_IMAGE_LIMIT = 5
            if month_count >= CAMERA_IMAGE_LIMIT:
                return (f'You have used all {CAMERA_IMAGE_LIMIT} Camera images for this month. '
                        'Your quota resets on the 1st of next month.')
        elif _track == 'learning':
            if month_count >= LEARNING_IMAGE_LIMIT:
                return (f'You have used all {LEARNING_IMAGE_LIMIT} Learning tier images for this month. '
                        'Upgrade to Mobile or Camera to upload more.')
    # Mentor track — unlimited, no check needed
    return None


@app.route('/upload', methods=['GET', 'POST'])
@login_required
def upload():
    # Interests must be complete before uploading — genre_interests drives
    # seasonal advisory, curriculum dimension selection, and scoring context.
    if not getattr(current_user, 'interests_complete', False):
        session['post_login_next'] = request.url
        return redirect(url_for('onboarding_interests'))

    # Quota check — runs for GET and POST alike, so a free user who's out of
    # quota gets stopped the moment they click "Upload" anywhere on the site,
    # not after they've picked a file and submitted the form.
    _quota_msg = _check_upload_quota(current_user)
    if _quota_msg:
        if request.method == 'POST' and (request.headers.get('X-Requested-With') == 'XMLHttpRequest' or request.form.get('_xhr') == '1'):
            return jsonify({'error': True, 'message': _quota_msg}), 403
        flash(_quota_msg, 'warning')
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        file = request.files.get('image')
        if not file or file.filename == '':
            flash('No file selected.', 'error')
            return redirect(request.url)
        if not allowed_file(file.filename):
            flash('File type not supported.', 'error')
            return redirect(request.url)

        uid       = str(uuid.uuid4())
        filename  = secure_filename(file.filename)
        raw_path  = os.path.join(app.config['UPLOAD_FOLDER'], 'raw', f"{uid}_{filename}")
        file.save(raw_path)

        # ── MPO format guard — convert to JPEG before pipeline ─────────────────
        # MPO (Multi Picture Object, iPhone Portrait mode) causes the vision API
        # to hang indefinitely. Detect and convert to standard JPEG before ingestion.
        try:
            from PIL import Image as _PILImage
            with _PILImage.open(raw_path) as _pil_img:
                if getattr(_pil_img, 'format', '').upper() == 'MPO':
                    app.logger.info(f'[upload] MPO detected — converting to JPEG: {raw_path}')
                    _pil_rgb = _pil_img.convert('RGB')
                    _jpeg_path = raw_path.rsplit('.', 1)[0] + '_converted.jpg'
                    _pil_rgb.save(_jpeg_path, 'JPEG', quality=95)
                    if os.path.exists(raw_path):
                        os.remove(raw_path)
                    raw_path = _jpeg_path
        except Exception as _mpo_err:
            app.logger.warning(f'[upload] MPO check failed (continuing): {_mpo_err}')

        try:
            thumb_path, w, h, fmt, phash = ingest_image(raw_path, app.config['UPLOAD_FOLDER'])
        except Exception as e:
            if os.path.exists(raw_path): os.remove(raw_path)
            if request.headers.get('X-Requested-With') == 'XMLHttpRequest' or request.form.get('_xhr') == '1':
                return jsonify({'error': True, 'message': str(e)}), 422
            flash(f'Image processing failed: {e}', 'error')
            return redirect(request.url)        # Extract EXIF from original file BEFORE deletion  -  raw_path still has full metadata
        from engine.exif_check import extract_exif
        exif_status, exif_data, exif_warning = extract_exif(raw_path)
        exif_settings = '  .  '.join(filter(None, [
            exif_data.get('focal_length',''), exif_data.get('aperture',''),
            exif_data.get('iso',''), exif_data.get('shutter',''),
        ]))

        # ── Device tier detection (v62) ────────────────────────────────────────
        from engine.auto_score import get_device_tier, build_exif_context
        _camera_track_for_tier = request.form.get('camera_track') or getattr(current_user, 'subscription_track', None)
        _device_tier   = get_device_tier(exif_data)
        _exif_context  = build_exif_context(exif_data, camera_track=_camera_track_for_tier)

        if os.path.exists(raw_path): os.remove(raw_path)

        from engine.processor import hash_similarity_pct
        _near_match_previous = None   # (score, audit_json) for delta scoring
        existing = Image.query.filter(Image.phash.isnot(None)).all()
        for ex in existing:
            sim = hash_similarity_pct(phash, ex.phash)
            if ex.user_id == current_user.id and sim >= 99.0:
                # Exact re-upload of a file the user already has in their gallery.
                # Do NOT block — the phash cache will return the anchored score below.
                # Just break out of the loop; cache hit handles it.
                app.logger.info(
                    f'[upload] exact phash match (sim={sim:.1f}%) on existing image '
                    f'{ex.id} — cache will anchor score, not blocking'
                )
                break
            elif ex.user_id == current_user.id and sim >= 85.0:
                # Near-match — this is an edited version of a previously scored image.
                # Allow upload. Capture previous score + audit for delta scoring.
                if ex.status == 'scored' and ex.score:
                    _prev_audit_json = ex._audit_json or ''
                    try:
                        import json as _json
                        _prev_audit = _json.loads(_prev_audit_json) if _prev_audit_json else {}
                    except Exception:
                        _prev_audit = {}
                    _near_match_previous = {
                        'score':      float(ex.score),
                        'audit':      _prev_audit,
                        'image_id':   ex.id,
                        'similarity': sim,
                    }
                    app.logger.info(
                        f'[upload] near-match edit detected (sim={sim:.1f}%) — '
                        f'previous score={ex.score} image={ex.id} — delta scoring enabled'
                    )
                break
            elif ex.user_id != current_user.id and sim >= 98.0:
                if os.path.exists(thumb_path): os.remove(thumb_path)
                return jsonify({'error': True, 'message':
                    'We were unable to accept this image. Our system has detected that it may be identical to a photograph already in our database. '
                    'Please ensure you are submitting your own original work. '
                    'If you believe this is an error, contact support@shutterleague.com and we will review it promptly.'
                }), 409

        # Blocklist check — reject known confirmed AI images
        from models import FlaggedPhash as _FlaggedPhash
        for _fp in _FlaggedPhash.query.all():
            if _fp.phash and hash_similarity_pct(phash, _fp.phash) >= 98.0:
                if os.path.exists(thumb_path): os.remove(thumb_path)
                return jsonify({'error': True, 'message':
                    'We were unable to accept this image. '
                    'Please ensure you are submitting your own original work. '
                    'If you believe this is an error, contact support@shutterleague.com and we will review it promptly.'
                }), 409

        # ── Score anchor — phash cache (v63) ──────────────────────────────────
        # If this user previously uploaded and scored this identical image
        # (same phash, same genre), return the cached score instead of calling
        # the engine again. Prevents score re-rolling via delete + re-upload.
        # Stored in scored_phash_cache which survives image deletion.
        _anchored_score = None
        try:
            _cache_row = db.session.execute(
                db.text(
                    "SELECT score, tier, dod_score, disruption_score, dm_score, "
                    "wonder_score, aq_score, archetype, soul_bonus, original_image_id, audit_json "
                    "FROM scored_phash_cache "
                    "WHERE user_id = :uid AND phash = :ph AND genre = :genre "
                    "ORDER BY scored_at DESC LIMIT 1"
                ),
                {'uid': current_user.id, 'ph': phash,
                 'genre': normalise_genre(request.form.get('genre', '').strip())}
            ).fetchone()
            if _cache_row:
                _anchored_score = dict(_cache_row._mapping)
                app.logger.info(
                    f'[upload] phash cache hit: user={current_user.id} '
                    f'phash={phash[:16]}… anchored_score={_anchored_score["score"]}'
                )
                # If the cached original has no audit_json, don't anchor —
                # fall through to the engine so this upload gets a full
                # scorecard (avoids the empty-scorecard bug on duplicate
                # uploads of images scored before audit_json existed, or
                # whose original was deleted without audit_json).
                _orig_id = _anchored_score.get('original_image_id')
                _has_audit = False
                if _orig_id:
                    try:
                        _audit_check = db.session.execute(
                            db.text("SELECT audit_json FROM images WHERE id = :iid"),
                            {'iid': _orig_id}
                        ).fetchone()
                        if _audit_check and _audit_check[0]:
                            _has_audit = True
                    except Exception:
                        pass
                if not _has_audit:
                    app.logger.info(
                        f'[upload] cache hit but no audit_json on original '
                        f'{_orig_id} — falling through to engine for image {phash[:16]}…'
                    )
                    _anchored_score = None
        except Exception as _cache_err:
            app.logger.warning(f'[upload] phash cache lookup failed (non-fatal): {_cache_err}')

        # ── Watermark / logo detection (v62) ──────────────────────────────────
        # Runs synchronously before DB save or R2 upload — immediate rejection.
        # Uses Haiku for speed and cost. Fails open (upload proceeds) if API is
        # unavailable so a network blip never blocks legitimate uploads.
        try:
            _wm_api_key = os.getenv('ANTHROPIC_API_KEY', '')
            if _wm_api_key and os.path.exists(thumb_path):
                import base64 as _b64, urllib.request as _wmur, json as _wmjson
                from PIL import Image as _PILWM
                import io as _wmio

                # Resize to 1024px max for speed — watermarks are visible at low res
                _wm_pil = _PILWM.open(thumb_path).convert('RGB')
                if max(_wm_pil.size) > 1024:
                    _wm_pil.thumbnail((1024, 1024))
                _wm_buf = _wmio.BytesIO()
                _wm_pil.save(_wm_buf, format='JPEG', quality=80)
                _wm_b64 = _b64.b64encode(_wm_buf.getvalue()).decode('utf-8')

                _wm_payload = _wmjson.dumps({
                    'model': 'claude-haiku-4-5-20251001',
                    'max_tokens': 100,
                    'messages': [{
                        'role': 'user',
                        'content': [
                            {'type': 'image', 'source': {'type': 'base64', 'media_type': 'image/jpeg', 'data': _wm_b64}},
                            {'type': 'text', 'text': (
                                'Does this photograph contain a photographer-added watermark, text overlay, '
                                'studio logo, social media handle (@username), copyright text, or any branding '
                                'embedded into the image by the photographer? '
                                'Do NOT flag: image content (signs, billboards, labels that are part of the scene), '
                                'platform watermarks, or natural scene text. '
                                'Only flag overlays added on top of the photograph after capture. '
                                'Respond ONLY with JSON: {"watermark_detected": true/false, "description": "one short phrase or null"}'
                            )}
                        ]
                    }]
                }).encode('utf-8')

                _wm_req = _wmur.Request(
                    'https://api.anthropic.com/v1/messages',
                    data=_wm_payload,
                    headers={'Content-Type': 'application/json', 'x-api-key': _wm_api_key,
                             'anthropic-version': '2023-06-01'},
                    method='POST'
                )
                with _wmur.urlopen(_wm_req, timeout=15) as _wmresp:
                    _wm_result = _wmjson.loads(_wmresp.read().decode())

                _wm_text = _wm_result.get('content', [{}])[0].get('text', '{}')
                _wm_text = _wm_text.strip().lstrip('`').lstrip('json').strip('`').strip()
                _wm_data = _wmjson.loads(_wm_text)

                if _wm_data.get('watermark_detected'):
                    if os.path.exists(thumb_path): os.remove(thumb_path)
                    app.logger.info(f'[upload] watermark rejected: {_wm_data.get("description")} uid={current_user.id}')
                    _wm_msg = (
                        'Your image appears to contain a watermark, logo, or text overlay. '
                        'Shutter League evaluates the original photograph only — please remove any '
                        'added text, handles, or branding and re-upload the clean image.'
                    )
                    if request.headers.get('X-Requested-With') == 'XMLHttpRequest' or request.form.get('_xhr') == '1':
                        return jsonify({'error': True, 'message': _wm_msg}), 422
                    flash(_wm_msg, 'error')
                    return redirect(request.url)

        except Exception as _wm_err:
            # Fail open — network or API error must never block a legitimate upload
            app.logger.warning(f'[upload] watermark check failed (non-fatal): {_wm_err}')

        # ── NSFW / Nudity detection (v63) ─────────────────────────────────────
        # Uses Claude Haiku vision — same pattern as watermark check above.
        # Hard reject: nudity / explicit content → delete thumb, block upload.
        # Breastfeeding: passes upload, flagged for scoring-thread sub-genre check.
        # Fails open — API error never blocks a legitimate upload.
        _nsfw_breastfeeding_flagged = False
        try:
            _nsfw_api_key = os.getenv('ANTHROPIC_API_KEY', '')
            if _nsfw_api_key and os.path.exists(thumb_path):
                import base64 as _nsfw_b64, urllib.request as _nsfw_ur, json as _nsfw_json
                from PIL import Image as _PIL_nsfw
                import io as _nsfw_io

                # Resize to 1024px max — nudity is obvious at low res, saves tokens
                _nsfw_pil = _PIL_nsfw.open(thumb_path).convert('RGB')
                if max(_nsfw_pil.size) > 1024:
                    _nsfw_pil.thumbnail((1024, 1024))
                _nsfw_buf = _nsfw_io.BytesIO()
                _nsfw_pil.save(_nsfw_buf, format='JPEG', quality=80)
                _nsfw_b64_data = _nsfw_b64.b64encode(_nsfw_buf.getvalue()).decode('utf-8')

                _nsfw_prompt = (
                    'Examine this photograph carefully. Respond ONLY with JSON — no other text. '
                    'Return: {"nudity": true/false, "breastfeeding": true/false, "description": "one short phrase or null"} '
                    'Where: '
                    '"nudity" = true ONLY if the image contains explicit nudity, exposed genitalia, bare breasts '
                    '(other than breastfeeding), or explicit sexual content. '
                    'IMPORTANT: Traditional, cultural, or religious attire must NOT be flagged — this includes '
                    'dhotis, mundus, lungis, sarongs, loincloths, bare-chested traditional dress at festivals, '
                    'temples, or cultural events (common in South Asian, African, and Pacific cultures), '
                    'and any other regional clothing that leaves skin exposed as a matter of cultural practice. '
                    'ALSO IMPORTANT: Commercial, editorial, or advertising photography — billboards, posters, '
                    'magazine ads, fashion/swimwear/lingerie shoots, sports uniforms — must NOT be flagged for '
                    'showing models in swimwear, lingerie, or undergarments. Only flag this kind of image if it '
                    'exposes genitalia or bare breasts, or is otherwise explicit/sexual rather than commercial. '
                    'ALSO IMPORTANT: Vigorous physical activity — sports, water play, splashing, running, '
                    'wrestling, bent-over or twisted poses, wet clothing clinging to the body — must NOT be '
                    'flagged as nudity on its own. Only flag if genitalia or bare breasts are clearly and '
                    'unambiguously visible, regardless of pose, motion, or activity. '
                    'ALSO IMPORTANT: Bare-chested men in any context — family portraits, street photography, '
                    'documentary, everyday life, cultural events, sports, or casual settings — must NOT be '
                    'flagged. Male shirtlessness is not nudity. Only flag a male subject if genitalia '
                    'are explicitly exposed. '
                    'ALSO IMPORTANT: Children in age-appropriate contexts must NOT be flagged. This includes '
                    'boys shirtless or in underwear in family, beach, play, or everyday settings; girls in '
                    'age-appropriate swimwear (bikinis, one-piece), underwear, or everyday clothing; children '
                    'bathing, swimming, playing, or in family portraits. Only flag a child if genitalia are '
                    'explicitly and unambiguously exposed, or if there are clear signs of sexual exploitation '
                    'or abuse. When in doubt about a child image, return nudity=false. '
                    'Fine art nude studies with no explicit or sexual context should still be flagged as nudity=true. '
                    '"breastfeeding" = true ONLY if a mother is visibly breastfeeding an infant — '
                    'this overrides nudity=true when present. '
                    '"description" = one short phrase describing what was detected, or null if clean.'
                )

                _nsfw_payload = _nsfw_json.dumps({
                    'model': 'claude-haiku-4-5-20251001',
                    'max_tokens': 80,
                    'messages': [{
                        'role': 'user',
                        'content': [
                            {'type': 'image', 'source': {
                                'type': 'base64', 'media_type': 'image/jpeg', 'data': _nsfw_b64_data
                            }},
                            {'type': 'text', 'text': _nsfw_prompt}
                        ]
                    }]
                }).encode('utf-8')

                _nsfw_req = _nsfw_ur.Request(
                    'https://api.anthropic.com/v1/messages',
                    data=_nsfw_payload,
                    headers={
                        'Content-Type': 'application/json',
                        'x-api-key': _nsfw_api_key,
                        'anthropic-version': '2023-06-01',
                    },
                    method='POST'
                )
                with _nsfw_ur.urlopen(_nsfw_req, timeout=20) as _nsfw_resp:
                    _nsfw_result = _nsfw_json.loads(_nsfw_resp.read().decode('utf-8'))

                _nsfw_raw = _nsfw_result.get('content', [{}])[0].get('text', '{}')
                _nsfw_raw = _nsfw_raw.strip().lstrip('`').lstrip('json').strip('`').strip()
                _nsfw_data = _nsfw_json.loads(_nsfw_raw)

                _nsfw_reject          = bool(_nsfw_data.get('nudity', False))
                _nsfw_breastfeeding_flagged = bool(_nsfw_data.get('breastfeeding', False))

                # Breastfeeding overrides nudity reject — do not hard-reject
                if _nsfw_breastfeeding_flagged:
                    _nsfw_reject = False

                app.logger.info(
                    f'[upload] nsfw check (haiku): nudity={_nsfw_reject} '
                    f'breastfeeding={_nsfw_breastfeeding_flagged} '
                    f'description={_nsfw_data.get("description")} '
                    f'uid={current_user.id}'
                )

                if _nsfw_reject:
                    # Preserve a copy under disputed/ and create a dispute record
                    # BEFORE deleting the local thumb — gives the user a "Tell us"
                    # recourse path instead of a dead-end rejection, and gives an
                    # admin something to actually look at if they object.
                    _dispute_id = None
                    try:
                        _disputed_uid = str(uuid.uuid4())
                        _disputed_thumb_url = _r2_upload_disputed_thumb(thumb_path, _disputed_uid)
                        if _disputed_thumb_url:
                            _dispute_row = db.session.execute(
                                db.text("""
                                    INSERT INTO upload_disputes
                                        (user_id, thumb_url, original_filename, nsfw_description, status)
                                    VALUES (:uid, :thumb_url, :fname, :desc, 'pending')
                                    RETURNING id
                                """),
                                {'uid': current_user.id, 'thumb_url': _disputed_thumb_url,
                                 'fname': file.filename, 'desc': _nsfw_data.get('description')}
                            )
                            db.session.commit()
                            _dispute_id = _dispute_row.scalar()
                    except Exception as _dispute_save_err:
                        db.session.rollback()
                        app.logger.warning(f'[upload] dispute save failed (non-fatal): {_dispute_save_err}')

                    if os.path.exists(thumb_path): os.remove(thumb_path)
                    _nsfw_msg = (
                        'Nudity or explicit content was detected in your image. '
                        'Please re-upload a clean image that complies with Shutter League programme rules.'
                    )
                    if request.headers.get('X-Requested-With') == 'XMLHttpRequest' or request.form.get('_xhr') == '1':
                        return jsonify({'error': True, 'message': _nsfw_msg, 'dispute_id': _dispute_id}), 422
                    flash(_nsfw_msg, 'error')
                    return redirect(request.url)

        except Exception as _nsfw_err:
            # Fail open — API error must never block a legitimate upload
            app.logger.warning(f'[upload] nsfw check failed (non-fatal): {_nsfw_err}')

        thumb_url = _r2_upload_thumb(thumb_path, uid)
        if not thumb_url:
            app.logger.error(f'[upload] R2 thumb upload failed for uid={uid}')
            if request.headers.get('X-Requested-With') == 'XMLHttpRequest' or request.form.get('_xhr') == '1':
                return jsonify({'error': True, 'message': 'Storage upload failed. Please try again.'}), 500
            flash('Storage upload failed. Please try again.', 'error')
            return redirect(request.url)

        raw_genre = request.form.get('genre', 'Wildlife')
        genre     = normalise_genre(raw_genre)
        raw_sub_genre = request.form.get('sub_genre', '').strip()
        sub_genre = raw_sub_genre if raw_sub_genre in VALID_SUBGENRES else None

        img = Image(
            user_id           = current_user.id,
            original_filename = filename,
            stored_filename   = os.path.basename(thumb_path),
            thumb_path        = thumb_path,
            thumb_url         = thumb_url,
            file_size_kb      = int(os.path.getsize(thumb_path) / 1024),
            width=w, height=h, format=fmt,
            asset_name        = (request.form.get('asset_name') or '').strip() or
                                  os.path.splitext(filename)[0].replace('_',' ').replace('-',' ').title(),
            genre             = genre,
            subject           = (('[Species: ' + request.form.get('species_hint', '').strip() + '] ') if request.form.get('species_hint', '').strip() else '') + request.form.get('subject', ''),
            location          = request.form.get('location', ''),
            conditions        = request.form.get('conditions', ''),
            photographer_name = request.form.get('photographer_name',
                                                  current_user.full_name or current_user.username),
            camera_track      = request.form.get('camera_track') or getattr(current_user, 'subscription_track', None),
            phash             = phash,
            status            = 'pending',
            legal_declaration = bool(request.form.get('legal_declaration')),
            mission_dimension = (request.form.get('mission_dimension') or request.args.get('mission_dimension')) or None,
            mission_title     = (request.form.get('mission_title') or request.args.get('mission_title')) or None,
            is_public         = (request.form.get('is_public', '0') == '1'),
            exif_status=exif_status, exif_camera=(exif_data.get('camera', '') or '').replace('\x00', ''),
            exif_lens=(exif_data.get('lens', '') or '').replace('\x00', ''),
            exif_date_taken=(exif_data.get('date_taken', '') or '').replace('\x00', ''),
            exif_settings=(exif_settings or '').replace('\x00', ''), exif_warning=(exif_warning or '').replace('\x00', ''),
            # v62 extended EXIF fields
            exif_make             = (exif_data.get('make',  '') or '').replace('\x00', '') or None,
            exif_model            = (exif_data.get('model', '') or '').replace('\x00', '') or None,
            exif_focal_length_35mm= exif_data.get('focal_length_35mm') or None,
            exif_focal_length_raw = exif_data.get('focal_length_raw')  or None,
            exif_aperture_raw     = exif_data.get('aperture_raw')      or None,
            exif_iso_raw          = exif_data.get('iso_raw')           or None,
            exif_shutter_raw      = exif_data.get('shutter_raw')       or None,
            exif_software         = (exif_data.get('software', '') or '').replace('\x00', '') or None,
            exif_has_gps          = exif_data.get('has_gps')           or False,
            exif_gps_lat          = exif_data.get('gps_lat'),
            exif_gps_lon          = exif_data.get('gps_lon'),
            exif_device_tier      = _device_tier or None,
        )
        db.session.add(img)
        img.sub_genre = sub_genre
        # Increment lifetime upload counter — never decremented on delete.
        # Used to enforce free tier limit even if user deletes images.
        try:
            db.session.execute(
                db.text("UPDATE users SET total_uploads_ever = COALESCE(total_uploads_ever, 0) + 1 WHERE id = :uid"),
                {'uid': current_user.id}
            )
        except Exception:
            pass

        # ── Item A REMOVED (v76) — was: update user.city from upload-time
        # location text (v74). Removed because it conflated "where was this
        # photo taken" (img.location, a free-text per-upload form field) with
        # "where does this user live" (current_user.city, the profile home
        # base). It only updated `city` (never `state`/`country`), and a
        # naive split(',')[0] often produced landmark/park names (e.g.
        # "Sanjay Van" from "Sanjay Van, New Delhi") rather than real cities —
        # silently corrupting profile location data (confirmed:
        # r_mahesh_iyer ended up with city=Thrissur / state=Karnataka, a
        # mismatched pair, after uploading a Thrissur Pooram photo from a
        # Bengaluru/Karnataka home base). The upload form also prefills the
        # location field from the user's last upload, making the corruption
        # self-reinforcing across sessions.
        #
        # Item B below already covers "this upload was taken somewhere
        # different from home" correctly and non-destructively: it derives
        # _travel_city from EXIF GPS for THIS upload's seasonal context only,
        # and only proposes updating current_user.city via
        # pending_location_update after 14 consecutive days of GPS
        # disagreement (user must confirm). current_user.city/state/country
        # now only change via explicit profile edit (Active Location widget)
        # or that confirmed-relocation flow.

        # ── Item B: GPS-based travel context + relocation detection (v74) ────
        # If the photo's EXIF GPS resolves to a different city than the user's
        # declared city, use the GPS city for THIS upload's seasonal context
        # ("you're in Goa this weekend — here's what's worth shooting"),
        # without touching user.city. Separately, track how long the GPS city
        # has differed from user.city — if it's been 14+ consecutive days,
        # flag pending_location_update so a banner can prompt the user to
        # confirm a real move (avoids false positives from short trips).
        _travel_city = None
        _gps_lat, _gps_lon = exif_data.get('gps_lat'), exif_data.get('gps_lon')
        if _gps_lat is not None and _gps_lon is not None:
            _gps_city = _reverse_geocode_city(_gps_lat, _gps_lon)
            if _gps_city:
                if _gps_city != (current_user.city or ''):
                    _travel_city = _gps_city  # this upload's seasonal context uses this

                    if current_user.last_gps_city == _gps_city:
                        # Same differing city as last time — check how long it's persisted.
                        if (current_user.last_gps_city_since
                                and (datetime.utcnow() - current_user.last_gps_city_since) >= timedelta(days=14)):
                            current_user.pending_location_update = _gps_city
                    else:
                        # New differing city — restart the clock.
                        current_user.last_gps_city = _gps_city
                        current_user.last_gps_city_since = datetime.utcnow()
                else:
                    # GPS city matches declared city — clear any tracking/flag.
                    current_user.last_gps_city = None
                    current_user.last_gps_city_since = None
                    current_user.pending_location_update = None

        db.session.commit()

        # ── Curriculum advance — mark principle taught after mission upload ──────
        # Safe: _advance_curriculum swallows all errors internally.
        # curriculum_principle_id may arrive via:
        #   (a) hidden form field (populated by JS from URL param) -> request.form
        #   (b) URL query param on XHR POST URL -> request.args (Flask splits these)
        # Check both so either path works.
        _curriculum_pid = (request.form.get('curriculum_principle_id')
                           or request.args.get('curriculum_principle_id') or None)
        _curriculum_dim = (request.form.get('mission_dimension')
                           or request.args.get('mission_dimension') or None)
        if _curriculum_pid and _curriculum_dim:
            app.logger.info(
                f'[curriculum_advance] firing: user={current_user.id} '
                f'principle={_curriculum_pid!r} dim={_curriculum_dim!r}'
            )
            _advance_curriculum(current_user.id, _curriculum_pid, _curriculum_dim)
            # Persist which exact curriculum principle this mission came from,
            # onto the image itself — used later if the mission fails, to build
            # a failure message grounded in the actual lesson text rather than
            # only a generic dimension label.
            try:
                img.mission_principle_id = _curriculum_pid
                db.session.commit()
            except Exception as _mpid_err:
                db.session.rollback()
                app.logger.warning(f'[mission_principle_id] write failed: {_mpid_err}')
        else:
            app.logger.info(
                f'[curriculum_advance] skipped: pid={_curriculum_pid!r} '
                f'dim={_curriculum_dim!r} -- not a mission upload'
            )

        # ── Breastfeeding flag — hold pending DDI sub-genre resolution ───────────
        # Admin email is NOT sent here. Sub-genre detection happens async in the scoring
        # thread. If DDI returns lifestyle_intimate → auto-approve (whitelist).
        # Otherwise → admin email fires from scoring thread after DDI scores.
        # See breastfeeding whitelist block in _score_in_background below.
        if _nsfw_breastfeeding_flagged:
            try:
                _user_wanted_private = not img.is_public  # capture before we override
                img.needs_review   = True
                img.is_public      = False
                img.flagged_reason = ('Breastfeeding content detected — held pending sub-genre check.'
                                      + (' user_private' if _user_wanted_private else ''))
                img.flagged_at     = datetime.utcnow()
                img.scoring_flash  = (
                    'Your image is under review — breastfeeding photography is permitted '
                    'and usually cleared automatically. '
                    'If not resolved within 24 hours, contact support@shutterleague.com.'
                )
                db.session.commit()
                app.logger.info(f'[upload] breastfeeding flag: image={img.id} held pending scoring thread sub-genre check')
            except Exception as _bf_err:
                app.logger.warning(f'[upload] breastfeeding flag failed: {_bf_err}')

        # -- League integrity check (three-strike system) ------------------
        # Mobile League users uploading camera EXIF images get graduated penalties.
        # Only flags images uploaded AFTER subscription date (protects legacy images).
        _CAMERA_BRANDS_EXIF = ('canon', 'nikon', 'sony', 'fuji', 'fujifilm', 'olympus',
                               'panasonic', 'leica', 'hasselblad', 'pentax', 'sigma',
                               'ricoh', 'om system', 'om-system')
        _user_league    = getattr(current_user, 'subscription_track', None) or ''
        _exif_cam_lower = (exif_data.get('camera', '') or '').lower()
        _subscribed_at  = getattr(current_user, 'subscribed_at', None)
        _after_sub      = (_subscribed_at is None or datetime.utcnow() >= _subscribed_at)

        if (_user_league == 'mobile'
                and any(b in _exif_cam_lower for b in _CAMERA_BRANDS_EXIF)
                and _after_sub):

            strike = current_user.record_mismatch(img.id, exif_data.get('camera', ''), db.session)

            img.needs_review = True
            img.exif_warning = (img.exif_warning or '') + (
                f' [LEAGUE MISMATCH: Camera EXIF "{exif_data.get("camera","")}" '
                f'detected on Mobile League subscription  -  strike {strike}/3]'
            )
            db.session.commit()
            app.logger.warning(
                f'[league_mismatch] user={current_user.id} image={img.id} '
                f'exif={_exif_cam_lower} strike={strike}'
            )

            if strike == 1:
                flash(
                    ' League check: this image appears to have been taken on a dedicated camera, '
                    'but you are in the Mobile League. The image has been held for review. '
                    'If you shoot on a camera, please switch to the Camera League. '
                    'Contact '+CONTACT_EMAIL+' with questions.',
                    'warning'
                )
            elif strike == 2:
                flash(
                    ' Second league mismatch. This image has been held for review and '
                    'your programme entries for this month have been removed pending admin review. '
                    'One more mismatch will suspend your programme access.',
                    'warning'
                )
                _month = datetime.utcnow().strftime('%Y-%m')
                ContestEntry.query.filter_by(user_id=current_user.id, contest_month=_month).delete()
                db.session.commit()
            elif strike >= 3:
                flash(
                    ' Three league mismatches detected. Your programme access has been suspended '
                    'and this month\'s programme entries have been removed. '
                    'Contact '+CONTACT_EMAIL+' to resolve.',
                    'error'
                )
                _month = datetime.utcnow().strftime('%Y-%m')
                ContestEntry.query.filter_by(user_id=current_user.id, contest_month=_month).delete()
                db.session.commit()

        # -- Background scoring thread -------------------------------------
        # Fire-and-forget: score in background so user gets a response in
        # 5-10s instead of waiting 45-90s for the Anthropic API + card build.
        # The browser polls /score-status/<image_id> every 2s until done.
        api_key = os.getenv('ANTHROPIC_API_KEY', '')
        if api_key:

            # ── Score anchor: cache hit → skip engine entirely ─────────────
            if _anchored_score:
                img.dod_score        = _anchored_score.get('dod_score') or 0.0
                img.disruption_score = _anchored_score.get('disruption_score') or 0.0
                img.dm_score         = _anchored_score.get('dm_score') or 0.0
                img.wonder_score     = _anchored_score.get('wonder_score') or 0.0
                img.aq_score         = _anchored_score.get('aq_score') or 0.0
                img.score            = _anchored_score.get('score') or 0.0
                img.tier             = _anchored_score.get('tier') or get_tier(img.score)
                img.archetype        = _anchored_score.get('archetype') or ''
                img.soul_bonus       = bool(_anchored_score.get('soul_bonus', False))
                img.status           = 'scored'
                img.scored_at        = datetime.utcnow()
                img.scoring_flash    = f'Score anchored: {img.score} ({img.tier})'
                # Restore audit_json: prefer cached copy (survives image deletion),
                # fall back to original image if cache predates audit_json column.
                _cached_audit = _anchored_score.get('audit_json')
                if _cached_audit:
                    img._audit_json = _cached_audit
                    app.logger.info(f'[upload] audit_json restored from phash cache')
                else:
                    _orig_id = _anchored_score.get('original_image_id')
                    if _orig_id:
                        try:
                            _orig = Image.query.get(_orig_id)
                            if _orig and _orig._audit_json:
                                img._audit_json = _orig._audit_json
                                app.logger.info(f'[upload] audit_json restored from original image {_orig_id}')
                        except Exception as _ae:
                            app.logger.warning(f'[upload] audit copy failed: {_ae}')
                db.session.commit()
                app.logger.info(
                    f'[upload] score anchored from cache: image={img.id} '
                    f'score={img.score} user={current_user.id}'
                )

                # ── Breastfeeding + cache hit: still need sub-genre check ──
                # The engine wasn't called so _effective_subgenre is unknown.
                # Spin a lightweight thread to call auto_score for sub-genre
                # only — re-uses the scoring thread's whitelist logic.
                # This is the only case where cache hit still needs a thread.
                if _nsfw_breastfeeding_flagged:
                    img.status = 'processing'
                    db.session.commit()
                    app.logger.info(
                        f'[upload] breastfeeding+cache: spinning sub-genre thread image={img.id}'
                    )
            else:
                img.status = 'processing'
                db.session.commit()

            def _score_in_background(image_id, _uid, _travel_city=None):
                import traceback
                from engine.auto_score import auto_score, build_audit_data, build_exif_context
                from engine.compositor import build_card1
                with app.app_context():
                    audit = None  # initialise — prevents UnboundLocalError on all paths
                    try:
                        _img = Image.query.get(image_id)
                        if not _img:
                            return

                        # ── LAYER 2: Hive AI detection ─────────────────────
                        # Runs before Claude Vision. If Hive detects AI with
                        # high confidence, we reject without calling Claude.
                        # Fails safe — if Hive is down or key missing, scoring
                        # continues normally. Never crashes the upload.
                        _hive_key = os.getenv('HIVE_API_KEY', '')
                        if _hive_key and _img.thumb_url:
                            try:
                                import urllib.request as _ureq
                                import json as _hjson
                                _exclude = {
                                    'ai_generated', 'not_ai_generated', 'deepfake',
                                    'none', 'inconclusive', 'inconclusive_video',
                                    'not_ai_generated_audio', 'ai_generated_audio',
                                }
                                # V3 API — public R2 URL directly in media_url
                                # Secret Key only — NOT AccessKeyID:SecretKey
                                _hive_payload = _hjson.dumps({
                                    'media_metadata': True,
                                    'input': [{'media_url': _img.thumb_url}]
                                }).encode('utf-8')
                                _hive_req = _ureq.Request(
                                    'https://api.thehive.ai/api/v3/hive/ai-generated-and-deepfake-content-detection',
                                    data=_hive_payload,
                                    headers={
                                        'Authorization': f'Bearer {_hive_key}',
                                        'Content-Type': 'application/json',
                                    },
                                    method='POST'
                                )
                                with _ureq.urlopen(_hive_req, timeout=15) as _hr:
                                    _hive_resp = _hjson.loads(_hr.read().decode('utf-8'))
                                # Parse V3 response — output[0].classes
                                _classes = (
                                    _hive_resp.get('output', [{}])[0]
                                    .get('classes', [])
                                )
                                _score_map = {c['class']: c['value'] for c in _classes}
                                _hive_ai_score = float(_score_map.get('ai_generated', 0.0))
                                # Find generator name — highest value excluding meta-classes
                                _gen_candidates = [
                                    c for c in _classes
                                    if c['class'] not in _exclude
                                    and c['value'] > 0.001
                                ]
                                _hive_generator = (
                                    max(_gen_candidates, key=lambda c: c['value'])['class']
                                    if _gen_candidates else 'unknown'
                                )
                                app.logger.info(
                                    f'[hive] image={image_id} '
                                    f'ai_score={_hive_ai_score:.3f} '
                                    f'generator={_hive_generator}'
                                )
                                # Store Hive result on image regardless of threshold
                                _img.ai_suspicion = _hive_ai_score
                                _img.ai_suspicion_reason = (
                                    f'Hive: {_hive_generator} '
                                    f'{_hive_ai_score:.0%}'
                                )
                                db.session.commit()

                                if _hive_ai_score >= 0.90:
                                    # ── HARD REJECT ───────────────────────
                                    # High confidence AI — reject immediately,
                                    # never call Claude Vision.
                                    _img.score            = 0.0
                                    _img.tier             = 'Rookie'
                                    _img.dod_score        = 0.0
                                    _img.disruption_score = 0.0
                                    _img.dm_score         = 0.0
                                    _img.wonder_score     = 0.0
                                    _img.aq_score         = 0.0
                                    _img.archetype        = ''
                                    _img.soul_bonus       = False
                                    _img.status           = 'scored'
                                    _img.scored_at        = datetime.utcnow()
                                    _img.is_flagged       = True
                                    _img.needs_review     = True
                                    _img.is_public        = False
                                    _img.flagged_reason   = (
                                        f'AI generation detected by Hive '
                                        f'({_hive_ai_score:.0%} confidence). '
                                        f'Generator: {_hive_generator}.'
                                    )
                                    _img.flagged_at       = datetime.utcnow()
                                    db.session.commit()
                                    # Notify user and admin
                                    try:
                                        _u = User.query.get(_img.user_id)
                                        _uname = (
                                            (_u.full_name or _u.username)
                                            if _u else 'Photographer'
                                        )
                                        _gen_display = _hive_generator.replace('_', ' ').title()
                                        send_email(
                                            to_addresses=[_u.email] if _u else [],
                                            subject='[Shutter League] Image Rejected &#8212; AI Generation Detected',
                                            html_body=(
                                                '<div style="font-family:Georgia,serif;'
                                                'max-width:560px;margin:0 auto;padding:32px;'
                                                'background:#fffef9;color:#111111;">'
                                                '<p style="font-family:Courier New,monospace;'
                                                'font-size:15px;letter-spacing:2px;'
                                                'text-transform:uppercase;color:#F5C518;'
                                                'margin-bottom:24px;">Shutter League</p>'
                                                '<h2 style="font-size:22px;font-weight:700;'
                                                'color:#111111;margin-bottom:16px;">'
                                                'Image Rejected</h2>'
                                                '<p style="font-size:16px;line-height:1.7;'
                                                'color:#111111;">Hi ' + _uname + ',</p>'
                                                '<p style="font-size:16px;line-height:1.7;'
                                                'color:#111111;">Your image <strong>'
                                                + (_img.asset_name or 'Untitled') +
                                                '</strong> has been rejected. Our system '
                                                'detected it was generated by '
                                                + _gen_display +
                                                ' (' + f'{_hive_ai_score:.0%}' + ' confidence).</p>'
                                                '<p style="font-size:16px;line-height:1.7;'
                                                'color:#111111;">Shutter League accepts only '
                                                'original photographs taken by the submitting '
                                                'photographer.</p>'
                                                '<p style="font-size:16px;line-height:1.7;color:#111111;">'
                                                'High-production constructed shoots — allegorical tableaux, '
                                                'studio work, heavily lit portraits — can occasionally '
                                                'trigger false positives. If this is an original photograph, '
                                                'we want to clear it quickly.</p>'
                                                '<p style="font-size:16px;line-height:1.7;color:#111111;">'
                                                '<strong>To appeal, email '
                                                '<a href="mailto:' + CONTACT_EMAIL + '">'
                                                + CONTACT_EMAIL + '</a> with:</strong></p>'
                                                '<ul style="font-size:16px;line-height:2;color:#111111;">'
                                                '<li>Your original RAW or unedited file</li>'
                                                '<li>Any behind-the-scenes photos or production notes</li>'
                                                '<li>Camera and lens used</li>'
                                                '</ul>'
                                                '<p style="font-size:15px;color:#555555;margin-top:24px;">'
                                                'We aim to resolve appeals within 48 hours. '
                                                'Your image will go public immediately if cleared.</p>'
                                                '<p style="font-size:15px;color:#555555;'
                                                'margin-top:8px;">&#8212; Shutter League</p>'
                                                '</div>'
                                            ),
                                            text_body=(
                                                'Hi ' + _uname + ',\n\n'
                                                'Your image "' +
                                                (_img.asset_name or 'Untitled') +
                                                '" has been rejected.\n\n'
                                                'Our system detected it was generated by ' +
                                                _gen_display + ' (' +
                                                f'{_hive_ai_score:.0%}' + ' confidence).\n\n'
                                                'High-production constructed shoots can sometimes trigger false positives.\n'
                                                'If this is an original photograph, email ' +
                                                CONTACT_EMAIL +
                                                ' with:\n'
                                                '  - Your original RAW or unedited file\n'
                                                '  - Any behind-the-scenes photos or production notes\n'
                                                '  - Camera and lens used\n\n'
                                                'We aim to resolve appeals within 48 hours.\n\n'
                                                '-- Shutter League'
                                            )
                                        )
                                        send_email(
                                            to_addresses=[ADMIN_EMAIL],
                                            subject=(
                                                '[Admin] Hive Hard Reject — ' +
                                                (_img.asset_name or 'Untitled') +
                                                ' (' + _gen_display + ' ' +
                                                f'{_hive_ai_score:.0%}' + ')'
                                            ),
                                            html_body=(
                                                '<p>Hive hard rejected an image — '
                                                'Claude Vision was NOT called.</p>'
                                                '<ul><li>Image: ' +
                                                (_img.asset_name or 'Untitled') +
                                                '</li><li>Generator: ' + _gen_display +
                                                '</li><li>Confidence: ' +
                                                f'{_hive_ai_score:.0%}' +
                                                '</li><li>User: ' +
                                                (_u.email if _u else 'unknown') +
                                                '</li></ul>'
                                            ),
                                            text_body=(
                                                'Hive hard reject.\nImage: ' +
                                                (_img.asset_name or 'Untitled') +
                                                '\nGenerator: ' + _gen_display +
                                                '\nConfidence: ' +
                                                f'{_hive_ai_score:.0%}' +
                                                '\nUser: ' +
                                                (_u.email if _u else 'unknown')
                                            )
                                        )
                                    except Exception as _he:
                                        app.logger.error(
                                            f'[hive reject email error] {_he}'
                                        )
                                    return  # Stop — do not call Claude Vision

                                elif _hive_ai_score >= 0.70:
                                    # ── AMBER FLAG ────────────────────────
                                    # Medium confidence — score with Claude
                                    # but flag for admin review.
                                    _img.needs_review = True
                                    db.session.commit()
                                    app.logger.info(
                                        f'[hive] amber flag image={image_id} '
                                        f'score={_hive_ai_score:.3f}'
                                    )
                                    # Continue to Claude Vision below

                            except Exception as _hive_err:
                                _err_body = ''
                                try:
                                    _err_body = _hive_err.read().decode('utf-8')[:200]
                                except Exception:
                                    pass
                                app.logger.warning(
                                    f'[hive] check failed for image={image_id}: '
                                    f'{_hive_err} body={_err_body} — continuing to Claude Vision'
                                )
                        # ── END Hive check ─────────────────────────────────

                        # ── Sprint 2 — seasonal + portfolio context ───────────────────────────
                        try:
                            from engine.seasonal_calendar import build_seasonal_context, get_primary_genre
                            _u = User.query.get(_img.user_id)
                            _sc_primary_genre = get_primary_genre(_u) if _u else (_img.genre or '')
                            # Item B: if this upload's GPS resolved to a different city than the
                            # user's declared city, use the GPS (travel) city for THIS image's
                            # seasonal context only — does not affect user.city.
                            _sc_user_city     = _travel_city or (getattr(_u, 'city', '') or '' if _u else '')
                            _sc_seasonal_ctx, _sc_calendar_ids = build_seasonal_context(
                                db_session    = db.session,
                                user_city     = _sc_user_city,
                                primary_genre = _sc_primary_genre or _img.genre or '',
                                current_month = datetime.utcnow().month,
                                user_id       = _img.user_id,
                            )

                            # ── On-demand discovery: if no calendar rows exist for this
                            # city/genre, run discovery synchronously NOW (we're already
                            # in a background thread, so this doesn't block the HTTP
                            # response). This ensures the FIRST scorecard for any new
                            # city always has a local advisory — not 24hrs later.
                            if not _sc_seasonal_ctx and _sc_user_city and (_sc_primary_genre or _img.genre):
                                _od_genre = _sc_primary_genre or _img.genre or ''
                                try:
                                    from engine.seasonal_discovery import discover_one, enqueue_priority_combo
                                    # discover_one() is targeted — web search + LLM extract
                                    # for exactly this (city, genre). Much cheaper than
                                    # run_seasonal_discovery() which scans all users first.
                                    _od_n = discover_one(db.session, _sc_user_city, _od_genre, current_month=datetime.utcnow().month)
                                    app.logger.info(f'[auto_score] on-demand discovery for ({_sc_user_city}, {_od_genre}): {_od_n} row(s) inserted')
                                    if _od_n > 0:
                                        # Retry build_seasonal_context now that rows exist
                                        _sc_seasonal_ctx, _sc_calendar_ids = build_seasonal_context(
                                            db_session    = db.session,
                                            user_city     = _sc_user_city,
                                            primary_genre = _od_genre,
                                            current_month = datetime.utcnow().month,
                                            user_id       = _img.user_id,
                                        )
                                        if _sc_seasonal_ctx:
                                            app.logger.info(f'[auto_score] on-demand discovery succeeded — advisory ready for ({_sc_user_city}, {_od_genre})')
                                        else:
                                            app.logger.warning(
                                                f'[auto_score] on-demand discovery inserted {_od_n} row(s) for '
                                                f'({_sc_user_city}, {_od_genre}) but month filter returned no context '
                                                f'(month={datetime.utcnow().month}) — scorecard will have no advisory'
                                            )
                                    else:
                                        app.logger.warning(f'[auto_score] on-demand discovery found nothing for ({_sc_user_city}, {_od_genre})')
                                        # Mark as done in queue so we don't retry endlessly
                                        enqueue_priority_combo(db.session, _sc_user_city, _od_genre)
                                except Exception as _od_err:
                                    app.logger.warning(f'[auto_score] on-demand discovery failed for ({_sc_user_city}, {_od_genre}): {_od_err}')
                                    # Non-fatal — scoring proceeds without advisory
                        except Exception as _sc_err:
                            app.logger.warning(f'[auto_score] seasonal context error: {_sc_err}')
                            _sc_seasonal_ctx  = ''
                            _sc_calendar_ids  = []
                            _sc_primary_genre = _img.genre or ''
                            _sc_user_city     = ''

                        # Portfolio summary — active from image 2 onwards (history-aware evaluation)
                        _sc_portfolio = None
                        _sc_image_number = 1
                        try:
                            _sc_count = db.session.query(Image).filter(
                                Image.user_id == _img.user_id,
                                Image.status  == 'scored',
                            ).count()
                            _sc_image_number = _sc_count + 1
                            if _sc_count >= 2:
                                _sc_recent = db.session.query(
                                    Image.aq_score, Image.dm_score, Image.dod_score
                                ).filter(
                                    Image.user_id == _img.user_id,
                                    Image.status  == 'scored',
                                    Image.genre   == _img.genre,
                                ).order_by(Image.scored_at.desc()).limit(8).all()
                                if _sc_recent and len(_sc_recent) >= 1:
                                    _sc_recent = list(reversed(_sc_recent))
                                    _sc_portfolio = {
                                        'feeling':    [r.aq_score  for r in _sc_recent if r.aq_score  is not None],
                                        'timing':     [r.dm_score  for r in _sc_recent if r.dm_score  is not None],
                                        'difficulty': [r.dod_score for r in _sc_recent if r.dod_score is not None],
                                    }
                                    # ── Variety history — last 5 audit JSONs ──────────────
                                    # Extract what masters, openings, locations, philosophy
                                    # lines were used recently so the engine avoids repeating.
                                    try:
                                        _recent_audits = db.session.execute(
                                            db.text("SELECT audit_json FROM images WHERE user_id=:uid AND status='scored' ORDER BY scored_at DESC LIMIT 5"),
                                            {'uid': _img.user_id}
                                        ).fetchall()
                                        _r_masters, _r_openings, _r_locations, _r_philosophy = [], [], [], []
                                        import re as _re_var
                                        _open_rx = _re_var.compile(
                                            r'^(Brilliantly|Beautifully|Exceptionally|Wonderfully|Remarkably|'
                                            r'Impressively|Expertly|Perfectly|Powerfully|Elegantly|Sharply|'
                                            r'Boldly|Quietly|Instinctively|Patiently|Decisively|Confidently|'
                                            r'Sensitively|Fearlessly|Generously)', _re_var.IGNORECASE
                                        )
                                        for (_aj,) in _recent_audits:
                                            if not _aj:
                                                continue
                                            try:
                                                _ad = json.loads(_aj)
                                            except Exception:
                                                continue
                                            # Extract master name from transferable_advice bold line
                                            _ta = _ad.get('transferable_advice') or ''
                                            for _bold in _re_var.findall(r'\*\*([^*]+)\*\*', _ta):
                                                _first_word = _bold.split()[0] if _bold.split() else ''
                                                if _first_word and len(_first_word) > 2:
                                                    _r_masters.append(_bold[:60])
                                                    break
                                            # Extract opening adjective from hard_truth
                                            _ht = _ad.get('hard_truth') or ''
                                            _om = _open_rx.match(_ht.strip())
                                            if _om:
                                                _r_openings.append(_om.group(1))
                                            # Extract location from mentor_location_1
                                            _ml = _ad.get('mentor_location_1') or ''
                                            if _ml:
                                                _loc_first = _ml.split('.')[0][:50].strip()
                                                if _loc_first:
                                                    _r_locations.append(_loc_first)
                                        _sc_portfolio['recent_masters']    = _r_masters[:5]
                                        _sc_portfolio['recent_openings']   = _r_openings[:5]
                                        _sc_portfolio['recent_locations']  = _r_locations[:3]
                                        _sc_portfolio['recent_philosophy'] = []  # tracked by index in future
                                    except Exception as _var_err:
                                        app.logger.debug(f'[auto_score] variety history extraction failed: {_var_err}')
                        except Exception as _sp_err:
                            app.logger.warning(f'[auto_score] portfolio context error: {_sp_err}')
                            _sc_portfolio = None
                            _sc_image_number = 1

                        # ── CSI genre weight boosts (post-calibration) ────────────────
                        # Read per-genre saturation boosts set by admin CSI calibration run.
                        # Injected as context into the scoring prompt — no direct score math.
                        _csi_boost_ctx = ''
                        try:
                            _csi_w = db.session.execute(db.text(
                                "SELECT disruption_boost, wonder_boost FROM csi_genre_weights "
                                "WHERE genre = :genre"
                            ), {'genre': _img.genre}).fetchone()
                            if _csi_w and (_csi_w[0] > 0 or _csi_w[1] > 0):
                                _csi_boost_ctx = (
                                    f"\nCSI CALIBRATION ACTIVE — {_img.genre} pool saturation detected. "
                                    f"Disruption dimension: apply +{_csi_w[0]:.1f} weighting. "
                                    f"Wonder dimension: apply +{_csi_w[1]:.1f} weighting. "
                                    f"This reflects the volume of similar images already in the scored pool — "
                                    f"reward genuine departure from established compositions."
                                )
                        except Exception:
                            _csi_boost_ctx = ''

                        result = auto_score(
                            image_path=_img.thumb_path, genre=_img.genre,
                            sub_genre=_img.sub_genre,
                            title=_img.asset_name, photographer=_img.photographer_name,
                            subject=_img.subject, location=_img.location,
                            exif_context=build_exif_context(
                                {
                                    'make': _img.exif_make, 'model': _img.exif_model,
                                    'focal_length_35mm': _img.exif_focal_length_35mm,
                                    'focal_length': _img.exif_settings,
                                    'aperture': None, 'shutter': None, 'iso': None,
                                    'lens': _img.exif_lens, 'software': _img.exif_software,
                                    'has_gps': _img.exif_has_gps,
                                },
                                camera_track=_img.camera_track,
                            ) if _img.exif_make or _img.exif_model or _img.exif_focal_length_35mm else '',
                            seasonal_context  = _sc_seasonal_ctx + _csi_boost_ctx,
                            portfolio_summary = _sc_portfolio,
                            user_city         = _sc_user_city,
                            primary_genre     = _sc_primary_genre,
                            image_number      = _sc_image_number,
                            previous_score    = _near_match_previous['score'] if _near_match_previous else None,
                            previous_audit    = _near_match_previous['audit'] if _near_match_previous else None,
                        )

                        ai_suspicion = float(result.get('ai_suspicion', 0.0))
                        _img.ai_suspicion        = ai_suspicion
                        _img.ai_suspicion_reason = result.get('ai_suspicion_reason') or None
                        # NOTE: do NOT overwrite needs_review here — breastfeeding images
                        # arrive with needs_review=True set at upload. The whitelist block
                        # below resolves it. Overwriting here would break _bf_held detection.
                        if not ('breastfeeding' in (_img.flagged_reason or '').lower()):
                            _img.needs_review = bool(result.get('needs_review', False))

                        # ── Breastfeeding whitelist — resolve hold set at upload ────────────────
                        # Upload set needs_review=True, is_public=False when Hive detected
                        # breastfeeding (>=0.70). Now DDI sub-genre is known. Two paths:
                        #   lifestyle_intimate  → whitelist: clear hold, go public, no email
                        #   any other sub-genre → admin review: send email, stay held
                        _bf_held = (
                            'breastfeeding' in (_img.flagged_reason or '').lower()
                            and _img.needs_review
                            and not _img.is_flagged  # not already hard-rejected for AI etc.
                        )
                        if _bf_held:
                            # _effective_subgenre: read from image record (set by DDI during
                            # scoring) rather than from result dict — auto_score() doesn't
                            # return this field. Re-query to get the freshest value.
                            db.session.refresh(_img)
                            _effective_subgenre = (_img.sub_genre or result.get('_effective_subgenre') or '').strip().lower()
                            if _effective_subgenre == 'lifestyle_intimate':
                                # Whitelisted — fine art documentary, auto-approve
                                # Respect user's original visibility choice: flagged_reason
                                # stores 'user_private' marker if user chose hidden at upload.
                                _img.needs_review   = False
                                _user_chose_private = 'user_private' in (_img.flagged_reason or '')
                                if not _user_chose_private:
                                    _img.is_public = True
                                _img.flagged_reason = None
                                _img.scoring_flash  = None  # clear hold message
                                _img.status        = 'scored'
                                _img.scored_at     = _img.scored_at or datetime.utcnow()
                                # Save audit if not already present
                                if not _img.get_audit():
                                    try:
                                        audit = build_audit_data(result, _img)
                                        _img.set_audit(audit)
                                    except Exception as _bf_audit_err:
                                        app.logger.warning(f'[scoring] breastfeeding audit save failed: {_bf_audit_err}')
                                db.session.commit()
                                app.logger.info(
                                    f'[scoring] breastfeeding whitelist cleared: '
                                    f'image={image_id} subgenre={_effective_subgenre}'
                                )
                                return  # fully handled — skip ai_suspicion + score blocks
                            else:
                                # Non-intimate sub-genre — send admin review email now
                                try:
                                    _bf_admin_emails = _admin_notify_emails()
                                    if not _bf_admin_emails:
                                        _bf_admin_emails = [ADMIN_NOTIFY_EMAIL]
                                    _bf_site = os.getenv('SITE_URL', 'https://shutterleague.com')
                                    _bf_u = User.query.get(_img.user_id)
                                    _img.flagged_reason = (
                                        f'Breastfeeding content detected — held for admin approval. '
                                        f'Sub-genre: {_effective_subgenre or "undetected"}.'
                                    )
                                    db.session.commit()
                                    send_email(
                                        _bf_admin_emails,
                                        f'[Content Review] Breastfeeding Image — {_img.asset_name or "Untitled"} (ID: {_img.id})',
                                        (
                                            '<div style="font-family:Courier New,monospace;max-width:560px;margin:0 auto;padding:32px;">'
                                            '<p style="color:#C8A84B;font-weight:700;font-size:15px;">CONTENT REVIEW REQUIRED — BREASTFEEDING IMAGE</p>'
                                            f'<p>Image: <strong>{_img.asset_name or "Untitled"}</strong> (ID: {_img.id})<br>'
                                            f'Photographer: {(_bf_u.username if _bf_u else "unknown")} ({(_bf_u.email if _bf_u else "unknown")})<br>'
                                            f'Genre: {_img.genre or "—"}<br>'
                                            f'Sub-genre: <strong>{_effective_subgenre or "undetected"}</strong></p>'
                                            '<p>This image has been held from public view pending your review. '
                                            'Breastfeeding photography requires admin approval when sub-genre is not '
                                            '<em>lifestyle_intimate</em>.</p>'
                                            f'<a href="{_bf_site}/admin/image/{_img.id}" '
                                            'style="display:inline-block;background:#C8A84B;color:#1a1a18;'
                                            'font-family:Courier New,monospace;font-size:13px;font-weight:700;'
                                            'letter-spacing:1px;text-transform:uppercase;padding:12px 24px;'
                                            'text-decoration:none;border-radius:4px;margin:16px 0;">'
                                            'Review &amp; Approve &#8594;</a>'
                                            '</div>'
                                        )
                                    )
                                    app.logger.info(
                                        f'[scoring] breastfeeding admin email sent: '
                                        f'image={image_id} subgenre={_effective_subgenre}'
                                    )
                                except Exception as _bf_email_err:
                                    app.logger.warning(f'[scoring] breastfeeding admin email failed: {_bf_email_err}')
                        # ── END breastfeeding whitelist ─────────────────────────────────────────

                        if ai_suspicion >= 0.7:
                            # TIER 3 — auto-flagged AI-generated
                            _img.score            = 0.0
                            _img.tier             = 'Rookie'
                            _img.dod_score        = 0.0
                            _img.disruption_score = 0.0
                            _img.dm_score         = 0.0
                            _img.wonder_score     = 0.0
                            _img.aq_score         = 0.0
                            _img.archetype        = ''
                            _img.soul_bonus       = False
                            _img.status           = 'scored'
                            _img.scored_at        = datetime.utcnow()
                            _img.is_flagged       = True
                            _img.needs_review     = True
                            _img.is_public        = False
                            _img.flagged_reason   = f'AI generation detected (suspicion: {ai_suspicion:.2f}). {_img.ai_suspicion_reason or ""}'.strip()
                            _img.flagged_at       = datetime.utcnow()
                            db.session.commit()
                            try:
                                _u = User.query.get(_img.user_id)
                                _uname = (_u.full_name or _u.username) if _u else 'Photographer'
                                _iurl = f'https://shutterleague.com/image/{_img.id}'
                                send_email(
                                    to_addresses=[_u.email] if _u else [],
                                    subject='[Shutter League] Image Flagged — AI Generation Detected',
                                    html_body=(
                                        '<div style="font-family:Georgia,serif;max-width:560px;margin:0 auto;padding:32px;background:#fffef9;color:#111111;">'
                                        '<p style="font-family:Courier New,monospace;font-size:15px;letter-spacing:2px;text-transform:uppercase;color:#F5C518;margin-bottom:24px;">Shutter League</p>'
                                        '<h2 style="font-size:22px;font-weight:700;color:#111111;margin-bottom:16px;">Image Under Review</h2>'
                                        '<p style="font-size:16px;line-height:1.7;color:#111111;">Hi ' + _uname + ',</p>'
                                        '<p style="font-size:16px;line-height:1.7;color:#111111;">Your image <strong>' + (_img.asset_name or 'Untitled') + '</strong> has been flagged for admin review before going public. Our automated system detected characteristics that may indicate AI generation.</p>'
                                        '<p style="font-size:16px;line-height:1.7;color:#111111;">We know that high-production constructed shoots — studio work, allegorical tableaux, heavily lit portraits — can sometimes trigger false positives. If this is an original photograph, we want to clear it quickly.</p>'
                                        '<p style="font-size:16px;line-height:1.7;color:#111111;"><strong>To appeal, email <a href="mailto:' + CONTACT_EMAIL + '">' + CONTACT_EMAIL + '</a> with:</strong></p>'
                                        '<ul style="font-size:16px;line-height:2;color:#111111;">'
                                        '<li>Your original RAW or unedited file</li>'
                                        '<li>Any behind-the-scenes photos, casting, or production notes (if available)</li>'
                                        '<li>Camera and lens used</li>'
                                        '</ul>'
                                        '<p style="font-size:16px;line-height:1.7;color:#111111;">We aim to resolve appeals within 48 hours. Your image will go public immediately if cleared.</p>'
                                        '<p style="font-size:15px;color:#555555;margin-top:24px;">&#8212; Shutter League</p>'
                                        '</div>'
                                    ),
                                    text_body=(
                                        'Hi ' + _uname + ',\n\n'
                                        'Your image "' + (_img.asset_name or 'Untitled') + '" has been flagged for admin review before going public.\n\n'
                                        'Our automated system detected characteristics that may indicate AI generation. '
                                        'High-production constructed shoots can sometimes trigger false positives — if this is an original photograph, we want to clear it quickly.\n\n'
                                        'To appeal, email ' + CONTACT_EMAIL + ' with:\n'
                                        '  - Your original RAW or unedited file\n'
                                        '  - Any behind-the-scenes photos or production notes (if available)\n'
                                        '  - Camera and lens used\n\n'
                                        'We aim to resolve appeals within 48 hours.\n\n'
                                        '-- Shutter League'
                                    )
                                )
                                send_email(
                                    to_addresses=[ADMIN_EMAIL],
                                    subject='[Admin] AI Flag — ' + (_img.asset_name or 'Untitled'),
                                    html_body=('<p>Auto-flagged AI image.</p><ul><li>Image: ' + (_img.asset_name or 'Untitled') + '</li><li>AI Suspicion: ' + str(round(ai_suspicion, 2)) + '</li><li>User: ' + (_u.email if _u else 'unknown') + '</li></ul><p><a href="' + _iurl + '">Review</a></p>'),
                                    text_body=('AI Flag\nImage: ' + (_img.asset_name or 'Untitled') + '\nSuspicion: ' + str(round(ai_suspicion, 2)) + '\nUser: ' + (_u.email if _u else 'unknown') + '\nReview: ' + _iurl)
                                )
                            except Exception as _me:
                                app.logger.error(f'[AI flag email error] {_me}')

                        else:
                            # Score normally — but only write engine scores if image
                            # wasn't already scored from cache (breastfeeding+cache path).
                            # In that case auto_score was called for sub-genre only;
                            # the cached scores must be preserved.
                            _already_scored = bool(_img.score)  # True on cache-hit+BF path
                            if not _already_scored:
                                _img.dod_score        = float(result.get('dod', 0))
                                _img.disruption_score = float(result.get('disruption', 0))
                                _img.dm_score         = float(result.get('dm', 0))
                                _img.wonder_score     = float(result.get('wonder', 0))
                                _img.aq_score         = float(result.get('aq', 0))
                                _img.score            = float(result.get('score', 0))
                                _img.tier             = get_tier(float(result.get('score', 0)))
                                _img.archetype        = result.get('archetype', '')
                                _img.soul_bonus       = result.get('soul_bonus', False)
                                _img.status           = 'scored'
                                _img.scored_at        = datetime.utcnow()
                                audit = build_audit_data(result, _img)
                                _img.set_audit(audit)
                                if _sc_calendar_ids:
                                    _img.seasonal_calendar_ids_shown = ','.join(str(_cid) for _cid in _sc_calendar_ids)
                                db.session.commit()

                                # Item C — log rotation entries only on successful scoring,
                                # so a failed/retried attempt doesn't burn a rotation slot.
                                try:
                                    if _sc_calendar_ids:
                                        from engine.seasonal_calendar import log_seasonal_shown
                                        log_seasonal_shown(db.session, _img.user_id, _sc_calendar_ids)
                                except Exception as _ssl_err:
                                    app.logger.warning(f'[auto_score] seasonal_shown_log error: {_ssl_err}')

                            # ── Write to scored_phash_cache (v63) ──────────────────────────
                            # Anchors score to phash so delete+reupload returns same score.
                            # Only caches clean scores (ai_suspicion < 0.4, not flagged).
                            try:
                                if (_img.phash and _img.score
                                        and not _img.is_flagged and ai_suspicion < 0.4):
                                    _cache_sql = (
                                        "INSERT INTO scored_phash_cache "
                                        "(user_id, phash, genre, score, tier, "
                                        " dod_score, disruption_score, dm_score, "
                                        " wonder_score, aq_score, archetype, "
                                        " soul_bonus, original_image_id, audit_json, scored_at) "
                                        "VALUES "
                                        "(:uid, :ph, :genre, :score, :tier, "
                                        " :dod, :dis, :dm, :wonder, :aq, :arch, "
                                        " :soul, :iid, :audit_json, NOW()) "
                                        "ON CONFLICT (user_id, phash, genre) "
                                        "DO UPDATE SET "
                                        " score=EXCLUDED.score, tier=EXCLUDED.tier, "
                                        " dod_score=EXCLUDED.dod_score, "
                                        " disruption_score=EXCLUDED.disruption_score, "
                                        " dm_score=EXCLUDED.dm_score, "
                                        " wonder_score=EXCLUDED.wonder_score, "
                                        " aq_score=EXCLUDED.aq_score, "
                                        " archetype=EXCLUDED.archetype, "
                                        " soul_bonus=EXCLUDED.soul_bonus, "
                                        " original_image_id=EXCLUDED.original_image_id, "
                                        " audit_json=EXCLUDED.audit_json, "
                                        " scored_at=NOW()"
                                    )
                                    db.session.execute(db.text(_cache_sql), {
                                        'uid':   _img.user_id,  'ph':    _img.phash,
                                        'genre': _img.genre,    'score': _img.score,
                                        'tier':  _img.tier,     'dod':   _img.dod_score,
                                        'dis':   _img.disruption_score,
                                        'dm':    _img.dm_score, 'wonder':_img.wonder_score,
                                        'aq':    _img.aq_score, 'arch':  _img.archetype,
                                        'soul':  bool(_img.soul_bonus), 'iid': _img.id,
                                        'audit_json': _img._audit_json or None,
                                    })
                                    db.session.commit()
                                    app.logger.info(
                                        f'[scoring] phash cache written: image={_img.id} '
                                        f'score={_img.score} phash={_img.phash[:16]}…'
                                    )
                            except Exception as _cache_write_err:
                                app.logger.warning(
                                    f'[scoring] phash cache write failed (non-fatal): {_cache_write_err}'
                                )
                            # ── END scored_phash_cache write ───────────────────────────────

                            # ── CSI — Cultural Saturation Intelligence scan ─────────────
                            # Runs on main upload path only. Skipped for edit versions
                            # (parent_image_id set = edit path) — the edit is the same
                            # photographer improving their own image; rescanning would
                            # re-trigger the same cross-user flag already on the parent.
                            # No score changes. Ever. Detection and logging only.
                            try:
                                _csi_parent_row = db.session.execute(db.text(
                                    "SELECT parent_image_id FROM images WHERE id = :iid"
                                ), {'iid': _img.id}).fetchone()
                                _csi_is_edit = bool(_csi_parent_row and _csi_parent_row[0])

                                if not _csi_is_edit and _img.phash and _img.genre and not _img.is_flagged:
                                    from engine.processor import hash_similarity_pct as _csi_sim
                                    _csi_others = db.session.execute(db.text(
                                        "SELECT id, phash FROM images "
                                        "WHERE user_id != :uid AND genre = :genre "
                                        "AND phash IS NOT NULL AND status = 'scored' "
                                        "AND id != :iid"
                                    ), {'uid': _img.user_id, 'genre': _img.genre, 'iid': _img.id}).fetchall()

                                    _csi_95_ids  = []
                                    _csi_85_ids  = []
                                    for _co in _csi_others:
                                        try:
                                            _sim = _csi_sim(_img.phash, _co[1])
                                            if _sim >= 95.0:
                                                _csi_95_ids.append((_co[0], _sim))
                                            elif _sim >= 85.0:
                                                _csi_85_ids.append((_co[0], _sim))
                                        except Exception:
                                            continue

                                    # Log all 85%+ matches to admin log
                                    _csi_all_matches = [(iid, s, 95) for iid, s in _csi_95_ids] + \
                                                       [(iid, s, 85) for iid, s in _csi_85_ids]
                                    for _cm_id, _cm_sim, _cm_thresh in _csi_all_matches:
                                        try:
                                            db.session.execute(db.text(
                                                "INSERT INTO csi_admin_log "
                                                "(image_id, similar_image_id, similarity_pct, genre, threshold_hit) "
                                                "VALUES (:iid, :sid, :sim, :genre, :thresh)"
                                            ), {
                                                'iid':   _img.id,
                                                'sid':   _cm_id,
                                                'sim':   round(_cm_sim, 1),
                                                'genre': _img.genre,
                                                'thresh': _cm_thresh,
                                            })
                                        except Exception:
                                            pass
                                    if _csi_all_matches:
                                        db.session.commit()

                                    # 95%+ → inject into audit_json as scorecard note trigger
                                    if _csi_95_ids:
                                        try:
                                            _csi_audit = _img.get_audit()
                                            _csi_audit['csi_threshold_hit']  = 95
                                            _csi_audit['csi_similar_count']  = len(_csi_95_ids)
                                            _csi_audit['csi_similar_ids']    = [iid for iid, _ in _csi_95_ids[:3]]
                                            _img.set_audit(_csi_audit)
                                            db.session.commit()
                                            app.logger.info(
                                                f'[csi] image={_img.id} genre={_img.genre} '
                                                f'95%+ matches={len(_csi_95_ids)} — scorecard note set'
                                            )
                                        except Exception as _csi_audit_err:
                                            app.logger.warning(f'[csi] audit update failed: {_csi_audit_err}')
                                    elif _csi_85_ids:
                                        app.logger.info(
                                            f'[csi] image={_img.id} genre={_img.genre} '
                                            f'85-94% matches={len(_csi_85_ids)} — admin log only'
                                        )

                            except Exception as _csi_err:
                                app.logger.warning(f'[csi] scan failed (non-fatal): {_csi_err}')
                            # ── END CSI scan ────────────────────────────────────────────
                            try:
                                _pts_user = User.query.get(_img.user_id)
                                if (_pts_user and _pts_user.is_subscribed
                                        and _img.score and not _img.is_flagged):
                                    _pts_earned = _img.score * 10  # exact, no rounding
                                    award_points(_pts_user, _pts_earned, 'image_scored', commit=False)

                                    # ── Mission bonus: +10 pts if mission was followed ──
                                    # Mission is followed if:
                                    # (a) image has a mission_dimension set, AND
                                    # (b) the score on that dimension >= user's baseline avg
                                    _mission_dim = getattr(_img, 'mission_dimension', None)
                                    if _mission_dim:
                                        _dim_key_map = {
                                            'dod': 'dod_score', 'dm': 'dm_score',
                                            'aq': 'aq_score', 'wonder': 'wonder_score',
                                            'disruption': 'disruption_score'
                                        }
                                        _dim_col = _dim_key_map.get(_mission_dim)
                                        _dim_score = getattr(_img, _dim_col, None) if _dim_col else None
                                        if _dim_score and _dim_score >= 5.0:
                                            # Mission followed — award bonus
                                            award_points(_pts_user, 10.0, 'mission_complete', commit=False)
                                            _img.scoring_flash = (
                                                f'+{_pts_earned:.1f} pts earned \u00b7 Your eye is moving forward.'
                                            )
                                        else:
                                            # Mission not followed — ground the message in the actual
                                            # curriculum lesson behind this mission, not just a generic
                                            # dimension label. Disruption is kept as the literal term
                                            # (not euphemised to "Originality") because that's the actual
                                            # construct the engine measures — does the eye get forced to
                                            # re-look at something it expected it had already understood.
                                            # A user's subject being inherently unusual (e.g. a flamingo)
                                            # doesn't make the TREATMENT disruptive, so the guidance line
                                            # below still does the work of clarifying that distinction.
                                            _dim_label_map = {
                                                'dod': 'Technical Difficulty', 'dm': 'Timing',
                                                'aq': 'Visual Impact', 'wonder': 'Wonder',
                                                'disruption': 'Disruption'
                                            }
                                            _dim_label = _dim_label_map.get(_mission_dim, 'that dimension')
                                            _dim_guidance_map = {
                                                'dod': 'push your technical control \u2014 exposure, focus, and handling of light have to work harder here.',
                                                'dm': 'the timing has to be unmistakably decisive \u2014 a beat earlier or later and the frame falls apart.',
                                                'aq': 'the image needs more visual punch \u2014 composition and color that hold attention immediately.',
                                                'wonder': 'the photograph has to evoke genuine wonder \u2014 something that stops a viewer, not just documents a scene.',
                                                'disruption': 'this isn\u2019t about how unusual the subject is \u2014 it\u2019s about breaking from the expected, predictable treatment of it. Try an unconventional angle, mood, or moment.',
                                            }
                                            _dim_guidance = _dim_guidance_map.get(
                                                _mission_dim, 'submit a frame where that is the primary intention.')

                                            # Look up the exact curriculum principle this mission was
                                            # generated from (if linked) to name the real lesson instead
                                            # of only the dimension. NOTE: this grounds the message in the
                                            # lesson text already shown to the user on the mission screen —
                                            # it is not yet a per-dimension AI critique of the submitted
                                            # photo itself; that's a separate, still-in-progress piece of
                                            # the scoring engine.
                                            _principle_id = getattr(_img, 'mission_principle_id', None)
                                            _principle_entry = _CURRICULUM_BY_ID.get(_principle_id) if _principle_id else None

                                            if _principle_entry:
                                                _img.scoring_flash = (
                                                    f'+{_pts_earned:.1f} pts earned \u00b7 Your photograph was evaluated \u2014 '
                                                    f'today\u2019s mission was \u201c{_principle_entry.get("title", _dim_label)}\u201d: '
                                                    f'{_principle_entry.get("principle", "")} This frame didn\u2019t carry that through \u2014 {_dim_guidance}'
                                                )
                                            else:
                                                _img.scoring_flash = (
                                                    f'+{_pts_earned:.1f} pts earned \u00b7 Your photograph was evaluated \u2014 '
                                                    f'the mission focuses on {_dim_label}. {_dim_guidance}'
                                                )
                                    else:
                                        # No mission — generic flash
                                        _img.scoring_flash = f'+{_pts_earned:.1f} pts earned'
                                    # Check tier jump bonus
                                    _img_count = Image.query.filter_by(
                                        user_id=_pts_user.id, status='scored'
                                    ).count()
                                    check_tier_jump_bonus(
                                        _pts_user, _img.tier, _img_count, commit=False
                                    )
                                    db.session.commit()
                            except Exception as _pe:
                                app.logger.error(f'[points hook] image_scored error: {_pe}')

                            # TIER 2 — needs human review
                            if ai_suspicion >= 0.4 or _img.score >= 9.0:
                                _img.needs_review = True
                                _img.is_public    = False
                                review_reason_parts = []
                                if ai_suspicion >= 0.4:
                                    review_reason_parts.append(f'AI suspicion score {ai_suspicion:.2f} (amber zone)')
                                if _img.score >= 9.0:
                                    review_reason_parts.append(f'Grandmaster score {_img.score} requires RAW verification')
                                _img.flagged_reason = ' . '.join(review_reason_parts)

                                try:
                                    _u = User.query.get(_img.user_id)
                                    _uname = (_u.full_name or _u.username) if _u else 'Photographer'
                                    _iurl = f'https://shutterleague.com/image/{_img.id}'
                                    _site_url = os.getenv('SITE_URL', 'https://shutterleague.com')
                                    if _img.score >= 9.0 and ai_suspicion < 0.4:
                                        _img.raw_verification_required = True
                                        _deadline = datetime.utcnow() + timedelta(days=7)
                                        # ── JPEG provenance path check ──
                                        if check_jpeg_provenance_eligible(_img):
                                            # Camera-direct JPEG — send the JPEG provenance emailer instead
                                            _jp_url = f'{_site_url}/jpeg-provenance/submit/{_img.id}'
                                            import threading as _jpt
                                            _jpt.Thread(
                                                target=_send_jpeg_provenance_email,
                                                args=(_img.id, _jp_url, _user_email, _user_name, _img.asset_name, round(_img.normalised_score, 2)),
                                                daemon=True
                                            ).start()
                                            app.logger.info(f'[jpeg_provenance_trigger] image={_img.id} score={_img.normalised_score}')
                                        else:
                                            _submit_url = f'{_site_url}/raw/submit/weekly/{_img.id}'
                                        try:
                                            db.session.execute(db.text(
                                                "INSERT INTO raw_submissions "
                                                "(image_id, user_id, contest_ref, contest_type, deadline, analysis_status) "
                                                "VALUES (:iid, :uid, 'grandmaster', 'weekly', :dl, 'awaiting') "
                                                "ON CONFLICT (image_id, contest_ref, contest_type) DO UPDATE SET deadline=:dl"
                                            ), {'iid': _img.id, 'uid': _img.user_id, 'dl': _deadline})
                                        except Exception:
                                            pass
                                        _send_grandmaster_raw_email(
                                            user_email = _u.email if _u else '',
                                            user_name  = _uname,
                                            asset_name = _img.asset_name,
                                            score      = _img.score,
                                            tier       = _img.tier,
                                            submit_url = _submit_url,
                                        )
                                        send_email(
                                            to_addresses=[ADMIN_EMAIL],
                                            subject='[Admin] Grandmaster RAW Required — ' + (_img.asset_name or 'Untitled') + ' (' + str(_img.score) + ')',
                                            html_body=('<p>Grandmaster image auto-flagged for RAW verification. Submission record created. User notified with direct submit link.</p><ul><li>Image: ' + (_img.asset_name or 'Untitled') + '</li><li>Score: ' + str(_img.score) + ' — ' + (_img.tier or '') + '</li><li>Photographer: ' + (_img.photographer_name or _uname) + '</li><li>User: ' + (_u.email if _u else 'unknown') + '</li><li>Deadline: 7 days</li></ul><p><a href="' + _site_url + '/admin/raw-verification/' + str(_img.id) + '">View in RAW Queue</a></p>'),
                                            text_body=('Grandmaster RAW auto-flagged\nImage: ' + (_img.asset_name or 'Untitled') + '\nScore: ' + str(_img.score) + '\nUser: ' + (_u.email if _u else 'unknown'))
                                        )
                                    else:
                                        send_email(
                                            to_addresses=[ADMIN_EMAIL],
                                            subject='[Admin] Image Flagged for Review — ' + (_img.asset_name or 'Untitled'),
                                            html_body=('<p>Image flagged for review.</p><ul><li>Image: ' + (_img.asset_name or 'Untitled') + '</li><li>Score: ' + str(_img.score) + ' — ' + (_img.tier or '') + '</li><li>Reason: ' + (_img.flagged_reason or '') + '</li><li>User: ' + (_u.email if _u else 'unknown') + '</li></ul><p><a href="' + _iurl + '">Review</a></p>'),
                                            text_body=('Flagged for review.\nImage: ' + (_img.asset_name or 'Untitled') + '\nReason: ' + (_img.flagged_reason or '') + '\nUser: ' + (_u.email if _u else 'unknown') + '\nReview: ' + _iurl)
                                        )
                                except Exception as _me:
                                    app.logger.error(f'[review notification email error] {_me}')

                            db.session.commit()

                            try:
                                _card_audit = audit or _img.get_audit() or {}
                                card_fname = (f"LL_{date.today().strftime('%Y%m%d')}_"
                                              f"{secure_filename((_img.photographer_name or 'unknown').replace(' ',''))}_"
                                              f"{_img.genre}_{_img.score}.jpg")
                                card_path = os.path.join(app.config['UPLOAD_FOLDER'], 'cards', card_fname)
                                build_card1(_img.thumb_path, _card_audit, card_path)
                                _img.card_path = card_path
                                card_url = _r2_upload_card(card_path, _uid + '_card')
                                if card_url:
                                    _img.card_url = card_url
                                db.session.commit()
                            except Exception:
                                app.logger.error(f'[upload card build error] {traceback.format_exc()}')

                    except Exception as e:
                        app.logger.error(f'[background scoring error] {traceback.format_exc()}')
                        try:
                            _img = Image.query.get(image_id)
                            if _img and _img.status == 'processing':
                                _img.status = 'error'
                                db.session.commit()
                        except Exception:
                            pass

            if not _anchored_score or _nsfw_breastfeeding_flagged:
                # Fire scoring thread when: no cache (normal path), OR
                # breastfeeding flagged (needs sub-genre check even on cache hit)
                threading.Thread(
                    target=_score_in_background,
                    args=(img.id, uid, _travel_city),
                    daemon=True
                ).start()

        else:
            flash('Image uploaded! Add scores below.', 'success')

        # XHR (upload.html) gets JSON.
        # Cache hit → status 'processing' still works because score-status
        # polls and finds status='scored' immediately on first poll.
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest' or request.form.get('_xhr') == '1':
            _next = request.args.get('next', '')
            return jsonify({
                'status': 'processing',
                'image_id': img.id,
                'next': _next
            })
        # Non-XHR fallback — redirect to dashboard.
        # Redirecting to image_detail (login_required) in the same chain as
        # the POST causes the session cookie to be dropped on some browsers,
        # kicking the user to login. Dashboard is safe — it already shows
        # pending/processing images and the score appears once ready.
        next_page = request.args.get('next', '')
        if next_page == 'challenge':
            return redirect(url_for('challenge_submit') + f'?highlight={img.id}')
        flash('Image uploaded — your score will appear shortly.', 'success')
        return redirect(url_for('dashboard'))

    import json as _json
    _last_image = Image.query.filter(
        Image.user_id == current_user.id,
        Image.location.isnot(None),
        Image.location != ''
    ).order_by(Image.created_at.desc()).first()
    _last_location = (_last_image.location if _last_image else None) or current_user.city or ''

    return render_template('upload.html', genres=GENRE_IDS, genre_choices=GENRE_CHOICES,
                           subgenre_map=SUBGENRE_MAP,
                           subgenre_map_json=_json.dumps(
                               {k: list(v) for k, v in SUBGENRE_MAP.items()}
                           ),
                           last_location=_last_location,
                           mission_dimension=request.args.get('mission_dimension', ''),
                           curriculum_principle_id=request.args.get('curriculum_principle_id', ''),
                           mission_title=request.args.get('mission_title', ''),
                           next_page=request.args.get('next', ''))


@app.route('/upload/dispute/<int:dispute_id>/submit', methods=['POST'])
@login_required
def submit_upload_dispute(dispute_id):
    """
    User objects to an NSFW hard-reject — "Think this is a mistake? Tell us".
    Marks the dispute submitted and emails ADMIN_EMAIL with the preserved
    thumbnail, the user's info, and what the check itself detected, so an
    admin can review and resolve manually. V1 has no in-app approve/reject
    UI — that's a natural follow-up if manual handling becomes a drag.
    """
    row = db.session.execute(
        db.text("""SELECT id, user_id, thumb_url, original_filename, nsfw_description, status
                    FROM upload_disputes WHERE id = :id"""),
        {'id': dispute_id}
    ).fetchone()

    if not row or row.user_id != current_user.id:
        return jsonify({'error': True, 'message': 'Dispute not found.'}), 404

    if row.status == 'submitted':
        return jsonify({'ok': True, 'message': "Already sent to our team."})

    _user_reason = request.form.get('reason', '').strip()[:500]

    try:
        db.session.execute(
            db.text("UPDATE upload_disputes SET status = 'submitted', submitted_at = NOW(), user_reason = :reason WHERE id = :id"),
            {'id': dispute_id, 'reason': _user_reason}
        )
        db.session.commit()
    except Exception as _dispute_update_err:
        db.session.rollback()
        app.logger.error(f'[upload_dispute] status update failed: {_dispute_update_err}')
        return jsonify({'error': True, 'message': 'Could not record your objection — please try again.'}), 500

    try:
        _user_label = getattr(current_user, 'name', None) or current_user.email
        html_body = f"""<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:0;background:#F5F0E8;font-family:Georgia,serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#F5F0E8;padding:32px 16px;">
  <tr><td align="center">
    <table width="560" cellpadding="0" cellspacing="0" style="background:#ffffff;border:1px solid #E0D8C8;border-radius:8px;overflow:hidden;max-width:560px;width:100%;">
      <tr><td style="background:#1a1a18;padding:24px 32px;">
        <p style="margin:0;font-family:'Courier New',monospace;font-size:15px;font-weight:700;letter-spacing:3px;color:#C8A84B;text-transform:uppercase;">SHUTTER LEAGUE</p>
      </td></tr>
      <tr><td style="padding:28px 32px;">
        <h1 style="margin:0 0 6px;font-size:22px;color:#1a1a18;">Upload rejection disputed</h1>
        <p style="margin:0 0 20px;color:#8a8070;font-size:15px;">Dispute #{dispute_id} &middot; submitted {datetime.utcnow().strftime('%d %b %Y, %H:%M UTC')}</p>
        <img src="{row.thumb_url}" alt="Flagged image" style="width:100%;max-width:480px;border-radius:6px;border:1px solid #E0D8C8;margin-bottom:20px;display:block;">
        <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:20px;">
          <tr><td style="padding:6px 0;color:#8a8070;font-size:14px;width:140px;vertical-align:top;">User</td><td style="padding:6px 0;color:#1a1a18;font-size:14px;">{_user_label} ({current_user.email})</td></tr>
          <tr><td style="padding:6px 0;color:#8a8070;font-size:14px;vertical-align:top;">Filename</td><td style="padding:6px 0;color:#1a1a18;font-size:14px;">{row.original_filename or 'unknown'}</td></tr>
          <tr><td style="padding:6px 0;color:#8a8070;font-size:14px;vertical-align:top;">System flagged</td><td style="padding:6px 0;color:#1a1a18;font-size:14px;">{row.nsfw_description or 'no description returned'}</td></tr>
          <tr><td style="padding:6px 0;color:#8a8070;font-size:14px;vertical-align:top;">Photographer says</td><td style="padding:6px 0;color:#1a1a18;font-size:14px;font-style:italic;">{_user_reason or 'No reason provided'}</td></tr>
        </table>
        <table width="100%" cellpadding="0" cellspacing="0" style="margin-top:24px;">
          <tr>
            <td style="padding-right:8px;">
              <a href="{_site_url}/admin/dispute/{dispute_id}/approve" style="display:inline-block;background:#2a7a3a;color:#fff;font-family:'Courier New',monospace;font-size:13px;font-weight:700;letter-spacing:1px;text-transform:uppercase;padding:12px 24px;border-radius:6px;text-decoration:none;">✓ Approve — Clear Flag</a>
            </td>
            <td>
              <a href="{_site_url}/admin/dispute/{dispute_id}/reject" style="display:inline-block;background:#7a2a2a;color:#fff;font-family:'Courier New',monospace;font-size:13px;font-weight:700;letter-spacing:1px;text-transform:uppercase;padding:12px 24px;border-radius:6px;text-decoration:none;">✗ Reject — Keep Flagged</a>
            </td>
          </tr>
        </table>
      </td></tr>
    </table>
  </td></tr>
</table>
</body>
</html>"""
        send_email(
            ADMIN_EMAIL,
            f'Upload dispute #{dispute_id} — {_user_label}',
            html_body
        )
    except Exception as _email_err:
        # Dispute is already recorded in the DB regardless — email is best-effort,
        # never block the user's confirmation on a transport failure.
        app.logger.warning(f'[upload_dispute] email send failed (non-fatal): {_email_err}')

    return jsonify({'ok': True, 'message': "Sent to our team — we'll review and follow up by email."})


@app.route('/score-status/<int:image_id>')
@login_required
def score_status(image_id):
    """Polling endpoint — upload.html checks this every 2s while background scoring runs."""
    img = Image.query.get_or_404(image_id)
    if img.user_id != current_user.id and current_user.role != 'admin':
        abort(403)

    _next = request.args.get('next', '')

    if img.status == 'processing':
        return jsonify({'status': 'processing'})

    if img.status == 'error':
        return jsonify({
            'status': 'error',
            'message': 'Scoring failed. Your image has been saved — please retry from your dashboard.'
        })

    if getattr(img, 'is_flagged', False):
        return jsonify({
            'status': 'flagged',
            'image_id': img.id,
            'message': ('&#x1F6AB; This image has been flagged as potentially AI-generated and cannot be submitted. '
                        'Only original photographs taken by you are accepted. '
                        'If you believe this is an error, contact ' + CONTACT_EMAIL + '.'),
            'redirect': url_for('dashboard')
        })

    if getattr(img, 'needs_review', False):
        if img.score and img.score >= 9.0:
            msg = (f'&#x2728; Grandmaster score ({img.score:.2f})! Your image has been held for RAW verification. '
                   f'Check your email for a direct link to submit your RAW file within 7 days.')
        else:
            msg = ('&#x26A0; Your image has been held for human review before going public. '
                   'Usually resolved within 24-48 hours.')
        return jsonify({
            'status': 'needs_review',
            'image_id': img.id,
            'score': img.score,
            'tier': img.tier,
            'message': msg,
            'redirect': url_for('image_detail', image_id=img.id)
        })

    _redir = (url_for('challenge_submit') + f'?highlight={img.id}') if _next == 'challenge' else url_for('image_detail', image_id=img.id)
    return jsonify({
        'status': 'ok',
        'image_id': img.id,
        'score': img.score,
        'tier': img.tier,
        'redirect': _redir
    })


@app.route('/admin/image/<int:image_id>/force-rescore', methods=['POST'])
@login_required
@admin_required
def admin_force_rescore(image_id):
    """
    Admin-only: force a full rescore of a SINGLE already-scored image using
    the current auto_score() — including the famous event calibration gate,
    mandatory master references, and seasonal/portfolio context.

    Runs in a background thread (same pattern as upload scoring) so the
    HTTP response returns instantly — avoids long-request 503s if a
    redeploy/restart happens mid-scoring. Sets img.status = 'processing'
    immediately; admin UI polls /score-status/<id> for completion.

    Unlike retry_score (owner-only, only for status != 'scored') and
    rescore-all (bulk, old signature), this targets one image regardless
    of its current status, using the full Sprint 2 call signature.

    Use case: an image was scored before a calibration/prompt fix and needs
    to be re-evaluated under the corrected rules (e.g. Latmarr Holi /
    famous-event calibration gate).
    """
    img = Image.query.get_or_404(image_id)

    api_key = os.getenv('ANTHROPIC_API_KEY', '')
    if not api_key:
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest' or request.form.get('_xhr') == '1':
            return jsonify({'status': 'error', 'message': 'Scoring service not available.'}), 503
        flash('Scoring service not available.', 'error')
        return redirect(request.referrer or url_for('admin_dashboard'))

    old_score    = img.score
    old_tier     = img.tier
    old_status   = img.status
    img.status = 'processing'
    db.session.commit()

    threading.Thread(
        target=_force_rescore_in_background,
        args=(image_id, old_score, old_tier, old_status),
        daemon=True
    ).start()

    if request.headers.get('X-Requested-With') == 'XMLHttpRequest' or request.form.get('_xhr') == '1':
        return jsonify({'status': 'processing', 'image_id': image_id})

    flash(f'Rescoring "{img.asset_name}" — this runs in the background, refresh in ~30s.', 'info')
    return redirect(request.referrer or url_for('image_detail', image_id=image_id))


def _force_rescore_in_background(image_id, old_score, old_tier, old_status='scored'):
    """
    Background worker for admin_force_rescore. Runs in its own thread —
    needs its own app context and db session usage matches existing
    _score_in_background pattern in this file.
    """
    with app.app_context():
        img = Image.query.get(image_id)
        if not img:
            return

        try:
            import tempfile, traceback as _tb
            from engine.auto_score import auto_score, build_audit_data, build_exif_context
            from engine.seasonal_calendar import build_seasonal_context, get_primary_genre
            from engine.compositor import build_card1

            thumb_path = img.thumb_path
            temp_file  = None
            if not thumb_path or not os.path.exists(thumb_path):
                from storage import get_client, BUCKET
                tf = tempfile.NamedTemporaryFile(suffix='.jpg', delete=False)
                get_client().download_fileobj(
                    BUCKET, 'thumbs/' + img.thumb_url.split('/thumbs/')[-1], tf
                )
                tf.close()
                thumb_path = temp_file = tf.name

            _exif_ctx = build_exif_context(
                {'make': img.exif_make, 'model': img.exif_model,
                 'focal_length_35mm': img.exif_focal_length_35mm,
                 'lens': img.exif_lens, 'software': img.exif_software,
                 'has_gps': img.exif_has_gps},
                camera_track=img.camera_track,
            ) if (img.exif_make or img.exif_model or img.exif_focal_length_35mm) else ''

            _owner = User.query.get(img.user_id)
            _primary_genre = get_primary_genre(_owner) if _owner else (img.genre or '')
            _user_city     = getattr(_owner, 'city', '') or '' if _owner else ''
            _seasonal_ctx, _sc_calendar_ids = build_seasonal_context(
                db_session    = db.session,
                user_city     = _user_city,
                primary_genre = _primary_genre or img.genre or '',
                current_month = datetime.utcnow().month,
                user_id       = img.user_id,
            )

            # On-demand discovery — same as upload path: call discover_one()
            # directly for this specific city/genre (cheaper than
            # run_seasonal_discovery which scans all users first).
            if not _seasonal_ctx and _user_city and (_primary_genre or img.genre):
                _od_genre = _primary_genre or img.genre or ''
                try:
                    from engine.seasonal_discovery import discover_one
                    _od_n = discover_one(db.session, _user_city, _od_genre, current_month=datetime.utcnow().month)
                    app.logger.info(f'[retry_score] on-demand discovery for ({_user_city}, {_od_genre}): {_od_n} row(s) inserted')
                    if _od_n > 0:
                        _seasonal_ctx, _sc_calendar_ids = build_seasonal_context(
                            db_session    = db.session,
                            user_city     = _user_city,
                            primary_genre = _od_genre,
                            current_month = datetime.utcnow().month,
                            user_id       = img.user_id,
                        )
                except Exception as _od_err:
                    app.logger.warning(f'[retry_score] on-demand discovery failed for ({_user_city}, {_od_genre}): {_od_err}')

            _portfolio_summary = None
            _image_number = 1
            if _owner:
                _scored_count = Image.query.filter(
                    Image.user_id == _owner.id, Image.status == 'scored'
                ).count()
                _image_number = _scored_count + 1
                if _scored_count >= 2:
                    _recent = db.session.query(
                        Image.aq_score, Image.dm_score, Image.dod_score
                    ).filter(
                        Image.user_id == _owner.id,
                        Image.status  == 'scored',
                        Image.genre   == img.genre,
                    ).order_by(Image.scored_at.desc()).limit(8).all()
                    if _recent:
                        _recent = list(reversed(_recent))
                        _portfolio_summary = {
                            "feeling":    [r.aq_score  for r in _recent if r.aq_score  is not None],
                            "timing":     [r.dm_score  for r in _recent if r.dm_score  is not None],
                            "difficulty": [r.dod_score for r in _recent if r.dod_score is not None],
                        }
                        # ── Variety history — last 5 audit JSONs ──────────────
                        try:
                            _recent_audits = db.session.execute(
                                db.text("SELECT audit_json FROM images WHERE user_id=:uid AND status='scored' ORDER BY scored_at DESC LIMIT 5"),
                                {'uid': _owner.id}
                            ).fetchall()
                            _r_masters, _r_openings, _r_locations = [], [], []
                            import re as _re_var2
                            _open_rx2 = _re_var2.compile(
                                r'^(Brilliantly|Beautifully|Exceptionally|Wonderfully|Remarkably|'
                                r'Impressively|Expertly|Perfectly|Powerfully|Elegantly|Sharply|'
                                r'Boldly|Quietly|Instinctively|Patiently|Decisively|Confidently|'
                                r'Sensitively|Fearlessly|Generously)', _re_var2.IGNORECASE
                            )
                            for (_aj,) in _recent_audits:
                                if not _aj:
                                    continue
                                try:
                                    _ad = json.loads(_aj)
                                except Exception:
                                    continue
                                _ta = _ad.get('transferable_advice') or ''
                                for _bold in _re_var2.findall(r'\*\*([^*]+)\*\*', _ta):
                                    _first_word = _bold.split()[0] if _bold.split() else ''
                                    if _first_word and len(_first_word) > 2:
                                        _r_masters.append(_bold[:60])
                                        break
                                _ht = _ad.get('hard_truth') or ''
                                _om = _open_rx2.match(_ht.strip())
                                if _om:
                                    _r_openings.append(_om.group(1))
                                _ml = _ad.get('mentor_location_1') or ''
                                if _ml:
                                    _loc_first = _ml.split('.')[0][:50].strip()
                                    if _loc_first:
                                        _r_locations.append(_loc_first)
                            _portfolio_summary['recent_masters']   = _r_masters[:5]
                            _portfolio_summary['recent_openings']  = _r_openings[:5]
                            _portfolio_summary['recent_locations'] = _r_locations[:3]
                            _portfolio_summary['recent_philosophy'] = []
                        except Exception as _var_err2:
                            app.logger.debug(f'[retry_score] variety history extraction failed: {_var_err2}')

            result = auto_score(
                image_path        = thumb_path,
                genre             = img.genre,
                sub_genre         = img.sub_genre,
                title             = img.asset_name,
                photographer      = img.photographer_name,
                subject           = img.subject,
                location          = img.location,
                exif_context      = _exif_ctx,
                seasonal_context  = _seasonal_ctx,
                portfolio_summary = _portfolio_summary,
                user_city         = _user_city,
                primary_genre     = _primary_genre or img.genre or '',
                image_number      = _image_number,
            )

            img.dod_score        = float(result.get('dod', 0))
            img.disruption_score = float(result.get('disruption', 0))
            img.dm_score         = float(result.get('dm', 0))
            img.wonder_score     = float(result.get('wonder', 0))
            img.aq_score         = float(result.get('aq', 0))
            img.score            = float(result.get('score', 0))
            img.tier             = get_tier(float(result.get('score', 0)))
            img.archetype        = result.get('archetype', img.archetype)
            img.soul_bonus       = result.get('soul_bonus', img.soul_bonus)
            img.status           = 'scored'
            img.scored_at        = datetime.utcnow()
            audit = build_audit_data(result, img)
            img.set_audit(audit)

            # ── Re-evaluate review/RAW-verification flags against the new score ──
            # needs_review can be set for two independent reasons: AI suspicion
            # (>=0.4, stored separately and unaffected by rescore) or Grandmaster
            # score (>=9.0, which a rescore may have changed). Only clear the
            # Grandmaster-driven flags if the new score no longer qualifies AND
            # AI suspicion isn't the (or an additional) reason.
            _ai_susp = getattr(img, 'ai_suspicion', 0.0) or 0.0
            _was_grandmaster_flag = (
                img.needs_review and _ai_susp < 0.4 and
                img.flagged_reason and 'RAW verification' in (img.flagged_reason or '')
            )
            if _was_grandmaster_flag and img.score < 9.0:
                img.needs_review              = False
                img.raw_verification_required = False
                img.flagged_reason            = None
                if not img.is_flagged:
                    img.is_public = True
                app.logger.info(
                    f'[force_rescore] image={image_id} cleared Grandmaster RAW-verification '
                    f'flag — new score {img.score:.2f} no longer qualifies'
                )
            elif img.score >= 9.0 and not img.needs_review and _ai_susp < 0.4:
                # New score crossed INTO Grandmaster territory on rescore — flag it
                img.needs_review              = True
                img.raw_verification_required = True
                img.is_public                 = False
                img.flagged_reason            = f'Grandmaster score {img.score:.2f} requires RAW verification'
                app.logger.info(
                    f'[force_rescore] image={image_id} new score {img.score:.2f} '
                    f'crossed into Grandmaster — flagged for RAW verification'
                )
                # Notify the photographer — same Sherpa email as the original
                # scoring path, and create the raw_submissions deadline record
                # so /raw/submit/weekly/<id> works the same way.
                try:
                    _owner = User.query.get(img.user_id)
                    if _owner:
                        _uname    = _owner.full_name or _owner.username
                        _deadline = datetime.utcnow() + timedelta(days=7)
                        _site_url = os.getenv('SITE_URL', 'https://shutterleague.com')
                        _submit_url = f'{_site_url}/raw/submit/weekly/{img.id}'
                        try:
                            db.session.execute(db.text(
                                "INSERT INTO raw_submissions "
                                "(image_id, user_id, contest_ref, contest_type, deadline, analysis_status) "
                                "VALUES (:iid, :uid, 'grandmaster', 'weekly', :dl, 'awaiting') "
                                "ON CONFLICT (image_id, contest_ref, contest_type) DO UPDATE SET deadline=:dl"
                            ), {'iid': img.id, 'uid': img.user_id, 'dl': _deadline})
                        except Exception:
                            pass
                        _send_grandmaster_raw_email(
                            user_email = _owner.email,
                            user_name  = _uname,
                            asset_name = img.asset_name,
                            score      = img.score,
                            tier       = img.tier,
                            submit_url = _submit_url,
                        )
                except Exception as _gme:
                    app.logger.error(f'[force_rescore grandmaster email] {_gme}')

            db.session.commit()

            # Item C — log rotation entries only on successful (re)scoring.
            try:
                if _sc_calendar_ids:
                    img.seasonal_calendar_ids_shown = ','.join(str(_cid) for _cid in _sc_calendar_ids)
                    db.session.commit()
                    from engine.seasonal_calendar import log_seasonal_shown
                    log_seasonal_shown(db.session, img.user_id, _sc_calendar_ids)
            except Exception as _ssl_err:
                app.logger.warning(f'[force_rescore] seasonal_shown_log error: {_ssl_err}')

            # Regenerate the scorecard card image (best effort — non-fatal)
            try:
                uid = str(uuid.uuid4())
                card_fname = (f"LL_{date.today().strftime('%Y%m%d')}_"
                              f"{secure_filename((img.photographer_name or 'unknown').replace(' ',''))}_"
                              f"{img.genre}_{img.score}.jpg")
                card_path = os.path.join(app.config['UPLOAD_FOLDER'], 'cards', card_fname)
                build_card1(thumb_path, audit, card_path)
                img.card_path = card_path
                card_url = _r2_upload_card(card_path, uid + '_card')
                if card_url:
                    img.card_url = card_url
                db.session.commit()
            except Exception:
                app.logger.error(f'[force_rescore card error] {_tb.format_exc()}')

            if temp_file:
                try: os.unlink(temp_file)
                except: pass

            app.logger.info(
                f'[force_rescore] image={image_id} '
                f'{(old_score if old_score is not None else 0):.2f} ({old_tier or "—"}) -> {img.score:.2f} ({img.tier})'
            )

        except Exception as e:
            db.session.rollback()
            img2 = Image.query.get(image_id)
            if img2:
                # Restore to whatever status the image had before this rescore
                # attempt — don't leave it stuck in 'processing', but don't
                # claim 'scored' for an image that was never successfully
                # scored (e.g. a retry of an 'error'-status image that failed again).
                img2.status = old_status if old_status in ('scored', 'error') else 'scored'
                db.session.commit()
            app.logger.error(f'[force_rescore_bg] {_tb.format_exc()}')


@app.route('/image/<int:image_id>/retry-score', methods=['POST'])
@login_required
def retry_score(image_id):
    img = Image.query.get_or_404(image_id)
    if img.user_id != current_user.id and current_user.role != 'admin':
        abort(403)
    if img.status == 'scored':
        flash('This image has already been scored.', 'info')
        return redirect(url_for('image_detail', image_id=image_id))
    if img.status == 'processing':
        flash('This image is already being evaluated — refresh in a moment.', 'info')
        return redirect(url_for('image_detail', image_id=image_id))
    if not img.thumb_path or not os.path.exists(img.thumb_path):
        if not img.thumb_url:
            flash('Image file not found. Please contact support.', 'error')
            return redirect(url_for('image_detail', image_id=image_id))

    api_key = os.getenv('ANTHROPIC_API_KEY', '')
    if not api_key:
        flash('Scoring service not available. Please try again later.', 'error')
        return redirect(url_for('image_detail', image_id=image_id))

    old_status = img.status
    img.status = 'processing'
    db.session.commit()

    threading.Thread(
        target=_retry_score_in_background,
        args=(image_id, old_status),
        daemon=True
    ).start()

    flash('Evaluating your photograph — this can take up to a minute.', 'info')
    return redirect(url_for('image_detail', image_id=image_id))


def _retry_score_in_background(image_id, old_status):
    """
    Background worker for retry_score. Runs in its own thread — needs its
    own app context, matches the existing _force_rescore_in_background
    pattern in this file. No request context here, so no flash() calls;
    outcomes are communicated via img.status, which the existing
    /score-status/<id> polling route + image_detail.html already surface
    to the user (processing -> scored, or processing -> error with a
    friendly message).
    """
    with app.app_context():
        img = Image.query.get(image_id)
        if not img:
            return

        temp_file = None
        try:
            import traceback, tempfile
            from engine.auto_score import auto_score, build_audit_data, build_exif_context
            from engine.compositor import build_card1

            thumb_path = img.thumb_path
            if not thumb_path or not os.path.exists(thumb_path):
                from storage import get_client, BUCKET
                tf = tempfile.NamedTemporaryFile(suffix='.jpg', delete=False)
                get_client().download_fileobj(
                    BUCKET, 'thumbs/' + img.thumb_url.split('/thumbs/')[-1], tf
                )
                tf.close()
                thumb_path = temp_file = tf.name

            _rescore_exif_ctx = build_exif_context(
                {'make': img.exif_make, 'model': img.exif_model,
                 'focal_length_35mm': img.exif_focal_length_35mm,
                 'lens': img.exif_lens, 'software': img.exif_software,
                 'has_gps': img.exif_has_gps},
                camera_track=img.camera_track,
            ) if (img.exif_make or img.exif_model or img.exif_focal_length_35mm) else ''

            result = auto_score(
                image_path   = thumb_path,
                genre        = img.genre,
                sub_genre    = img.sub_genre,
                title        = img.asset_name,
                photographer = img.photographer_name,
                subject      = img.subject,
                location     = img.location,
                exif_context = _rescore_exif_ctx,
            )

            img.dod_score        = float(result.get('dod', 0))
            img.disruption_score = float(result.get('disruption', 0))
            img.dm_score         = float(result.get('dm', 0))
            img.wonder_score     = float(result.get('wonder', 0))
            img.aq_score         = float(result.get('aq', 0))
            img.score            = float(result.get('score', 0))
            img.tier             = get_tier(float(result.get('score', 0)))
            img.archetype        = result.get('archetype', '')
            img.soul_bonus       = result.get('soul_bonus', False)
            img.status           = 'scored'
            img.scored_at        = datetime.utcnow()
            _ensure_share_token(img)
            audit = build_audit_data(result, img)
            img.set_audit(audit)
            db.session.commit()

            # Sprint 2 — award points for scored image (subscribers only)
            try:
                _su = User.query.get(img.user_id)
                if _su and _su.is_subscribed and img.score and not img.is_flagged:
                    _sp = img.score * 10
                    award_points(_su, _sp, 'image_scored', commit=False)
                    _sc = Image.query.filter_by(user_id=_su.id, status='scored').count()
                    check_tier_jump_bonus(_su, img.tier, _sc, commit=False)
                    db.session.commit()
            except Exception as _spe:
                app.logger.error(f'[points hook] score_image error: {_spe}')
            try:
                _scored_total = Image.query.filter_by(
                    user_id=img.user_id, status='scored'
                ).count()
                if _scored_total == 1:
                    _ref_rec = db.session.execute(
                        db.text('SELECT id, referrer_id, points_reward_granted '
                                'FROM referrals WHERE referred_user_id = :uid'),
                        {'uid': img.user_id}
                    ).fetchone()
                    if _ref_rec and not _ref_rec[2]:
                        _referrer = User.query.get(_ref_rec[1])
                        if _referrer:
                            award_points(_referrer, 20, 'referral_first_image')
                        db.session.execute(
                            db.text('UPDATE referrals SET first_image_at = NOW() WHERE id = :rid'),
                            {'rid': _ref_rec[0]}
                        )
                        db.session.commit()
                        app.logger.info(f'[referral] +20pts: referrer={_ref_rec[1]} referred={img.user_id}')
            except Exception as _rse:
                app.logger.error(f'[referral] score hook: {_rse}')

            try:
                uid       = str(uuid.uuid4())
                card_fname = (f"LL_{date.today().strftime('%Y%m%d')}_"
                              f"{secure_filename((img.photographer_name or 'unknown').replace(' ',''))}_"
                              f"{img.genre}_{img.score}.jpg")
                card_path = os.path.join(app.config['UPLOAD_FOLDER'], 'cards', card_fname)
                build_card1(thumb_path, audit, card_path)
                img.card_path = card_path
                card_url = _r2_upload_card(card_path, uid + '_card')
                if card_url:
                    img.card_url = card_url
                db.session.commit()
            except Exception:
                app.logger.error(f'[retry_score_bg card error] {traceback.format_exc()}')

            app.logger.info(f'[retry_score_bg] image={image_id} scored -> {img.score:.2f} ({img.tier})')

        except Exception as e:
            db.session.rollback()
            img2 = Image.query.get(image_id)
            if img2:
                img2.status = 'error'
                db.session.commit()
            app.logger.error(f'[retry_score_bg] {traceback.format_exc()}')

        finally:
            if temp_file:
                try: os.unlink(temp_file)
                except: pass




@app.route('/image/<int:image_id>/upload-edit', methods=['GET', 'POST'])
@login_required
def upload_edited_version(image_id):
    """
    Upload an edited version of an existing scored image.
    - Linked to parent via parent_image_id
    - Scores normally, starts private (is_public=FALSE)
    - Leaderboard always uses highest-scoring version per parent group
    - Counts as a normal upload slot
    """
    parent = Image.query.get_or_404(image_id)

    # Walk up to find the root parent (handle chains: V1 -> V2 -> V3)
    # parent_image_id is a migration-only column — not in ORM model, read via SQL
    _pid_row = db.session.execute(
        db.text("SELECT parent_image_id FROM images WHERE id = :iid"),
        {'iid': parent.id}
    ).fetchone()
    _parent_image_id = _pid_row[0] if _pid_row else None
    root_id = _parent_image_id or parent.id
    root    = Image.query.get(root_id) if root_id != parent.id else parent

    # Only owner or admin
    if root.user_id != current_user.id and current_user.role != 'admin':
        abort(403)

    # Parent must be scored
    if parent.status != 'scored':
        flash('The original image must be scored before you can upload an edited version.', 'error')
        return redirect(url_for('image_detail', image_id=image_id))

    if request.method == 'POST':
        file = request.files.get('image')
        if not file or file.filename == '':
            flash('No file selected.', 'error')
            return redirect(request.url)
        if not allowed_file(file.filename):
            flash('File type not supported.', 'error')
            return redirect(request.url)

        # ── Edit version quota ──────────────────────────────────────────────
        # V2 (first edit) = FREE — no slot consumed
        # V3+ = costs 1 upload slot OR 10 points if balance available
        # Admin and UAT always free
        _plan = getattr(current_user, 'subscription_plan', None) or ''
        _edit_version_count = db.session.execute(
            db.text("SELECT COUNT(*) FROM images WHERE parent_image_id = :rid"),
            {'rid': root_id}
        ).scalar() or 0
        # _edit_version_count = number of existing edits (not counting the root)
        # 0 = this will be V2 (first edit) = free
        # 1+ = this will be V3+ = costs slot or points
        if current_user.role != 'admin' and _plan not in ('beta', 'uat') and _edit_version_count >= 1:
            from datetime import date as _date
            today   = _date.today()
            _track  = getattr(current_user, 'subscription_track', None) or ''
            _is_sub = getattr(current_user, 'is_subscribed', False)
            _pts_bal = round(getattr(current_user, 'points_balance', 0.0) or 0.0, 1)
            _EDIT_PTS_COST = 200

            # Try points redemption first if balance available
            if _pts_bal >= _EDIT_PTS_COST:
                try:
                    db.session.execute(
                        db.text("UPDATE users SET points_balance = points_balance - :cost WHERE id = :uid"),
                        {'cost': _EDIT_PTS_COST, 'uid': current_user.id}
                    )
                    db.session.commit()
                    app.logger.info(f'[upload_edit] V{_edit_version_count+2} redeemed {_EDIT_PTS_COST}pts user={current_user.id}')
                except Exception as _pe:
                    app.logger.error(f'[upload_edit] points deduct failed: {_pe}')
            elif not _is_sub:
                _lifetime = getattr(current_user, 'total_uploads_ever', None)
                if _lifetime is None:
                    _lifetime = Image.query.filter(Image.user_id == current_user.id).count()
                _bonus = getattr(current_user, 'referral_bonus_uploads', 0) or 0
                if _lifetime >= (FREE_IMAGE_LIMIT + _bonus):
                    flash('You have used your free assessments. Earn points by rating peers to unlock more edits (10 pts each).', 'warning')
                    return redirect(url_for('image_detail', image_id=image_id))
            elif _track in ('mobile', 'camera', 'learning'):
                month_start = datetime(today.year, today.month, 1)
                month_count = Image.query.filter(
                    Image.user_id == current_user.id,
                    Image.created_at >= month_start,
                ).count()
                limits = {'mobile': 8, 'camera': 5, 'learning': 12}
                if month_count >= limits.get(_track, 5):
                    if _pts_bal < _EDIT_PTS_COST:
                        flash(f'Monthly upload limit reached. Earn 10 points by rating peers to unlock this edit.', 'warning')
                        return redirect(url_for('image_detail', image_id=image_id))

        # ── Determine version number ──
        sibling_count = db.session.execute(
            db.text("SELECT COUNT(*) FROM images WHERE id = :rid OR parent_image_id = :rid"),
            {'rid': root_id}
        ).scalar() or 0
        version_num = sibling_count + 1

        # ── Ingest file ──
        uid        = str(uuid.uuid4())
        filename   = secure_filename(file.filename)
        raw_path   = os.path.join(app.config['UPLOAD_FOLDER'], 'raw', f"{uid}_{filename}")
        file.save(raw_path)
        # ── MPO format guard ────────────────────────────────────────────────────
        try:
            from PIL import Image as _PILImage
            with _PILImage.open(raw_path) as _pil_img:
                if getattr(_pil_img, 'format', '').upper() == 'MPO':
                    app.logger.info(f'[upload-edit] MPO detected — converting to JPEG: {raw_path}')
                    _pil_rgb = _pil_img.convert('RGB')
                    _jpeg_path = raw_path.rsplit('.', 1)[0] + '_converted.jpg'
                    _pil_rgb.save(_jpeg_path, 'JPEG', quality=95)
                    if os.path.exists(raw_path): os.remove(raw_path)
                    raw_path = _jpeg_path
        except Exception as _mpo_err:
            app.logger.warning(f'[upload-edit] MPO check failed (continuing): {_mpo_err}')
        try:
            thumb_path, w, h, fmt, phash = ingest_image(raw_path, app.config['UPLOAD_FOLDER'])
        except Exception as e:
            if os.path.exists(raw_path): os.remove(raw_path)
            flash(f'Image processing failed: {e}', 'error')
            return redirect(request.url)

        from engine.exif_check import extract_exif
        exif_status, exif_data, exif_warning = extract_exif(raw_path)
        if os.path.exists(raw_path): os.remove(raw_path)

        # Duplicate check against siblings only (not global — it IS the same photo)
        # No duplicate check for edited versions — they are intentionally similar to the original
        # Global duplicate check (cross-user 98%+ match) still applies via normal upload
        from engine.processor import hash_similarity_pct

        thumb_url = _r2_upload_thumb(thumb_path, uid)
        if not thumb_url:
            flash('Storage upload failed. Please try again.', 'error')
            return redirect(request.url)

        # ── Create image record — private by default ──
        img = Image(
            user_id           = current_user.id,
            original_filename = filename,
            stored_filename   = os.path.basename(thumb_path),
            thumb_path        = thumb_path,
            thumb_url         = thumb_url,
            file_size_kb      = int(os.path.getsize(thumb_path) / 1024),
            width=w, height=h, format=fmt,
            asset_name        = f"{root.asset_name or 'Untitled'} (V{version_num})",
            genre             = parent.genre,
            subject           = (parent.subject or '').split('] ', 1)[-1] if parent.subject and parent.subject.startswith('[') else (parent.subject or ''),
            location          = parent.location,
            conditions        = parent.conditions,
            photographer_name = parent.photographer_name,
            camera_track      = parent.camera_track,
            phash             = phash,
            status            = 'pending',
            is_public         = False,   # private until user chooses to publish
            # parent_image_id set via SQL after commit (migration-only column)
            exif_status=exif_status,
            exif_camera=(exif_data.get('camera', '') or '').replace('\x00', ''),
            exif_lens=(exif_data.get('lens', '') or '').replace('\x00', ''),
            exif_date_taken=(exif_data.get('date_taken', '') or '').replace('\x00', ''),
            exif_settings=('  .  '.join(filter(None, [
                exif_data.get('focal_length',''), exif_data.get('aperture',''),
                exif_data.get('iso',''), exif_data.get('shutter',''),
            ]))).replace('\x00', ''),
            exif_warning=(exif_warning or '').replace('\x00', ''),
        )
        # version_number set via SQL after flush (see below)

        db.session.add(img)
        db.session.flush()  # get img.id before commit

        # Set parent_image_id and version_number via SQL (migration-only columns)
        try:
            db.session.execute(
                db.text("UPDATE images SET parent_image_id = :pid, version_number = :vn WHERE id = :iid"),
                {'pid': root_id, 'vn': version_num, 'iid': img.id}
            )
        except Exception as _e:
            app.logger.warning(f'[upload_edit] parent_image_id set failed: {_e}')

        # Increment lifetime counter
        try:
            db.session.execute(
                db.text("UPDATE users SET total_uploads_ever = COALESCE(total_uploads_ever, 0) + 1 WHERE id = :uid"),
                {'uid': current_user.id}
            )
        except Exception:
            pass
        db.session.commit()

        # ── Background scoring ──
        api_key = os.getenv('ANTHROPIC_API_KEY', '')
        if api_key:
            img.status = 'processing'
            db.session.commit()

            def _score_edit(image_id_inner, uid_inner, root_id_inner):
                import traceback
                from engine.auto_score import auto_score, build_audit_data, build_exif_context
                from engine.compositor import build_card1
                with app.app_context():
                    try:
                        _img = Image.query.get(image_id_inner)
                        if not _img: return

                        # ── Build full context — parity with main scoring path ──────
                        # Previously this path called auto_score() cold (no portfolio,
                        # no parent delta, no EXIF, no seasonal) — causing Mahesh's
                        # "followed advice, score dropped" problem. Fixed Session 115.

                        # EXIF context
                        _edit_exif_ctx = build_exif_context(
                            {
                                'make': _img.exif_make, 'model': _img.exif_model,
                                'focal_length_35mm': _img.exif_focal_length_35mm,
                                'focal_length': _img.exif_settings,
                                'aperture': None, 'shutter': None, 'iso': None,
                                'lens': _img.exif_lens, 'software': _img.exif_software,
                                'has_gps': _img.exif_has_gps,
                            },
                            camera_track=_img.camera_track,
                        ) if (_img.exif_make or _img.exif_model or _img.exif_focal_length_35mm) else ''

                        # Portfolio context from history
                        _edit_portfolio = None
                        _edit_image_number = 1
                        try:
                            _edit_sc_count = db.session.query(Image).filter(
                                Image.user_id == _img.user_id,
                                Image.status  == 'scored',
                            ).count()
                            _edit_image_number = _edit_sc_count + 1
                            if _edit_sc_count >= 2:
                                _edit_recent = db.session.query(
                                    Image.aq_score, Image.dm_score, Image.dod_score
                                ).filter(
                                    Image.user_id == _img.user_id,
                                    Image.status  == 'scored',
                                    Image.genre   == _img.genre,
                                ).order_by(Image.scored_at.desc()).limit(8).all()
                                if _edit_recent:
                                    _edit_recent = list(reversed(_edit_recent))
                                    _edit_portfolio = {
                                        'feeling':    [r.aq_score  for r in _edit_recent if r.aq_score  is not None],
                                        'timing':     [r.dm_score  for r in _edit_recent if r.dm_score  is not None],
                                        'difficulty': [r.dod_score for r in _edit_recent if r.dod_score is not None],
                                    }
                        except Exception as _ep_err:
                            app.logger.warning(f'[upload_edit scoring] portfolio context error: {_ep_err}')
                            _edit_portfolio = None
                            _edit_image_number = 1

                        # Parent image audit + score as delta reference
                        _edit_prev_score = None
                        _edit_prev_audit = None
                        try:
                            _edit_parent = Image.query.get(root_id_inner)
                            if _edit_parent and _edit_parent.status == 'scored' and _edit_parent.score:
                                _edit_prev_score = float(_edit_parent.score)
                                _edit_prev_audit = _edit_parent.get_audit() or None
                        except Exception as _ed_err:
                            app.logger.warning(f'[upload_edit scoring] parent delta error: {_ed_err}')

                        # Seasonal context
                        _edit_seasonal_ctx = ''
                        try:
                            from engine.seasonal_calendar import build_seasonal_context, get_primary_genre
                            _edit_u = User.query.get(_img.user_id)
                            _edit_primary_genre = get_primary_genre(_edit_u) if _edit_u else (_img.genre or '')
                            _edit_user_city = getattr(_edit_u, 'city', '') or '' if _edit_u else ''
                            _edit_seasonal_ctx, _ = build_seasonal_context(
                                db_session    = db.session,
                                user_city     = _edit_user_city,
                                primary_genre = _edit_primary_genre or _img.genre or '',
                                current_month = datetime.utcnow().month,
                                user_id       = _img.user_id,
                            )
                        except Exception as _es_err:
                            app.logger.warning(f'[upload_edit scoring] seasonal context error: {_es_err}')
                            _edit_seasonal_ctx = ''

                        result = auto_score(
                            image_path=_img.thumb_path, genre=_img.genre,
                            title=_img.asset_name, photographer=_img.photographer_name,
                            subject=_img.subject, location=_img.location,
                            exif_context      = _edit_exif_ctx,
                            seasonal_context  = _edit_seasonal_ctx,
                            portfolio_summary = _edit_portfolio,
                            image_number      = _edit_image_number,
                            previous_score    = _edit_prev_score,
                            previous_audit    = _edit_prev_audit,
                        )
                        _img.dod_score        = float(result.get('dod', 0))
                        _img.disruption_score = float(result.get('disruption', 0))
                        _img.dm_score         = float(result.get('dm', 0))
                        _img.wonder_score     = float(result.get('wonder', 0))
                        _img.aq_score         = float(result.get('aq', 0))
                        _img.score            = float(result.get('score', 0))
                        _img.tier             = get_tier(float(result.get('score', 0)))
                        _img.archetype        = result.get('archetype', '')
                        _img.soul_bonus       = result.get('soul_bonus', False)
                        _img.status           = 'scored'
                        _img.scored_at        = datetime.utcnow()
                        audit = build_audit_data(result, _img)
                        _img.set_audit(audit)
                        db.session.commit()

                        # Award points for subscribed users
                        try:
                            _u = User.query.get(_img.user_id)
                            if _u and _u.is_subscribed and _img.score and not _img.is_flagged:
                                award_points(_u, _img.score * 10, 'image_scored', commit=False)
                                _cnt = Image.query.filter_by(user_id=_u.id, status='scored').count()
                                check_tier_jump_bonus(_u, _img.tier, _cnt, commit=False)
                                db.session.commit()
                        except Exception:
                            pass

                        # Build scorecard
                        try:
                            card_fname = (f"LL_{date.today().strftime('%Y%m%d')}_"
                                          f"{secure_filename((_img.photographer_name or 'unknown').replace(' ',''))}_"
                                          f"{_img.genre}_{_img.score}.jpg")
                            card_path = os.path.join(app.config['UPLOAD_FOLDER'], 'cards', card_fname)
                            build_card1(_img.thumb_path, audit, card_path)
                            _img.card_path = card_path
                            card_url = _r2_upload_card(card_path, uid_inner + '_card')
                            if card_url: _img.card_url = card_url
                            db.session.commit()
                        except Exception:
                            pass

                    except Exception as e:
                        app.logger.error(f'[upload_edit scoring] {traceback.format_exc()}')
                        try:
                            _img = Image.query.get(image_id_inner)
                            if _img and _img.status == 'processing':
                                _img.status = 'error'
                                db.session.commit()
                        except Exception:
                            pass

            threading.Thread(
                target=_score_edit,
                args=(img.id, uid, root_id),
                daemon=True
            ).start()

        if request.headers.get('X-Requested-With') == 'XMLHttpRequest' or request.form.get('_xhr') == '1':
            return jsonify({'status': 'processing', 'image_id': img.id})

        # Redirect to dashboard with scoring param — dashboard shows live scoring widget
        return redirect(url_for('dashboard') + f'?scoring={img.id}&v={version_num}')

    # GET — render the upload form
    # Fetch all existing versions for display
    _ver_ids = db.session.execute(
        db.text("SELECT id FROM images WHERE id = :rid OR parent_image_id = :rid ORDER BY id ASC"),
        {'rid': root_id}
    ).fetchall()
    versions = [Image.query.get(r[0]) for r in _ver_ids if Image.query.get(r[0])]

    # Read points balance fresh from DB — ORM attribute may be stale
    try:
        _pts_row = db.session.execute(
            db.text("SELECT points_balance FROM users WHERE id = :uid"),
            {'uid': current_user.id}
        ).fetchone()
        _pts_bal = round(float(_pts_row[0] or 0), 1) if _pts_row else 0.0
    except Exception:
        _pts_bal = round(getattr(current_user, 'points_balance', 0.0) or 0.0, 1)
    _existing_edits = len(versions) - 1  # subtract root, count edits only
    _is_sub         = getattr(current_user, 'is_subscribed', False)
    _track          = getattr(current_user, 'subscription_track', None) or ''
    _EDIT_PTS_COST  = 200
    # Check monthly slot availability for subscribed users
    _slots_ok = True
    if _is_sub and _track in ('mobile', 'camera', 'learning') and _pts_bal < _EDIT_PTS_COST:
        from datetime import date as _date
        _month_start = datetime(_date.today().year, _date.today().month, 1)
        _month_count = Image.query.filter(
            Image.user_id == current_user.id,
            Image.created_at >= _month_start,
        ).count()
        _limits = {'mobile': 8, 'camera': 5, 'learning': 12}
        _slots_ok = _month_count < _limits.get(_track, 5)
    # Free tier slot check
    _free_slots_ok = True
    if not _is_sub and _pts_bal < _EDIT_PTS_COST:
        _lifetime = getattr(current_user, 'total_uploads_ever', None) or 0
        _bonus    = getattr(current_user, 'referral_bonus_uploads', 0) or 0
        _free_slots_ok = _lifetime < (FREE_IMAGE_LIMIT + _bonus)
    _can_upload = _pts_bal >= _EDIT_PTS_COST or _slots_ok or _free_slots_ok

    return render_template('upload_edited.html',
                           parent=parent, root=root,
                           versions=versions,
                           version_num=len(versions) + 1,
                           existing_edits=_existing_edits,
                           points_balance=_pts_bal,
                           edit_pts_cost=_EDIT_PTS_COST,
                           can_upload=_can_upload,
                           slots_ok=_slots_ok and _free_slots_ok)



def _ensure_share_token(img):
    """
    Idempotent — generates and saves a share_token on `img` if one doesn't
    exist yet. Call this after scoring is confirmed, before returning.
    Returns the token string.
    """
    try:
        existing = db.session.execute(
            db.text("SELECT share_token FROM images WHERE id = :id"),
            {'id': img.id}
        ).fetchone()
        if existing and existing[0]:
            return existing[0]
        token = uuid.uuid4().hex  # 32-char hex, URL-safe, no ambiguous chars
        db.session.execute(
            db.text("UPDATE images SET share_token = :tok WHERE id = :id"),
            {'tok': token, 'id': img.id}
        )
        db.session.commit()
        return token
    except Exception as _te:
        app.logger.warning(f'[share_token] {_te}')
        return None


@app.route('/card/<token>')
def public_card(token):
    """
    Public share page for a scored evaluation card.
    No login required — the token is the access key.
    Shows the full scorecard: photo, score, evaluation detail, trend sparklines,
    dimension breakdown, and a download button for the card JPG (which carries
    the Shutter League logo via build_card1).
    """
    if not token or len(token) < 8:
        abort(404)

    row = db.session.execute(
        db.text("SELECT id FROM images WHERE share_token = :tok AND status = 'scored'"),
        {'tok': token}
    ).fetchone()
    if not row:
        abort(404)

    img = Image.query.get_or_404(row[0])
    if getattr(img, 'is_flagged', False):
        abort(404)

    # ── Trend / sparkline data (same logic as image_detail, but using the
    #    image OWNER's history — no auth check needed, token is the gate) ──
    _portfolio_data = None
    _stats          = None
    _owner_id       = img.user_id
    _now            = datetime.utcnow()

    try:
        _scored_count = db.session.query(Image).filter(
            Image.user_id == _owner_id,
            Image.status  == 'scored',
        ).count()

        if _scored_count >= 5:
            _recent = db.session.query(
                Image.aq_score, Image.dm_score, Image.dod_score, Image.score
            ).filter(
                Image.user_id == _owner_id,
                Image.status  == 'scored',
            ).order_by(Image.scored_at.desc()).limit(30).all()

            if _recent and len(_recent) >= 2:
                _recent = list(reversed(_recent))

                def _spark(values, height=30):
                    if not values or len(values) < 2:
                        return "", []
                    mn, mx = min(values), max(values)
                    rng = mx - mn if mx != mn else 1.0
                    w_step = 300 / (len(values) - 1)
                    pts = []
                    for i, v in enumerate(values):
                        x = round(i * w_step, 1)
                        y = round(height - ((v - mn) / rng) * (height - 2) - 1, 1)
                        pts.append({'x': x, 'y': y})
                    polyline = ' '.join(f"{p['x']},{p['y']}" for p in pts)
                    return polyline, pts

                def _trend_pill(values):
                    if len(values) < 3:
                        return None, None, None
                    first  = sum(values[:len(values)//2]) / (len(values)//2)
                    second = sum(values[len(values)//2:]) / (len(values) - len(values)//2)
                    diff   = second - first
                    if diff > 0.3:
                        return '↑ Climbing — getting stronger', '#27500A', '#EAF5EE'
                    if diff < -0.3:
                        return '↓ Dipped recently', '#72243E', '#F5EAF0'
                    return '— Steady — your next opportunity to grow', '#854F0B', '#FDF6E3'

                def _label_subset(vals, pts, max_labels=8):
                    n = len(vals)
                    if n <= max_labels:
                        idxs = list(range(n))
                    else:
                        step = (n - 1) / (max_labels - 1)
                        idxs = sorted(set(round(i * step) for i in range(max_labels)))
                    return [{'x_pct': round(pts[i]['x'] / 300 * 100, 1),
                             'value': round(vals[i], 1)} for i in idxs]

                _feeling    = [r.aq_score  for r in _recent if r.aq_score  is not None]
                _timing     = [r.dm_score  for r in _recent if r.dm_score  is not None]
                _difficulty = [r.dod_score for r in _recent if r.dod_score is not None]

                _dims = []
                for _lbl, _vals, _color, _flat_color in [
                    ('Whether it made one feel something', _feeling,    '#F5C518', '#BA7517'),
                    ('Whether the timing was right',       _timing,     '#2C3E6B', '#2C3E6B'),
                    ('How difficult it was',               _difficulty, '#BA7517', '#BA7517'),
                ]:
                    if len(_vals) >= 2:
                        _sp, _pts  = _spark(_vals)
                        _pill, _pc, _pb = _trend_pill(_vals)
                        _is_flat   = abs(max(_vals) - min(_vals)) < 0.5
                        _dims.append({
                            'label':        _lbl,
                            'current':      _vals[-1],
                            'score_values': [round(v, 1) for v in _vals],
                            'label_points': _label_subset(_vals, _pts),
                            'sparkline':    _sp,
                            'points':       _pts,
                            'color':        _flat_color if _is_flat else _color,
                            'flat':         _is_flat,
                            'pill':         _pill,
                            'pill_color':   _pc,
                            'pill_bg':      _pb,
                        })

                _portfolio_data = {
                    'has_trends':    bool(_dims),
                    'count':         _scored_count,
                    'plotted_count': len(_recent),
                    'dimensions':    _dims,
                }
            else:
                _portfolio_data = {'has_trends': False, 'count': _scored_count}
        else:
            _portfolio_data = {'has_trends': False, 'count': _scored_count}
    except Exception as _pe:
        app.logger.warning(f'[public_card] portfolio_data: {_pe}')
        _portfolio_data = {'has_trends': False, 'count': 0}

    try:
        _year_start  = datetime(_now.year, 1, 1)
        _month_start = datetime(_now.year, _now.month, 1)
        _year_imgs = db.session.query(Image).filter(
            Image.user_id  == _owner_id,
            Image.status   == 'scored',
            Image.scored_at >= _year_start,
        ).all()
        _month_imgs = [i for i in _year_imgs if i.scored_at and i.scored_at >= _month_start]
        _best_year  = max((i.score for i in _year_imgs if i.score), default=None)
        _best_img   = next((i for i in _year_imgs if i.score == _best_year), None)
        _month_avg  = (sum(i.score for i in _month_imgs if i.score) / len(_month_imgs)
                       if _month_imgs else None)
        _stats = {
            'best_this_year':  _best_year,
            'best_genre':      _best_img.genre if _best_img else None,
            'best_title':      _best_img.asset_name if _best_img else None,
            'month_avg':       round(_month_avg, 2) if _month_avg else None,
            'month_count':     len(_month_imgs),
        }
    except Exception as _se:
        app.logger.warning(f'[public_card] stats: {_se}')
        _stats = None

    # ── Parse audit JSON and pre-compute all card display values in Python ──
    # This approach mirrors how build_audit_data() assembles the data server-side.
    # Never rely on Jinja2 namespace() objects or conditional dict access for this
    # — subtle scoping issues produce empty strings silently in the template.
    _audit = img.get_audit() or {}

    # What Stood Out — new schema field first, fall back to old hard_truth
    _wso = (_audit.get('what_stood_out') or '').strip() or (_audit.get('hard_truth') or '').strip()

    # Card bodies — mirror image_detail.html resolution logic exactly
    # Extract rows tuples: [("Technical", val), ("Moment", val), ("Next", val)]
    _rows = _audit.get('rows') or []
    _tech_val = ''
    _mom_val  = ''
    _next_val = ''
    for _row in _rows:
        if _row and len(_row) >= 2:
            if _row[0] == 'Technical': _tech_val = _row[1] or ''
            if _row[0] == 'Moment':    _mom_val  = _row[1] or ''
            if _row[0] == 'Next':      _next_val = _row[1] or ''

    # Card 1 — The Photographer's Advice
    _c1 = ((_audit.get('transferable_advice') or '').strip()
           or _tech_val.strip())

    # Card 2 — What You Controlled
    _c2 = ''
    if (_audit.get('transferable_advice') or '').strip():
        _c2 = (_tech_val.strip() or _mom_val.strip())
    else:
        _c2 = _mom_val.strip()

    # Card 3 — What To Watch Next
    _bgcheck = ((_audit.get('background_check') or '').strip()
                or (_audit.get('byline_1') or '').strip())
    _c3 = _bgcheck or _next_val.strip()

    # Card 4 — Keep This In Mind
    _c4 = ((_audit.get('byline_2_body') or '').strip()
           or (_audit.get('byline_2') or '').strip())

    # Edit guide
    _edit_base     = (_audit.get('edit_base') or '').strip()
    _edit_creative = (_audit.get('edit_creative') or '').strip()

    # Dimension breakdown — from model attributes, not audit JSON
    _dim_breakdown = []
    for _dattr, _dl1, _dl2 in [
        ('dod_score',        'How Difficult', 'It Was'),
        ('disruption_score', 'Visual',        'Disruption'),
        ('dm_score',         'Timing',        'Was Right'),
        ('wonder_score',     'Makes You',     'Feel'),
        ('aq_score',         'Emotion',       'It Creates'),
    ]:
        _dval = getattr(img, _dattr, None)
        if _dval is not None:
            _dim_breakdown.append({'score': _dval, 'l1': _dl1, 'l2': _dl2})

    return render_template(
        'card_public.html',
        image          = img,
        portfolio_data = _portfolio_data,
        stats          = _stats,
        share_token    = token,
        dim_breakdown  = _dim_breakdown,
        platform_name  = PLATFORM_NAME,
        # Pre-computed evaluation display values — all plain strings
        wso            = _wso,
        c1_body        = _c1,
        c2_body        = _c2,
        c3_body        = _c3,
        c4_body        = _c4,
        edit_base      = _edit_base,
        edit_creative  = _edit_creative,
    )


@app.route('/card/<token>/download')
def public_card_download(token):
    """
    Serves the card JPG as a direct browser download from the share token URL.
    The card JPG (built by build_card1) already carries the Shutter League logo
    and photographer watermark, so no separate PDF generation is needed.
    """
    row = db.session.execute(
        db.text("SELECT id FROM images WHERE share_token = :tok AND status = 'scored'"),
        {'tok': token}
    ).fetchone()
    if not row:
        abort(404)
    img = Image.query.get_or_404(row[0])
    if getattr(img, 'is_flagged', False):
        abort(404)

    # Prefer the local card_path (Railway ephemeral storage); fall back to
    # the R2 public URL with a redirect.
    if img.card_path and os.path.exists(img.card_path):
        fname = f"SL_Evaluation_{(img.asset_name or 'card').replace(' ', '_')}.jpg"
        return send_file(img.card_path, as_attachment=True, download_name=fname)
    if img.card_url:
        return redirect(img.card_url)
    abort(404)


@app.route('/image/<int:image_id>')
def image_detail(image_id):
    img = Image.query.get_or_404(image_id)
    # Public scored images are viewable by anyone
    # Private images require login and ownership
    if not getattr(img, 'is_public', False):
        if not current_user.is_authenticated:
            return redirect(url_for('login', next=request.url))
        if img.user_id != current_user.id and current_user.role != 'admin':
            abort(403)
    percentile_data = {}
    if img.status == 'scored' and img.score and not getattr(img, 'is_flagged', False):
        try:
            from engine.scoring import compute_percentile
            percentile_data = compute_percentile(float(img.score), genre=img.genre)
        except Exception as e:
            app.logger.warning(f'[percentile] {e}')
    # Fetch all versions of this image (siblings sharing same root)
    _versions = []
    _parent_img_id = None
    try:
        _pid_row = db.session.execute(
            db.text("SELECT parent_image_id FROM images WHERE id = :iid"),
            {'iid': img.id}
        ).fetchone()
        _parent_img_id = _pid_row[0] if _pid_row else None
        _root_id = _parent_img_id or img.id
        _ver_rows = db.session.execute(
            db.text("SELECT id FROM images WHERE id = :rid OR parent_image_id = :rid ORDER BY id ASC"),
            {'rid': _root_id}
        ).fetchall()
        _versions = [Image.query.get(r[0]) for r in _ver_rows if Image.query.get(r[0])]
    except Exception as _ve:
        app.logger.warning(f'[image_detail] versions fetch: {_ve}')

    # ── Sprint 3 — scorecard context ─────────────────────────────────────────
    _portfolio_data = None
    _stats          = None
    _now            = datetime.utcnow()

    if current_user.is_authenticated and img.status == 'scored' and (
        img.user_id == current_user.id or current_user.role == 'admin'
    ):
        _owner_id = img.user_id  # use the image OWNER's id, not the viewer's —
                                  # so admins see the same trend/stats the photographer sees
        try:
            # ── Portfolio trend data (unlocks at 5+ photographs) ─────────────
            _scored_count = db.session.query(Image).filter(
                Image.user_id == _owner_id,
                Image.status  == 'scored',
            ).count()

            if _scored_count >= 5:
                # Pull up to the last 30 scored photographs across ALL
                # genres for trend lines. This used to filter to the
                # current photo's genre first, falling back to all genres
                # only when fewer than 2 same-genre results existed — which
                # meant a photographer with 6 total scored photos but only
                # 2 in this specific genre saw a near-meaningless 2-point
                # trend even though 6 data points were sitting right there.
                # Trends are about overall trajectory across everything you
                # shoot, not a single genre, so this is genre-agnostic by
                # design now, with a much longer lookback (30 vs 8) so it
                # actually tracks "where am I going" rather than just the
                # last handful of uploads.
                _recent = db.session.query(
                    Image.aq_score, Image.dm_score, Image.dod_score, Image.score
                ).filter(
                    Image.user_id == _owner_id,
                    Image.status  == 'scored',
                ).order_by(Image.scored_at.desc()).limit(30).all()

                if _recent and len(_recent) >= 2:
                    _recent = list(reversed(_recent))  # oldest first

                    def _spark(values, height=30):
                        """Convert list of floats to SVG polyline points string."""
                        if not values or len(values) < 2:
                            return "", []
                        mn, mx = min(values), max(values)
                        rng = mx - mn if mx != mn else 1.0
                        w_step = 300 / (len(values) - 1)
                        pts = []
                        for i, v in enumerate(values):
                            x = round(i * w_step, 1)
                            y = round(height - ((v - mn) / rng) * (height - 2) - 1, 1)
                            pts.append({'x': x, 'y': y})
                        polyline = ' '.join(f"{p['x']},{p['y']}" for p in pts)
                        return polyline, pts

                    def _trend_pill(values):
                        """Return pill text, color, bg for a dimension."""
                        if len(values) < 3:
                            return None, None, None
                        first = sum(values[:len(values)//2]) / (len(values)//2)
                        second = sum(values[len(values)//2:]) / (len(values) - len(values)//2)
                        diff = second - first
                        if diff > 0.3:
                            return '↑ Climbing — getting stronger', '#27500A', '#EAF5EE'
                        if diff < -0.3:
                            return '↓ Dipped recently', '#72243E', '#F5EAF0'
                        return '— Steady — your next opportunity to grow', '#854F0B', '#FDF6E3'

                    _feeling    = [r.aq_score  for r in _recent if r.aq_score  is not None]
                    _timing     = [r.dm_score  for r in _recent if r.dm_score  is not None]
                    _difficulty = [r.dod_score for r in _recent if r.dod_score is not None]

                    def _label_subset(vals, pts, max_labels=8):
                        """Pick values to label under the sparkline, positioned
                        to align with their actual x-coordinate on the SVG so
                        labels sit directly under their dot. Showing every
                        value works fine up to max_labels points (covers
                        nearly every real case today) but becomes an
                        unreadable wall of numbers as the trend lookback
                        grows toward 30, so beyond that this samples evenly
                        across the range -- always including the first and
                        last -- instead of dropping to just two endpoints.
                        """
                        n = len(vals)
                        if n <= max_labels:
                            idxs = list(range(n))
                        else:
                            step = (n - 1) / (max_labels - 1)
                            idxs = sorted(set(round(i * step) for i in range(max_labels)))
                        return [{'x_pct': round(pts[i]['x'] / 300 * 100, 1),
                                 'value': round(vals[i], 1)} for i in idxs]

                    _dims = []
                    for _label, _vals, _color, _flat_color in [
                        ('Whether it made one feel something', _feeling,    '#F5C518', '#BA7517'),
                        ('Whether the timing was right',       _timing,     '#2C3E6B', '#2C3E6B'),
                        ('How difficult it was',               _difficulty, '#BA7517', '#BA7517'),
                    ]:
                        if len(_vals) >= 2:
                            _sp, _pts = _spark(_vals)
                            _pill, _pcol, _pbg = _trend_pill(_vals)
                            _is_flat = abs(max(_vals) - min(_vals)) < 0.5
                            _dims.append({
                                'label':      _label,
                                'current':    _vals[-1],
                                'score_values': [round(v, 1) for v in _vals],
                                'label_points': _label_subset(_vals, _pts),
                                'sparkline':  _sp,
                                'points':     _pts,
                                'color':      _flat_color if _is_flat else _color,
                                'flat':       _is_flat,
                                'pill':       _pill,
                                'pill_color': _pcol,
                                'pill_bg':    _pbg,
                            })

                    _portfolio_data = {
                        'has_trends':     bool(_dims),
                        'count':          _scored_count,
                        'plotted_count':  len(_recent),
                        'dimensions':     _dims,
                    }
                else:
                    _portfolio_data = {'has_trends': False, 'count': _scored_count}
            else:
                _portfolio_data = {'has_trends': False, 'count': _scored_count}

        except Exception as _pe:
            app.logger.warning(f'[image_detail] portfolio_data: {_pe}')
            _portfolio_data = {'has_trends': False, 'count': 0}

        try:
            # ── 2025 stats ────────────────────────────────────────────────────
            _year_start = datetime(_now.year, 1, 1)
            _month_start = datetime(_now.year, _now.month, 1)

            _best_row = db.session.query(
                Image.score, Image.asset_name, Image.genre
            ).filter(
                Image.user_id   == _owner_id,
                Image.status    == 'scored',
                Image.scored_at >= _year_start,
                Image.score     != None,
            ).order_by(Image.score.desc()).first()

            _month_count = db.session.query(Image).filter(
                Image.user_id   == _owner_id,
                Image.status    == 'scored',
                Image.scored_at >= _month_start,
            ).count()

            _stats = {
                'best_this_year':  _best_row.score     if _best_row else None,
                'best_title':      _best_row.asset_name if _best_row else None,
                'best_genre':      _best_row.genre      if _best_row else None,
                'this_month_count': _month_count,
            }
        except Exception as _se:
            app.logger.warning(f'[image_detail] stats: {_se}')
            _stats = {}

    # ── Weekly challenge ──────────────────────────────────────────────────────
    _challenge = None
    try:
        _challenge = _get_active_challenge()
    except Exception:
        pass

    # ── Location advisory link(s) — "go here" for the seasonal advisory ────────
    # Uses the calendar IDs stored on THIS image at scoring time, not a fresh
    # city/genre/month lookup, so the link always matches what mentor_location_1/2
    # actually describes (rotation logic could otherwise select a different row).
    _location_links = []
    try:
        _sc_ids_csv = getattr(img, 'seasonal_calendar_ids_shown', None)
        if _sc_ids_csv:
            from engine.seasonal_calendar import get_location_links
            _sc_ids = [int(x) for x in _sc_ids_csv.split(',') if x.strip().isdigit()]
            _location_links = get_location_links(db.session, _sc_ids)
    except Exception as _lle:
        app.logger.warning(f'[image_detail] location_links: {_lle}')

    # ── First-eval full access — every free user's very first evaluated     ──
    # ── image shows the full scorecard (dimension scores, mission block,     ──
    # ── location advisory) even without a subscription. This is deliberately ──
    # ── ONE moment, not all 3 free evaluations — it demonstrates full value  ──
    # ── once, then the normal subscriber gate applies again. See image_detail──
    # ── .html "SUBSCRIBER GATE" for where this is consumed. ──────────────────
    _is_first_eval = False
    try:
        if (img.status == 'scored' and current_user.is_authenticated
                and img.user_id == current_user.id):
            _owner_scored_count = db.session.query(Image).filter(
                Image.user_id == img.user_id, Image.status == 'scored'
            ).count()
            _is_first_eval = (_owner_scored_count == 1)
    except Exception as _fee:
        app.logger.warning(f'[image_detail] first_eval check: {_fee}')

    # ── P8: Dimension reasoning drawer gate — reactivate when >50 images have dod_reasoning ──
    _drawer_active = False
    try:
        _drawer_count = db.session.execute(db.text(
            "SELECT COUNT(*) FROM images WHERE audit_json LIKE '%dod_reasoning%' AND status='scored'"
        )).scalar() or 0
        _drawer_active = (_drawer_count > 50)
    except Exception as _dge:
        db.session.rollback()
        app.logger.warning(f'[image_detail] drawer gate: {_dge}')

    # ── Pending peer eval check — show nudge only when user has work waiting ──
    _has_pending_eval = False
    try:
        if current_user.is_authenticated and getattr(current_user, 'is_subscribed', False):
            _has_pending_eval = db.session.query(RatingAssignment).filter(
                RatingAssignment.rater_id == current_user.id,
                RatingAssignment.status == 'started'
            ).first() is not None
    except Exception as _hpe:
        app.logger.warning(f'[image_detail] pending eval check: {_hpe}')

    return render_template('image_detail.html', image=img, archetypes=ARCHETYPES,
                           percentile=percentile_data,
                           image_versions=_versions,
                           parent_image_id=_parent_img_id,
                           portfolio_data=_portfolio_data,
                           stats=_stats,
                           weekly_challenge=_challenge,
                           location_links=_location_links,
                           is_first_eval=_is_first_eval,
                           all_masters=ALL_MASTERS,
                           drawer_active=_drawer_active,
                           has_pending_eval=_has_pending_eval,
                           now=_now)


@app.route('/image/<int:image_id>/score', methods=['POST'])
@login_required
def score_image(image_id):
    img = Image.query.get_or_404(image_id)
    if img.user_id != current_user.id and current_user.role != 'admin':
        abort(403)
    try:
        dod=float(request.form.get('dod',0))
        disruption=float(request.form.get('disruption',0))
        dm=float(request.form.get('dm',0))
        wonder=float(request.form.get('wonder',0))
        aq=float(request.form.get('aq',0))
        archetype=request.form.get('archetype','Sovereign Momentum')
        byline_1=request.form.get('byline_1','')
        byline_2=request.form.get('byline_2','')
        iucn_tag=request.form.get('iucn_tag','')
        final_score, tier, soul_bonus, checks = calculate_score(img.genre, dod, disruption, dm, wonder, aq)
        img.dod_score=dod; img.disruption_score=disruption; img.dm_score=dm
        img.wonder_score=wonder; img.aq_score=aq; img.score=final_score
        img.tier=tier; img.archetype=archetype; img.soul_bonus=soul_bonus
        img.status='scored'; img.scored_at=datetime.utcnow()
        audit = {
            'asset': img.asset_name,
            'meta': f"{img.genre}  .  {img.format}  .  {img.subject}  .  {img.location}",
            'score': str(final_score), 'tier': tier, 'dec': archetype,
            'credit': img.photographer_name,
            'genre_tag': f"{img.genre.upper()}  .  {img.format}",
            'soul_bonus': soul_bonus, 'iucn_tag': iucn_tag or None,
            'modules': [('DoD',dod),('VD',disruption),('DM',dm),('WF',wonder),('AQ',aq)],
            'rows': [
                ('Depth of\nDifficulty', request.form.get('row_technical','')),
                ('Visual\nDisruption',   request.form.get('row_geometric','')),
                ('Decisive\nMoment',     request.form.get('row_dm','')),
                ('Wonder\nFactor',       request.form.get('row_wonder','')),
                ('AQ  -  Soul',            request.form.get('row_aq','')),
            ],
            'byline_1': byline_1, 'byline_2_body': byline_2,
            'badges_g': request.form.get('badges_g','').splitlines(),
            'badges_w': request.form.get('badges_w','').splitlines(),
        }
        img.set_audit(audit)

        from engine.compositor import build_card1 as build_card
        uid = str(uuid.uuid4())
        card_fname = (f"LL_{date.today().strftime('%Y%m%d')}_"
                      f"{secure_filename((img.photographer_name or 'unknown').replace(' ',''))}_"
                      f"{img.genre}_{final_score}.jpg")
        card_path = os.path.join(app.config['UPLOAD_FOLDER'], 'cards', card_fname)
        build_card(img.thumb_path, audit, card_path)
        img.card_path = card_path

        card_url = _r2_upload_card(card_path, uid + '_card')
        if card_url:
            img.card_url = card_url

        db.session.commit()
        flash(f'Scored! LL-Score: {final_score}  -  {tier}', 'success')
    except Exception as e:
        flash(f'Scoring error: {e}', 'error')
    return redirect(url_for('image_detail', image_id=image_id))


@app.route('/image/<int:image_id>/download')
@login_required
def download_card(image_id):
    img = Image.query.get_or_404(image_id)
    if not img.score:
        return "This image has not been scored yet.", 404

    # Free tier gate — per investor doc, free users get score + tier only.
    # Full evaluation PDF (Hard Truth, Gap Analysis, Edit Guide, mentor fields)
    # is a subscriber-only feature. This is the primary conversion hook.
    _is_sub = getattr(current_user, 'is_subscribed', False)
    _is_owner = (img.user_id == current_user.id)
    _is_admin = (current_user.role == 'admin')
    if _is_owner and not _is_sub and not _is_admin:
        flash(
            'The full evaluation PDF is available to subscribers. '
            'Subscribe to Camera or Mobile League to download your complete analysis.',
            'info'
        )
        return redirect(url_for('pricing'))

    import io, tempfile, os as _os
    from engine.compositor import build_card1, build_card2

    audit = img.get_audit() or {}
    app.logger.info(f'[download] img={image_id} audit_keys={list(audit.keys())}')
    modules = [(n,v) for n,v in [
        ('DoD', img.dod_score),
        ('VD',  img.disruption_score),
        ('DM',  img.dm_score),
        ('WF',  img.wonder_score),
        ('AQ',  img.aq_score),
    ] if v and float(v) > 0]

    card_data = {
        'score':         img.score,
        'tier':          img.tier or '',
        'asset':         img.asset_name or img.original_filename or 'Untitled',
        'meta':          '  .  '.join(filter(None,[img.genre,img.format,img.location])),
        'dec':           img.archetype or '',
        'credit':        img.photographer_name or '',
        'soul_bonus':    bool(img.soul_bonus),
        'iucn_tag':      audit.get('iucn_tag',''),
        'modules':       modules,
        'rows':          audit.get('rows',[]),
        'byline_1':      audit.get('byline_1',''),
        'byline_2_body': audit.get('byline_2_body','') or audit.get('byline_2',''),
        'badges_g':      audit.get('badges_g',[]),
        'badges_w':      audit.get('badges_w',[]),
        'hard_truth':          audit.get('hard_truth',''),
        'edit_base':           audit.get('edit_base',''),
        'edit_creative':       audit.get('edit_creative',''),
        'what_stood_out':      audit.get('what_stood_out',''),
        'transferable_advice': audit.get('transferable_advice',''),
        'background_check':    audit.get('background_check',''),
        'mentor_location_1':   audit.get('mentor_location_1',''),
        'mentor_location_2':   audit.get('mentor_location_2',''),
        'mentor_location_3':   audit.get('mentor_location_3',''),
        'days_since_language': audit.get('days_since_language',''),
        'genre_tag':           audit.get('genre_tag',''),
        'composition_technique': audit.get('composition_technique',''),
    }

    photo_tmp  = None
    photo_path = img.thumb_path if (img.thumb_path and _os.path.exists(img.thumb_path)) else None
    if not photo_path and img.thumb_url:
        try:
            from storage import get_client, BUCKET
            tf = tempfile.NamedTemporaryFile(suffix='.jpg', delete=False)
            get_client().download_fileobj(BUCKET, 'thumbs/'+img.thumb_url.split('/thumbs/')[-1], tf)
            tf.close()
            photo_path = photo_tmp = tf.name
        except Exception as e:
            app.logger.warning(f'Thumb fetch failed: {e}')

    try:
        t1 = tempfile.NamedTemporaryFile(suffix='.jpg', delete=False)
        t2 = tempfile.NamedTemporaryFile(suffix='.jpg', delete=False)
        t1.close(); t2.close()

        # Run compositor in a thread with a hard timeout so a slow build
        # never pins the gunicorn sync worker and triggers maintenance mode.
        _build_exc = [None]
        def _run_build():
            try:
                build_card1(photo_path, card_data, t1.name)
                build_card2(card_data, t2.name)
            except Exception as _be:
                _build_exc[0] = _be

        _bt = threading.Thread(target=_run_build, daemon=True)
        _bt.start()
        _bt.join(timeout=55)
        if _bt.is_alive():
            app.logger.error(f'[download] build timeout img={image_id}')
            return Response('PDF generation timed out. Please try again.', status=503,
                            mimetype='text/plain')
        if _build_exc[0]:
            raise _build_exc[0]

        import re as _re
        raw = img.asset_name or 'card'
        clean = _re.sub(r'(?i)screenshot[\d._\-atATPM ]+','',raw).strip('_- ') or 'RatingCard'
        clean = clean[:40].replace(' ','_')

        # Build 2-page PDF (page 1 = score card, page 2 = analysis)
        from PIL import Image as _PILImg
        pg1 = _PILImg.open(t1.name).convert('RGB')
        pg2 = _PILImg.open(t2.name).convert('RGB')
        pdf_buf = io.BytesIO()
        pg1.save(pdf_buf, format='PDF', save_all=True, append_images=[pg2], resolution=150)
        pdf_bytes = pdf_buf.getvalue()

    finally:
        for p in [t1.name if t1 else None, t2.name if t2 else None, photo_tmp]:
            try:
                if p: _os.unlink(p)
            except: pass

    from flask import Response
    return Response(
        pdf_bytes,
        headers={
            'Content-Type':        'application/pdf',
            'Content-Disposition': f'inline; filename="ShutterLeague_{clean}_RatingCard.pdf"',
            'Content-Length':      str(len(pdf_bytes)),
            'Cache-Control':       'no-store, no-cache, must-revalidate',
            'Pragma':              'no-cache',
            'X-Content-Type-Options': 'nosniff',
        }
    )


