@app.route('/recent-work')
def recent_work():
    """Recent Work feed — up to 3 images per photographer, paginated at 24 per page.
    7-day window from midnight IST; falls back to all-time if empty.
    """
    _PER_PAGE = 24
    try:
        page = max(1, request.args.get('page', 1, type=int))
    except Exception:
        page = 1

    try:
        _now_utc   = datetime.utcnow()
        _today_ist = (_now_utc + _IST_OFFSET).replace(hour=0, minute=0, second=0, microsecond=0)
        _window_start = (_today_ist - timedelta(days=7)) - _IST_OFFSET

        _base_q = (
            "SELECT i.id, i.thumb_url, i.asset_name, i.genre, i.score, i.tier,"
            " i.photographer_name, i.scored_at, u.username, i.user_id"
            " FROM images i JOIN users u ON u.id = i.user_id"
            " WHERE i.status = 'scored' AND i.score IS NOT NULL"
            " AND i.is_public = TRUE AND i.is_flagged = FALSE"
            " AND (i.needs_review = FALSE OR i.needs_review IS NULL)"
            " AND (i.raw_disqualified = FALSE OR i.raw_disqualified IS NULL)"
            " AND i.thumb_url IS NOT NULL"
        )

        def _fetch_and_cap(since):
            if since:
                rows = db.session.execute(db.text(
                    _base_q + " AND i.scored_at >= :since ORDER BY i.scored_at DESC LIMIT 500"
                ), {'since': since}).fetchall()
            else:
                rows = db.session.execute(db.text(
                    _base_q + " ORDER BY i.scored_at DESC LIMIT 500"
                )).fetchall()
            # Cap at 3 per photographer
            seen = {}
            result = []
            for r in rows:
                d = dict(r._mapping)
                uid = d['user_id']
                if seen.get(uid, 0) < 3:
                    seen[uid] = seen.get(uid, 0) + 1
                    result.append(d)
            return result

        all_images = _fetch_and_cap(_window_start)
        if not all_images:
            all_images = _fetch_and_cap(None)
            app.logger.info('[recent_work] 7-day window empty — showing all-time')

        # Sort by scored_at descending (newest first)
        all_images = sorted(all_images, key=lambda x: x.get('scored_at') or '', reverse=True)

        total       = len(all_images)
        total_pages = max(1, (total + _PER_PAGE - 1) // _PER_PAGE)
        page        = min(page, total_pages)
        offset      = (page - 1) * _PER_PAGE
        images      = all_images[offset: offset + _PER_PAGE]

    except Exception as _e:
        app.logger.error(f'[recent_work] {_e}')
        images, total, total_pages, page = [], 0, 1, 1

    return render_template(
        'recent_work.html',
        feed_images  = images,
        page         = page,
        total_pages  = total_pages,
        total        = total,
    )


@app.route('/leaderboard')
def leaderboard():
    genre  = request.args.get('genre', 'all')
    tier   = request.args.get('tier', 'all')
    period = request.args.get('period', 'all')
    track  = request.args.get('track', 'all')
    tab    = request.args.get('tab', 'images')
    city   = request.args.get('city', 'all')

    now = datetime.utcnow()
    if period == 'week':
        since = now - timedelta(days=7)
    elif period == 'month':
        since = now - timedelta(days=30)
    else:
        since = None

    def apply_filters(q, user_already_joined=False):
        q = q.filter(
            Image.score.isnot(None),
            Image.score > 0,
            Image.status == 'scored',
            Image.is_public == True,
            db.or_(Image.is_flagged == False, Image.is_flagged == None),
            db.or_(Image.needs_review == False, Image.needs_review == None)
        )
        if since:
            q = q.filter(Image.created_at >= since)
        if genre != 'all':
            q = q.filter(Image.genre == genre)
        if tier != 'all':
            q = q.filter(Image.tier == tier)
        if track == 'camera':
            q = q.filter(db.or_(
                db.text("camera_track = 'camera'"),
                db.text("camera_track IS NULL"),
            ))
        elif track == 'mobile':
            q = q.filter(db.text("camera_track = 'mobile'"))
        if city != 'all':
            if not user_already_joined:
                q = q.join(User, Image.user_id == User.id)
            q = q.filter(User.city == city)
        return q

    img_page     = request.args.get('img_page', 1, type=int)
    img_per_page = 25
    img_q        = apply_filters(Image.query, user_already_joined=False).order_by(desc(Image.score))
    img_total    = img_q.count()
    img_pages    = min(25, max(1, (img_total + img_per_page - 1) // img_per_page))
    img_page     = max(1, min(img_page, img_pages))
    top_images   = img_q.offset((img_page - 1) * img_per_page).limit(img_per_page).all()

    # Find current user's best image rank for "your position" indicator
    from flask_login import current_user as _cu
    user_img_rank = None
    if _cu.is_authenticated:
        try:
            all_scored = apply_filters(Image.query, user_already_joined=False)\
                .order_by(desc(Image.score)).all()
            for _i, _img in enumerate(all_scored):
                if _img.user_id == _cu.id:
                    user_img_rank = _i + 1
                    break
        except Exception:
            pass

    # Top Photographers  -  grouped by user_id, sorted by avg_score DESC
    pg_base = (
        db.session.query(
            Image.user_id,
            User.username,
            User.full_name,
            User.city,
            User.state,
            User.created_at.label('user_created_at'),
            func.avg(Image.score).label('avg_score'),
            func.max(Image.score).label('best_score'),
            func.count(Image.id).label('image_count'),
            func.sum(Image.peer_rating_count).label('total_peer_ratings'),
        )
        .join(User, Image.user_id == User.id)
    )
    pg_base = apply_filters(pg_base, user_already_joined=True)
    pg_page     = request.args.get('pg_page', 1, type=int)
    pg_per_page = 25
    pg_all      = (
        pg_base
        .group_by(Image.user_id, User.username, User.full_name, User.city, User.state, User.created_at)
        .order_by(desc('avg_score'))
        .all()
    )
    pg_total    = len(pg_all)
    pg_pages    = min(25, max(1, (pg_total + pg_per_page - 1) // pg_per_page))
    pg_page     = max(1, min(pg_page, pg_pages))
    pg_rows     = pg_all[(pg_page - 1) * pg_per_page : pg_page * pg_per_page]

    # Find current user's photographer rank
    user_pg_rank = None
    if _cu.is_authenticated:
        for _i, _row in enumerate(pg_all):
            if _row.user_id == _cu.id:
                user_pg_rank = _i + 1
                break
    # Helper — whole calendar months since a datetime
    def _months_since(dt):
        if not dt:
            return 99  # unknown join date → treat as qualified
        _n = datetime.utcnow()
        return (_n.year - dt.year) * 12 + (_n.month - dt.month)

    photographer_stats = []
    for row in pg_rows:
        _jm = _months_since(row.user_created_at)
        photographer_stats.append({
            'user_id':            row.user_id,
            'username':           row.username,
            'display_name':       row.full_name or row.username,
            'city':               row.city,
            'state':              row.state,
            'avg_score':          round(float(row.avg_score), 2) if row.avg_score else 0,
            'best_score':         float(row.best_score) if row.best_score else 0,
            'image_count':        row.image_count,
            'total_peer_ratings': int(row.total_peer_ratings or 0),
            'joined_months':      _jm,
            'under_qualification': _jm < 6,
        })

    # Cities for filter dropdown
    cities = [c[0] for c in (
        db.session.query(User.city)
        .join(Image, Image.user_id == User.id)
        .filter(User.city != None, Image.status == 'scored', Image.is_public == True)
        .distinct().order_by(User.city).all()
    ) if c[0]]

    all_tiers = ['Rookie', 'Shooter', 'Contender', 'Craftsman', 'Maverick', 'Master', 'Grandmaster', 'Legend']

    # -- Camera rankings (lazy  -  only computed for Cameras tab) ---------------
    camera_rankings = []
    if tab == 'cameras':
        from collections import defaultdict
        _cam_q = Image.query.filter(
            Image.status == 'scored',
            Image.score != None,
            Image.score > 0,
            Image.is_public == True,
            db.or_(Image.is_flagged == False, Image.is_flagged == None),
            db.or_(Image.needs_review == False, Image.needs_review == None),
            Image.exif_camera != None,
            Image.exif_camera != '',
        )
        if since:
            _cam_q = _cam_q.filter(Image.created_at >= since)
        if track == 'camera':
            _cam_q = _cam_q.filter(db.or_(
                db.text("camera_track = 'camera'"),
                db.text("camera_track IS NULL"),
            ))
        elif track == 'mobile':
            _cam_q = _cam_q.filter(db.text("camera_track = 'mobile'"))

        _cam_buckets = defaultdict(list)
        for img in _cam_q.all():
            cam = (img.exif_camera or '').strip()
            if cam:
                _cam_buckets[cam].append({
                    'score': img.score,
                    'track': img.camera_track or 'camera',
                })
        for model, entries in _cam_buckets.items():
            scores = [e['score'] for e in entries]
            tracks = [e['track'] for e in entries]
            dominant = 'mobile' if tracks.count('mobile') > tracks.count('camera') else 'camera'
            camera_rankings.append({
                'model':      model,
                'track':      dominant,
                'count':      len(scores),
                'avg_score':  round(sum(scores) / len(scores), 2),
                'best_score': round(max(scores), 2),
            })
        camera_rankings.sort(key=lambda x: x['avg_score'], reverse=True)
        camera_rankings = camera_rankings[:30]

    # -- Lens rankings (lazy  -  only computed for Lenses tab) ------------------
    # Uses exif_lens where available, falls back to exif_camera for existing images
    lens_rankings = []
    if tab == 'lenses':
        try:
            from collections import defaultdict
            _lens_q = Image.query.filter(
                Image.status == 'scored',
                Image.score != None,
                Image.score > 0,
                Image.is_public == True,
                db.or_(Image.is_flagged == False, Image.is_flagged == None),
                db.or_(Image.needs_review == False, Image.needs_review == None),
                db.or_(
                    db.and_(Image.exif_lens != None, Image.exif_lens != ''),
                    db.and_(Image.exif_camera != None, Image.exif_camera != ''),
                ),
                db.or_(
                    db.text("camera_track = 'camera'"),
                    db.text("camera_track IS NULL"),
                ),
            )
            if since:
                _lens_q = _lens_q.filter(Image.created_at >= since)

            _lens_buckets = defaultdict(list)
            for img in _lens_q.all():
                lens = (img.exif_lens or '').strip() or (img.exif_camera or '').strip()
                if lens:
                    _lens_buckets[lens].append(img.score)
            for model, scores in _lens_buckets.items():
                lens_rankings.append({
                    'model':      model,
                    'count':      len(scores),
                    'avg_score':  round(sum(scores) / len(scores), 2),
                    'best_score': round(max(scores), 2),
                })
            lens_rankings.sort(key=lambda x: x['avg_score'], reverse=True)
            lens_rankings = lens_rankings[:30]
        except Exception:
            lens_rankings = []

    # Build join-date qualification map for image tiles
    # Keyed by user_id — used in template to tag images from under-qualification photographers
    try:
        _join_rows = db.session.query(User.id, User.created_at).all()
        user_join_map = {
            r.id: (_months_since(r.created_at) < 6)
            for r in _join_rows
        }
    except Exception:
        user_join_map = {}

    return render_template('leaderboard.html',
        top_images         = top_images,
        photographer_stats = photographer_stats,
        cam_data           = camera_rankings,
        lens_data          = lens_rankings,
        all_genres         = GENRE_IDS,
        all_tiers          = all_tiers,
        cities             = cities,
        genre              = genre,
        tier               = tier,
        period             = period,
        track              = track,
        tab                = tab,
        city               = city,
        img_page           = img_page,
        img_pages          = img_pages,
        img_total          = img_total,
        pg_page            = pg_page,
        pg_pages           = pg_pages,
        pg_total           = pg_total,
        user_img_rank      = user_img_rank,
        user_pg_rank       = user_pg_rank,
        user_join_map      = user_join_map,
    )


