@app.route('/image/<int:image_id>/delete', methods=['POST'])
@login_required
def delete_image(image_id):
    # Set timeout FIRST — before any DB access — so we never hang on a lock
    # held by a background RAW analysis thread
    try:
        db.session.execute(db.text("SET statement_timeout = '8s'"))
        db.session.commit()
    except Exception:
        pass

    img = Image.query.get_or_404(image_id)
    if img.user_id != current_user.id:
        abort(403)

    # Collect R2 keys before DB delete
    r2_keys = []
    for url_attr in ['thumb_url', 'card_url']:
        url = getattr(img, url_attr, None)
        if url:
            try:
                r2_keys.append(url.split(r2.R2_PUBLIC_URL + '/')[-1])
            except Exception:
                pass

    # Log a lightweight record before it's gone — just enough (filename,
    # score, genre) for the free-tier quota message to later explain where
    # a user's slots went, without resurfacing the actual photograph. See
    # the upload_history_log migration (v80) for why this exists. Runs in
    # the same session as the deletes below, so it commits atomically with
    # the real delete — if that fails and rolls back, this rolls back too.
    try:
        db.session.execute(
            db.text("""INSERT INTO upload_history_log (user_id, asset_name, score, genre)
                       VALUES (:uid, :name, :score, :genre)"""),
            {'uid': current_user.id, 'name': img.asset_name, 'score': img.score, 'genre': img.genre}
        )
    except Exception as _log_err:
        app.logger.warning(f'[delete_image] upload_history_log write failed: {_log_err}')

    # Direct SQL deletes — instant, no ORM cascade
    iid = image_id
    for sql in [
        "DELETE FROM raw_submissions      WHERE image_id = :iid",
        "DELETE FROM weekly_submissions   WHERE image_id = :iid",
        "DELETE FROM contest_entries      WHERE image_id = :iid",
        "DELETE FROM open_contest_entries WHERE image_id = :iid",
        "DELETE FROM image_reports        WHERE image_id = :iid",
        "DELETE FROM rating_assignments   WHERE image_id = :iid",
        "DELETE FROM peer_ratings         WHERE image_id = :iid",
        "DELETE FROM peer_pool_entries    WHERE image_id = :iid",
        "DELETE FROM brand_entries        WHERE image_id = :iid",
        "DELETE FROM calibration_notes    WHERE image_id = :iid",
        "DELETE FROM judge_assignments    WHERE image_id = :iid",
        "DELETE FROM judge_scores         WHERE image_id = :iid",
    ]:
        try:
            db.session.execute(db.text(sql), {'iid': iid})
        except Exception:
            pass

    # NULL out parent_image_id on child versions before deleting
    try:
        db.session.execute(
            db.text("UPDATE images SET parent_image_id = NULL WHERE parent_image_id = :iid"),
            {'iid': iid}
        )
        db.session.commit()
    except Exception:
        pass

    try:
        db.session.execute(db.text("DELETE FROM images WHERE id = :iid AND user_id = :uid"),
                           {'iid': iid, 'uid': current_user.id})
        db.session.commit()
    except Exception as _del_err:
        db.session.rollback()
        app.logger.warning(f'[delete_image] DB delete failed: {_del_err}')
        flash('Delete is taking longer than expected — please try again in a moment.', 'warning')
        return redirect(url_for('image_detail', image_id=image_id))

    # R2 cleanup in background — does not block user
    if r2_keys:
        import threading
        def _cleanup(keys):
            for k in keys:
                try:
                    r2.delete_file(k)
                except Exception:
                    pass
        threading.Thread(target=_cleanup, args=(r2_keys,), daemon=True).start()

    flash('Image deleted. Your scores and standing have been updated accordingly.', 'warning')
    return redirect(url_for('dashboard'))


@app.route('/admin/image/<int:image_id>/delete', methods=['POST'])
@login_required
@admin_required
def admin_delete_image(image_id):
    img = Image.query.get_or_404(image_id)
    if img.thumb_url:
        try:
            key = img.thumb_url.split(r2.R2_PUBLIC_URL + '/')[-1]
            r2.delete_file(key)
        except Exception:
            pass
    if img.card_url:
        try:
            key = img.card_url.split(r2.R2_PUBLIC_URL + '/')[-1]
            r2.delete_file(key)
        except Exception:
            pass
    # NULL out parent_image_id on any child versions before deleting
    try:
        db.session.execute(
            db.text("UPDATE images SET parent_image_id = NULL WHERE parent_image_id = :iid"),
            {'iid': image_id}
        )
        db.session.commit()
    except Exception:
        pass
    # Delete all related records first to avoid NOT NULL FK violations.
    # Must match the full set in user-facing delete_image — 12 tables.
    iid = image_id
    for _sql in [
        "DELETE FROM raw_submissions      WHERE image_id = :iid",
        "DELETE FROM weekly_submissions   WHERE image_id = :iid",
        "DELETE FROM contest_entries      WHERE image_id = :iid",
        "DELETE FROM open_contest_entries WHERE image_id = :iid",
        "DELETE FROM image_reports        WHERE image_id = :iid",
        "DELETE FROM rating_assignments   WHERE image_id = :iid",
        "DELETE FROM peer_ratings         WHERE image_id = :iid",
        "DELETE FROM peer_pool_entries    WHERE image_id = :iid",
        "DELETE FROM brand_entries        WHERE image_id = :iid",
        "DELETE FROM calibration_notes    WHERE image_id = :iid",
        "DELETE FROM judge_assignments    WHERE image_id = :iid",
        "DELETE FROM judge_scores         WHERE image_id = :iid",
    ]:
        try:
            db.session.execute(db.text(_sql), {'iid': iid})
        except Exception:
            pass
    # Also clear brand_entries referencing this image
    try:
        db.session.execute(db.text("DELETE FROM brand_entries WHERE image_id = :iid"), {'iid': image_id})
    except Exception:
        pass
    try:
        db.session.delete(img)
        db.session.commit()
    except Exception as _e:
        db.session.rollback()
        app.logger.error(f'[admin_delete_image] DB delete failed for image {image_id}: {_e}')
        # Try raw SQL as fallback
        try:
            db.session.execute(db.text("DELETE FROM images WHERE id = :iid"), {'iid': image_id})
            db.session.commit()
        except Exception as _e2:
            db.session.rollback()
            app.logger.error(f'[admin_delete_image] Raw SQL fallback also failed: {_e2}')
            flash(f'Delete failed: {str(_e2)[:120]}', 'error')
            return redirect(url_for('admin_dashboard'))
    flash(f'Image deleted.', 'success')
    return redirect(url_for('admin_dashboard'))


