@app.route('/sitemap.xml')
def sitemap():
    from datetime import date
    today = date.today().strftime('%Y-%m-%d')
    pages = [
        ('/', '1.0', 'weekly'),
        ('/about', '0.9', 'monthly'),
        ('/how-it-works', '0.9', 'monthly'),
        ('/pricing', '0.9', 'weekly'),
        ('/terms', '0.8', 'monthly'),
        ('/privacy', '0.8', 'monthly'),
        ('/refund-policy', '0.8', 'monthly'),
        # /shipping-policy removed — 301 redirects to /refund-policy (no physical goods)
        ('/contact', '0.7', 'monthly'),
        ('/mentors', '0.8', 'weekly'),
        ('/science', '0.7', 'monthly'),
        ('/learning', '0.7', 'weekly'),
    ]
    base = 'https://shutterleague.com'
    urls = ''
    seen = set()
    for path, priority, freq in pages:
        if path in seen:
            continue
        seen.add(path)
        urls += f'''  <url>
    <loc>{base}{path}</loc>
    <lastmod>{today}</lastmod>
    <changefreq>{freq}</changefreq>
    <priority>{priority}</priority>
  </url>
'''
    xml = f'''<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
{urls}</urlset>'''
    return xml, 200, {'Content-Type': 'application/xml; charset=utf-8'}


@app.route('/sitemap-index.xml')
def sitemap_index():
    """
    Sitemap index — references sitemap.xml (static pages) and
    sitemap-cards.xml (public scored evaluation cards).
    Submitted to Google Search Console.
    """
    base = 'https://shutterleague.com'
    xml = f'''<?xml version="1.0" encoding="UTF-8"?>
<sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
  <sitemap>
    <loc>{base}/sitemap.xml</loc>
  </sitemap>
  <sitemap>
    <loc>{base}/sitemap-cards.xml</loc>
  </sitemap>
</sitemapindex>'''
    return xml, 200, {'Content-Type': 'application/xml; charset=utf-8'}


@app.route('/sitemap-cards.xml')
def sitemap_cards():
    """
    Dynamic sitemap for public scored evaluation cards.
    Queries all scored images with a share_token (not flagged).
    Each /card/<token> page is unique content: photograph, score,
    photographer name, genre, and full evaluation — strong long-tail
    SEO targets (e.g. "Ashok Kochhar 8.92 Master Street Photography").
    """
    try:
        rows = db.session.execute(db.text(
            "SELECT share_token, scored_at "
            "FROM images "
            "WHERE status = 'scored' "
            "  AND share_token IS NOT NULL "
            "  AND share_token != '' "
            "  AND (is_flagged IS NULL OR is_flagged = false) "
            "ORDER BY scored_at DESC "
            "LIMIT 5000"
        )).fetchall()
    except Exception as _e:
        app.logger.error(f'[sitemap_cards] DB error: {_e}')
        rows = []

    from datetime import date as _date
    base = 'https://shutterleague.com'
    fallback_date = _date.today().strftime('%Y-%m-%d')
    urls = ''
    for row in rows:
        token     = row[0]
        scored_at = row[1]
        lastmod   = scored_at.strftime('%Y-%m-%d') if scored_at else fallback_date
        urls += f'''  <url>
    <loc>{base}/card/{token}</loc>
    <lastmod>{lastmod}</lastmod>
    <changefreq>never</changefreq>
    <priority>0.6</priority>
  </url>
'''
    xml = f'''<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
{urls}</urlset>'''
    return xml, 200, {'Content-Type': 'application/xml; charset=utf-8'}


@app.route('/contact', methods=['GET', 'POST'])
def contact():
    if request.method == 'POST':
        name    = request.form.get('name',    '').strip()
        email   = request.form.get('email',   '').strip()
        subject = request.form.get('subject', '').strip()
        message = request.form.get('message', '').strip()

        # Basic validation
        if not name or not email or not subject or not message:
            flash('Please fill in all fields.', 'error')
            return render_template('contact.html',
                                   form_name=name, form_email=email,
                                   form_subject=subject, form_message=message)

        if len(message) > 3000:
            flash('Message is too long (max 3000 characters).', 'error')
            return render_template('contact.html',
                                   form_name=name, form_email=email,
                                   form_subject=subject, form_message=message)

        # Simple rate limit — one submission per session per 60 seconds
        import time as _time
        last_sent = session.get('contact_last_sent', 0)
        if _time.time() - last_sent < 60:
            flash('Please wait a moment before sending another message.', 'warning')
            return render_template('contact.html',
                                   form_name=name, form_email=email,
                                   form_subject=subject, form_message=message)

        # Build and send email to admin
        html_body = (
            f'<h2 style="color:#B8892A;">Contact Form — {PLATFORM_NAME}</h2>'
            f'<table style="border-collapse:collapse; font-family:Arial,sans-serif; font-size:15px;">'
            f'<tr><td style="padding:8px 16px 8px 0; color:#8A8478; font-weight:600;">FROM</td>'
            f'<td style="padding:8px 0;">{name} &lt;{email}&gt;</td></tr>'
            f'<tr><td style="padding:8px 16px 8px 0; color:#8A8478; font-weight:600;">SUBJECT</td>'
            f'<td style="padding:8px 0;">{subject}</td></tr>'
            f'</table>'
            f'<hr style="border:none; border-top:1px solid #E0D8C8; margin:20px 0;">'
            f'<p style="font-family:Arial,sans-serif; font-size:15px; line-height:1.7; color:#1a1a18;">'
            f'{message.replace(chr(10), "<br>")}</p>'
            f'<hr style="border:none; border-top:1px solid #E0D8C8; margin:20px 0;">'
            f'<p style="font-size:15px; color:#8A8478;">Reply directly to {email}</p>'
        )
        text_body = f'From: {name} <{email}>\nSubject: {subject}\n\n{message}'

        admin_to = ADMIN_NOTIFY_EMAIL
        mail_subject = f'[{PLATFORM_NAME}] Contact: {subject}'

        ok = send_email(admin_to, mail_subject, html_body, text_body)

        if ok:
            session['contact_last_sent'] = _time.time()
            # Store message in DB
            try:
                db.session.execute(db.text(
                    "INSERT INTO contact_messages (name, email, subject, message) "
                    "VALUES (:n, :e, :s, :m)"
                ), {'n': name, 'e': email, 's': subject, 'm': message})
                db.session.commit()
            except Exception as _cm_err:
                db.session.rollback()
                app.logger.warning(f'[contact] Could not store message: {_cm_err}')
            # Auto-reply to sender — branded, 3 working days
            _ar_html = (
                '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#FFFFFF;">'
                '<div style="background:#1A2744;padding:20px 32px;">'
                '<p style="color:#F5C518;font-family:Courier New,monospace;font-weight:700;font-size:14px;letter-spacing:2px;margin:0;">SHUTTER LEAGUE</p>'
                '<p style="color:#FFFFFF;font-size:11px;margin:4px 0 0 0;letter-spacing:1px;">HONEST FEEDBACK. REAL IMPROVEMENT.</p>'
                '</div>'
                '<div style="padding:32px;">'
                f'<p style="font-size:16px;color:#1A1A18;margin:0 0 16px 0;line-height:1.7;">Hi ' + name + ',</p>'
                '<p style="font-size:16px;color:#1A1A18;margin:0 0 16px 0;line-height:1.7;">Thank you for writing in. We have received your message and will respond within <strong>3 working days</strong>.</p>'
                '<div style="background:#F5F3EF;border-left:4px solid #F5C518;padding:16px 20px;margin:20px 0;">'
                '<p style="font-size:14px;color:#1A1A18;font-weight:700;margin:0 0 6px 0;">Your message:</p>'
                f'<p style="font-size:14px;color:#555555;margin:0;font-style:italic;line-height:1.7;">' + message.replace('\n', '<br>') + '</p>'
                '</div>'
                '<p style="font-size:14px;color:#888888;margin:0;">If your query is urgent, you can also reach us directly at <a href="mailto:support@shutterleague.com" style="color:#F5C518;">support@shutterleague.com</a>.</p>'
                '</div>'
                '<div style="background:#F5F3EF;border-top:1px solid #E0D8C8;padding:16px 32px;">'
                '<p style="color:#888888;font-size:12px;margin:0;">Shutter League &nbsp;·&nbsp; support@shutterleague.com &nbsp;·&nbsp; shutterleague.com</p>'
                '</div>'
                '</div>'
            )
            _ar_text = (
                f'Hi {name},\n\n'
                'Thank you for writing in. We have received your message and will respond within 3 working days.\n\n'
                f'Your message:\n{message}\n\n'
                'If urgent: support@shutterleague.com\n\n-- Shutter League'
            )
            try:
                send_email(email, f'We received your message — Shutter League', _ar_html, _ar_text)
            except Exception as _are:
                app.logger.warning(f'[contact] Auto-reply failed: {_are}')
            flash('Your message has been sent. We respond within 3 working days.', 'success')
            return render_template('contact.html')
        else:
            app.logger.error(f'[contact] Failed to send contact email from {email}')
            flash('Message could not be sent right now. Please email us directly at '
                  + CONTACT_EMAIL + '.', 'error')
            return render_template('contact.html',
                                   form_name=name, form_email=email,
                                   form_subject=subject, form_message=message)

    return render_template('contact.html')

