@app.route('/subscribe/<track>', methods=['GET', 'POST'])
@login_required
def subscribe(track):
    if track not in ('camera', 'mobile', 'learning', 'mentor'):
        return redirect(url_for('pricing'))

    plan = request.args.get('plan', 'monthly')
    if plan not in ('monthly', 'annual'):
        plan = 'monthly'

    razorpay_key    = os.getenv('RAZORPAY_KEY_ID', '')
    razorpay_secret = os.getenv('RAZORPAY_KEY_SECRET', '')

    plan_ids = {
        'mobile': {
            'monthly': os.getenv('RAZORPAY_PLAN_MOBILE_MONTHLY', ''),
            'annual':  os.getenv('RAZORPAY_PLAN_MOBILE_ANNUAL', ''),
        },
        'camera': {
            'monthly': os.getenv('RAZORPAY_PLAN_CAMERA_MONTHLY', ''),
            'annual':  os.getenv('RAZORPAY_PLAN_CAMERA_ANNUAL', ''),
        },
        'learning': {
            'monthly': os.getenv('RAZORPAY_PLAN_LEARNING_MONTHLY', ''),
            'annual':  os.getenv('RAZORPAY_PLAN_LEARNING_ANNUAL', ''),
        },
        'mentor': {
            'monthly': os.getenv('RAZORPAY_PLAN_MENTOR_MONTHLY', ''),
            'annual':  os.getenv('RAZORPAY_PLAN_MENTOR_ANNUAL', ''),
        },
    }
    display_prices = {
        'mobile':   {'monthly': 99,   'annual': 999},
        'camera':   {'monthly': 199,  'annual': 1999},
        'learning': {'monthly': 100,  'annual': 999},
        'mentor':   {'monthly': 999,  'annual': 9999},
    }

    plan_id = plan_ids[track][plan]
    amount  = display_prices[track][plan]

    if request.method == 'POST':
        payment_id      = request.form.get('razorpay_payment_id', '')
        subscription_id = request.form.get('razorpay_subscription_id', '')
        signature       = request.form.get('razorpay_signature', '')

        if not razorpay_key:
            flash('Payment system not configured. Contact support.', 'error')
            return redirect(url_for('pricing'))

        try:
            import hmac as _hmac, hashlib as _hashlib
            # Subscription signature: HMAC-SHA256 of payment_id|subscription_id
            expected_sig = _hmac.new(
                razorpay_secret.encode('utf-8'),
                f'{payment_id}|{subscription_id}'.encode('utf-8'),
                _hashlib.sha256
            ).hexdigest()
            if not _hmac.compare_digest(expected_sig, signature):
                raise Exception('Payment signature verification failed')

            current_user.subscription_track  = track
            current_user.subscription_plan   = plan
            current_user.subscribed_at        = datetime.utcnow()
            current_user.is_subscribed        = True
            current_user.razorpay_sub_id      = subscription_id
            db.session.execute(
                db.text('UPDATE users SET referred_discount = FALSE WHERE id = :uid'),
                {'uid': current_user.id}
            )  # discount used — clear
            db.session.commit()
            # ── Referral: first payment — +200 pts to referrer ────────────
            try:
                _ref_rec2 = db.session.execute(
                    db.text('SELECT id, referrer_id, points_reward_granted '
                            'FROM referrals WHERE referred_user_id = :uid'),
                    {'uid': current_user.id}
                ).fetchone()
                if _ref_rec2 and not _ref_rec2[2]:
                    _referrer2 = User.query.get(_ref_rec2[1])
                    if _referrer2:
                        award_points(_referrer2, 200, 'referral_conversion')
                    db.session.execute(
                        db.text('UPDATE referrals SET first_payment_at = NOW(), '
                                'points_reward_granted = TRUE WHERE id = :rid'),
                        {'rid': _ref_rec2[0]}
                    )
                    db.session.commit()
                    app.logger.info(f'[referral] +200pts: referrer={_ref_rec2[1]} referred={current_user.id}')
            except Exception as _rpe:
                app.logger.error(f'[referral] subscribe hook: {_rpe}')

            track_names = {
                'camera':   'Camera League',
                'mobile':   'Mobile League',
                'learning': 'Learning — ₹100/mo',
                'mentor':   'Human + AI Mentor',
            }
            flash(f'Welcome to {track_names.get(track, track.title())}! Your subscription is active.', 'success')
            return redirect(url_for('learning') if track in ('learning', 'mentor') else url_for('dashboard'))
        except Exception as e:
            app.logger.error(f'[subscribe] verification failed: {e}')
            flash('Payment verification failed. Please contact support if you were charged.', 'error')
            return redirect(url_for('subscribe', track=track, plan=plan))

    # GET  -  Payment gateway finalisation in progress
    # Payment gateway onboarding pending — show coming soon wall
    # Once gateway is confirmed, remove this block and restore subscription creation below
    PAYMENT_GATEWAY_LIVE = os.getenv('PAYMENT_GATEWAY_LIVE', '0') == '1'
    if not PAYMENT_GATEWAY_LIVE:
        track_labels = {
            'camera':   'Camera League',
            'mobile':   'Mobile League',
            'learning': 'Learning Only',
            'mentor':   'Human + AI Mentor',
        }
        track_descriptions = {
            'camera':   '4 photographs evaluated/month · RAW eligible · Annual Excellence Award (AEA) · Programmes',
            'mobile':   '4 photographs evaluated/month · Annual Excellence Award (AEA) · Programmes',
            'learning': '12 photographs evaluated/month · AI mentor · Improvement paths',
            'mentor':   '12 photographs evaluated/month · Weekly 1-on-1 · Human + AI',
        }
        try:
            _ref_disc = db.session.execute(
                db.text('SELECT referred_discount FROM users WHERE id = :uid'),
                {'uid': current_user.id}
            ).scalar() or False
        except Exception:
            _ref_disc = False
        _disc_prices = REFERRAL_DISCOUNT_PRICES.get(track, {})
        _disc_amount = _disc_prices.get(plan) if _ref_disc else None
        return render_template('subscribe_coming_soon.html',
            track=track, plan=plan, amount=amount,
            track_label=track_labels.get(track, track.title()),
            track_description=track_descriptions.get(track, ''),
            referred_discount=_ref_disc,
            discount_amount=_disc_amount,
        )

    # GET  -  create payment subscription (live when PAYMENT_GATEWAY_LIVE=1)
    subscription = None
    if razorpay_key and plan_id:
        try:
            import razorpay
            client = razorpay.Client(auth=(razorpay_key, razorpay_secret))
            subscription = client.subscription.create({
                'plan_id':         plan_id,
                'total_count':     10 if plan == 'annual' else 120,
                'quantity':        1,
                'customer_notify': 1,
            })
        except Exception as e:
            app.logger.error(f'[subscribe] subscription create failed: {e}')
            flash('Could not initialise payment. Please try again.', 'error')

    track_labels = {
        'camera':   'Camera League',
        'mobile':   'Mobile League',
        'learning': 'Learning Only',
        'mentor':   'Human + AI Mentor',
    }
    track_descriptions = {
        'camera':   '5 scored images/month · RAW eligible · Annual Excellence Award (POTY) · Programmes',
        'mobile':   '8 scored images/month · Annual Excellence Award (POTY) · Programmes',
        'learning': '12 scored images/month · AI mentor · Improvement paths',
        'mentor':   '12 scored images/month · Weekly 1-on-1 · Human + AI',
    }
    return render_template('subscribe.html',
        track=track, plan=plan, amount=amount,
        subscription=subscription,
        razorpay_key=razorpay_key,
        track_label=track_labels.get(track, track.title()),
        track_description=track_descriptions.get(track, ''),
    )


@app.route('/razorpay/webhook', methods=['POST'])
def razorpay_webhook():
    import hmac as _hmac, hashlib as _hashlib, json as _json
    webhook_secret = os.getenv('RAZORPAY_WEBHOOK_SECRET', '')
    payload        = request.get_data()
    sig            = request.headers.get('X-Razorpay-Signature', '')

    if webhook_secret:
        expected = _hmac.new(
            webhook_secret.encode(), payload, _hashlib.sha256
        ).hexdigest()
        if not _hmac.compare_digest(expected, sig):
            app.logger.warning('[webhook] invalid signature')
            return jsonify({'status': 'invalid signature'}), 400

    try:
        event      = _json.loads(payload)
        event_type = event.get('event', '')
        app.logger.info(f'[webhook] {event_type}')
        sub_data   = (event.get('payload', {}).get('subscription', {}).get('entity', {}))
        sub_id     = sub_data.get('id', '')

        if event_type == 'subscription.activated':
            user = User.query.filter_by(razorpay_sub_id=sub_id).first()
            if user:
                user.is_subscribed = True
                db.session.commit()

        elif event_type in ('subscription.cancelled', 'subscription.completed', 'subscription.halted'):
            user = User.query.filter_by(razorpay_sub_id=sub_id).first()
            if user:
                user.is_subscribed      = False
                user.subscription_track = None
                user.subscription_plan  = None
                db.session.commit()

    except Exception as e:
        app.logger.error(f'[webhook] error: {e}')

    return jsonify({'status': 'ok'}), 200


@app.route('/subscription/cancel', methods=['GET', 'POST'])
@login_required
def cancel_subscription():
    """
    GET   -  confirmation page (user must confirm before cancelling)
    POST  -  actually cancel: call payment gateway API, clear DB fields, redirect to dashboard
    RBI compliance: user must be able to self-cancel without contacting support.
    """
    if request.method == 'GET':
        return render_template('cancel_subscription.html')

    # POST  -  confirmed cancellation
    razorpay_key    = os.getenv('RAZORPAY_KEY_ID', '')
    razorpay_secret = os.getenv('RAZORPAY_KEY_SECRET', '')
    sub_id          = current_user.razorpay_sub_id

    # Cancel on payment gateway end if we have a live subscription ID
    if sub_id and razorpay_key:
        try:
            import razorpay as _rz
            client = _rz.Client(auth=(razorpay_key, razorpay_secret))
            # cancel_at_cycle_end=1 means access continues until end of paid period
            client.subscription.cancel(sub_id, {'cancel_at_cycle_end': 1})
            app.logger.info(f'[cancel] Payment subscription {sub_id} cancelled for user {current_user.id}')
        except Exception as e:
            app.logger.error(f'[cancel] Payment subscription cancel failed for {sub_id}: {e}')
            # Still cancel locally  -  don't leave user stuck
            flash('Your subscription has been cancelled. If you continue to be charged, contact '+CONTACT_EMAIL+'.', 'warning')

    # Clear subscription fields in DB
    current_user.is_subscribed      = False
    current_user.subscription_track = None
    current_user.subscription_plan  = None
    current_user.razorpay_sub_id    = None
    db.session.commit()

    flash('Your subscription has been cancelled. You will retain access until the end of your current billing period.', 'info')
    return redirect(url_for('dashboard'))


@app.route('/bulk-upload', methods=['GET', 'POST'])
@login_required
def bulk_upload():
    if current_user.role != 'admin' and not getattr(current_user, 'is_subscribed', False):
        abort(403)
    is_xhr = request.headers.get('X-Requested-With') == 'XMLHttpRequest'
    results = []
    if request.method == 'POST':
        files = request.files.getlist('images')
        if len(files) > 10:
            if is_xhr:
                return jsonify({'error': True, 'message': 'Maximum 10 images per batch.'}), 400
            flash('Maximum 10 images per bulk upload. Please split into batches of 10.', 'error')
            return redirect(url_for('bulk_upload'))
        raw_genre = request.form.get('genre', '').strip()
        if not raw_genre:
            if is_xhr:
                return jsonify({'error': True, 'message': 'Please select a genre before uploading.'}), 400
            flash('Please select a genre before uploading.', 'error')
            return redirect(url_for('bulk_upload'))
        genre = normalise_genre(raw_genre)

        if current_user.role != 'admin' and not getattr(current_user, 'is_subscribed', False):
            total_count = Image.query.filter(
                Image.user_id == current_user.id,
            ).count()
            if total_count >= FREE_IMAGE_LIMIT:
                flash(
                    f'You have used all {FREE_IMAGE_LIMIT} free assessment images. '
                    'Subscribe to Camera or Mobile League to continue uploading.',
                    'error'
                )
                return redirect(url_for('pricing'))
        photographer = (request.form.get('photographer_name') or '').strip()
        if not photographer:
            photographer = current_user.full_name or current_user.username
        api_key = os.getenv('ANTHROPIC_API_KEY', '')
        for file in files:
            if not file or not file.filename:
                continue
            if not allowed_file(file.filename):
                results.append({'filename': file.filename, 'score': None, 'tier': None, 'status': 'skipped'})
                continue
            result_row = {'filename': file.filename, 'score': None, 'tier': None, 'status': 'failed'}
            try:
                uid      = str(uuid.uuid4())
                filename = secure_filename(file.filename)
                raw_path = os.path.join(app.config['UPLOAD_FOLDER'], 'raw', f"{uid}_{filename}")
                file.save(raw_path)
                thumb_path, w, h, fmt, phash = ingest_image(raw_path, app.config['UPLOAD_FOLDER'])
                if os.path.exists(raw_path): os.remove(raw_path)

                from engine.processor import hash_similarity_pct
                existing_imgs = Image.query.filter(Image.phash.isnot(None)).all()
                duplicate_found = False
                for ex in existing_imgs:
                    sim = hash_similarity_pct(phash, ex.phash)
                    if sim >= 98.0:
                        if ex.user_id == current_user.id:
                            result_row['status'] = f'duplicate: already uploaded as "{ex.asset_name or ex.original_filename}"'
                        else:
                            result_row['status'] = 'unable to accept: image may already exist in our database — contact support@shutterleague.com if you believe this is an error'
                        duplicate_found = True
                        if os.path.exists(thumb_path): os.remove(thumb_path)
                        break
                if duplicate_found:
                    results.append(result_row)
                    continue

                thumb_url = _r2_upload_thumb(thumb_path, uid)

                from models import Image as ImageModel
                img = ImageModel(
                    user_id=current_user.id, original_filename=filename,
                    stored_filename=os.path.basename(thumb_path),
                    thumb_path=thumb_path, thumb_url=thumb_url,
                    file_size_kb=int(os.path.getsize(thumb_path)/1024),
                    width=w, height=h, format=fmt,
                    asset_name=auto_title(filename, genre),
                    phash=phash, genre=genre, photographer_name=photographer,
                    camera_track=getattr(current_user, 'subscription_track', None),
                    status='pending',
                    is_public=(request.form.get('is_public', '0') == '1'),
                )
                db.session.add(img)
                db.session.flush()
                if api_key:
                    from engine.auto_score import auto_score, build_audit_data
                    from engine.compositor import build_card1 as _build_card
                    scored = auto_score(image_path=img.thumb_path, genre=genre,
                                        sub_genre=img.sub_genre,
                                        title=img.asset_name, photographer=photographer)
                    img.dod_score=float(scored.get('dod',0))
                    img.disruption_score=float(scored.get('disruption',0))
                    img.dm_score=float(scored.get('dm',0))
                    img.wonder_score=float(scored.get('wonder',0))
                    img.aq_score=float(scored.get('aq',0))
                    img.score=float(scored.get('score',0))
                    img.tier=get_tier(float(scored.get('score',0)))
                    img.archetype=scored.get('archetype','')
                    img.soul_bonus=scored.get('soul_bonus',False)
                    img.status='scored'; img.scored_at=datetime.utcnow()
                    audit = build_audit_data(scored, img)
                    img.set_audit(audit)
                    card_fname = (f"LL_{date.today().strftime('%Y%m%d')}_"
                                  f"{secure_filename(photographer.replace(' ',''))}_{genre}_{img.score}.jpg")
                    card_path = os.path.join(app.config['UPLOAD_FOLDER'], 'cards', card_fname)
                    _build_card(img.thumb_path, audit, card_path)
                    img.card_path = card_path
                    card_url = _r2_upload_card(card_path, uid + '_card')
                    if card_url: img.card_url = card_url
                    result_row['score']=img.score; result_row['tier']=img.tier; result_row['status']='scored'
                else:
                    img.status='pending'; result_row['status']='uploaded'
                db.session.commit()
            except Exception as e:
                try:
                    db.session.rollback()
                except:
                    pass
                import traceback
                app.logger.error(f'Bulk upload error for {file.filename}: {traceback.format_exc()}')
                result_row['status'] = f'error: {str(e)[:120]}'
            results.append(result_row)
    try:
        db.session.commit()
    except Exception as ce:
        app.logger.error(f'Final bulk commit error: {ce}')
        try:
            db.session.rollback()
        except:
            pass

    if request.method == 'POST' and results:
        scored_count  = sum(1 for r in results if r['status'] == 'scored')
        saved_count   = sum(1 for r in results if 'saved' in r['status'] or r['status'] == 'uploaded')
        error_count   = sum(1 for r in results if 'error' in r['status'])
        msg_parts = []
        if scored_count:  msg_parts.append(f'{scored_count} scored')
        if saved_count:   msg_parts.append(f'{saved_count} saved (pending)')
        if error_count:   msg_parts.append(f'{error_count} failed')
        flash(f"Bulk upload complete: {', '.join(msg_parts)}.", 'success')
        if is_xhr:
            return jsonify({'ok': True, 'results': results, 'redirect': url_for('dashboard')})
        return redirect(url_for('dashboard'))
    return render_template('bulk_upload.html', genres=GENRE_IDS, results=results,
                           genre_choices=GENRE_CHOICES,
                           subgenre_map=SUBGENRE_MAP,
                           subgenre_map_json=json.dumps({k: list(v) for k, v in SUBGENRE_MAP.items()}))








# ---------------------------------------------------------------------------
# Bulk Upload — single image endpoint (called per-image by frontend loop)
# ---------------------------------------------------------------------------
@app.route('/bulk-upload/one', methods=['POST'])
@login_required
def bulk_upload_one():
    """Process one image at a time — called in a loop by the bulk upload frontend.
    Keeps each request well under Gunicorn worker timeout regardless of batch size."""
    if current_user.role != 'admin' and not getattr(current_user, 'is_subscribed', False):
        return jsonify({'status': 'error', 'message': 'Subscription required for bulk upload.'}), 403

    file = request.files.get('image')
    if not file or not file.filename:
        return jsonify({'status': 'error', 'message': 'No file received'}), 400

    if not allowed_file(file.filename):
        return jsonify({'filename': file.filename, 'status': 'skipped',
                        'score': None, 'tier': None}), 200

    genre = normalise_genre(request.form.get('genre', '').strip())
    if not genre:
        return jsonify({'status': 'error', 'message': 'No genre provided'}), 400

    photographer = (request.form.get('photographer_name') or '').strip() \
                   or current_user.full_name or current_user.username
    is_public    = request.form.get('is_public', '0') == '1'
    sub_genre    = (request.form.get('sub_genre') or '').strip() or None
    location     = (request.form.get('location') or '').strip() or None
    subject      = (request.form.get('subject') or '').strip() or None
    species_hint = (request.form.get('species_hint') or '').strip() or None
    api_key      = os.getenv('ANTHROPIC_API_KEY', '')

    result = {'filename': file.filename, 'score': None, 'tier': None, 'status': 'failed'}
    try:
        uid        = str(uuid.uuid4())
        filename   = secure_filename(file.filename)
        raw_path   = os.path.join(app.config['UPLOAD_FOLDER'], 'raw', uid + '_' + filename)
        file.save(raw_path)
        thumb_path, w, h, fmt, phash = ingest_image(raw_path, app.config['UPLOAD_FOLDER'])
        if os.path.exists(raw_path):
            os.remove(raw_path)

        from engine.processor import hash_similarity_pct
        existing_imgs = Image.query.filter(Image.phash.isnot(None)).all()
        for ex in existing_imgs:
            if hash_similarity_pct(phash, ex.phash) >= 98.0:
                if os.path.exists(thumb_path):
                    os.remove(thumb_path)
                if ex.user_id == current_user.id:
                    dup_msg = 'duplicate: already uploaded as "' + (ex.asset_name or ex.original_filename or '') + '"'
                else:
                    dup_msg = 'unable to accept: image may already exist in our database'
                return jsonify({'filename': file.filename, 'status': dup_msg,
                                'score': None, 'tier': None}), 200

        thumb_url = _r2_upload_thumb(thumb_path, uid)

        # ── Watermark detection ───────────────────────────────────────────────
        try:
            _bwm_key = os.getenv('ANTHROPIC_API_KEY', '')
            if _bwm_key and os.path.exists(thumb_path):
                import base64 as _bwm_b64, urllib.request as _bwm_ur, json as _bwm_json
                from PIL import Image as _PILBWM
                import io as _bwm_io
                _bwm_pil = _PILBWM.open(thumb_path).convert('RGB')
                if max(_bwm_pil.size) > 1024: _bwm_pil.thumbnail((1024, 1024))
                _bwm_buf = _bwm_io.BytesIO()
                _bwm_pil.save(_bwm_buf, format='JPEG', quality=80)
                _bwm_payload = _bwm_json.dumps({
                    'model': 'claude-haiku-4-5-20251001', 'max_tokens': 100,
                    'messages': [{'role': 'user', 'content': [
                        {'type': 'image', 'source': {'type': 'base64', 'media_type': 'image/jpeg',
                            'data': _bwm_b64.b64encode(_bwm_buf.getvalue()).decode('utf-8')}},
                        {'type': 'text', 'text': (
                            'Does this photograph contain a photographer-added watermark, text overlay, '
                            'studio logo, social media handle (@username), copyright text, or any branding '
                            'embedded into the image by the photographer? '
                            'Do NOT flag: image content (signs, billboards, labels that are part of the scene), '
                            'platform watermarks, or natural scene text. '
                            'Only flag overlays added on top of the photograph after capture. '
                            'Respond ONLY with JSON: {"watermark_detected": true/false, "description": "one short phrase or null"}'
                        )}
                    ]}]
                }).encode('utf-8')
                _bwm_req = _bwm_ur.Request('https://api.anthropic.com/v1/messages',
                    data=_bwm_payload,
                    headers={'Content-Type': 'application/json', 'x-api-key': _bwm_key,
                             'anthropic-version': '2023-06-01'}, method='POST')
                with _bwm_ur.urlopen(_bwm_req, timeout=15) as _bwm_resp:
                    _bwm_result = _bwm_json.loads(_bwm_resp.read().decode())
                _bwm_text = _bwm_result.get('content', [{}])[0].get('text', '{}')
                _bwm_text = _bwm_text.strip().lstrip('`').lstrip('json').strip('`').strip()
                _bwm_data = _bwm_json.loads(_bwm_text)
                if _bwm_data.get('watermark_detected'):
                    if os.path.exists(thumb_path): os.remove(thumb_path)
                    app.logger.info(f'[bulk_upload_one] watermark rejected: {_bwm_data.get("description")} uid={current_user.id}')
                    return jsonify({'filename': file.filename, 'status': 'rejected — watermark or logo detected. Please remove any added text or branding and re-upload the clean image.', 'score': None, 'tier': None}), 200
        except Exception as _bwm_err:
            app.logger.warning(f'[bulk_upload_one] watermark check failed (non-fatal): {_bwm_err}')

        # ── NSFW / Nudity detection ───────────────────────────────────────────
        _bulk_nsfw_breastfeeding = False
        try:
            _bnsfw_key = os.getenv('ANTHROPIC_API_KEY', '')
            if _bnsfw_key and os.path.exists(thumb_path):
                import base64 as _bnsfw_b64, urllib.request as _bnsfw_ur, json as _bnsfw_json
                from PIL import Image as _PIL_bnsfw
                import io as _bnsfw_io
                _bnsfw_pil = _PIL_bnsfw.open(thumb_path).convert('RGB')
                if max(_bnsfw_pil.size) > 1024: _bnsfw_pil.thumbnail((1024, 1024))
                _bnsfw_buf = _bnsfw_io.BytesIO()
                _bnsfw_pil.save(_bnsfw_buf, format='JPEG', quality=80)
                _bnsfw_payload = _bnsfw_json.dumps({
                    'model': 'claude-haiku-4-5-20251001', 'max_tokens': 80,
                    'messages': [{'role': 'user', 'content': [
                        {'type': 'image', 'source': {'type': 'base64', 'media_type': 'image/jpeg',
                            'data': _bnsfw_b64.b64encode(_bnsfw_buf.getvalue()).decode('utf-8')}},
                        {'type': 'text', 'text': (
                            'Examine this photograph carefully. Respond ONLY with JSON — no other text. '
                            'Return: {"nudity": true/false, "breastfeeding": true/false, "description": "one short phrase or null"} '
                            'Where: '
                            '"nudity" = true ONLY if the image contains explicit nudity, exposed genitalia, bare breasts '
                            '(other than breastfeeding), or explicit sexual content. '
                            'IMPORTANT: Traditional, cultural, or religious attire must NOT be flagged — this includes '
                            'dhotis, mundus, lungis, sarongs, loincloths, bare-chested traditional dress at festivals, '
                            'temples, or cultural events (common in South Asian, African, and Pacific cultures), '
                            'and any other regional clothing that leaves skin exposed as a matter of cultural practice. '
                            'ALSO IMPORTANT: Commercial, editorial, or advertising photography — billboards, posters, '
                            'magazine ads, fashion/swimwear/lingerie shoots, sports uniforms — must NOT be flagged for '
                            'showing models in swimwear, lingerie, or undergarments. Only flag this kind of image if it '
                            'exposes genitalia or bare breasts, or is otherwise explicit/sexual rather than commercial. '
                            'ALSO IMPORTANT: Bare-chested men in any context — family portraits, street photography, '
                            'documentary, everyday life, cultural events, sports, or casual settings — must NOT be '
                            'flagged. Male shirtlessness is not nudity. Only flag a male subject if genitalia '
                            'are explicitly exposed. '
                            'ALSO IMPORTANT: Children in age-appropriate contexts must NOT be flagged. This includes '
                            'boys shirtless or in underwear in family, beach, play, or everyday settings; girls in '
                            'age-appropriate swimwear (bikinis, one-piece), underwear, or everyday clothing; children '
                            'bathing, swimming, playing, or in family portraits. Only flag a child if genitalia are '
                            'explicitly and unambiguously exposed, or if there are clear signs of sexual exploitation '
                            'or abuse. When in doubt about a child image, return nudity=false. '
                            'Fine art nude studies with no explicit or sexual context should still be flagged as nudity=true. '
                            '"breastfeeding" = true ONLY if a mother is visibly breastfeeding an infant — '
                            'this overrides nudity=true when present. '
                            '"description" = one short phrase describing what was detected, or null if clean.'
                        )}
                    ]}]
                }).encode('utf-8')
                _bnsfw_req = _bnsfw_ur.Request('https://api.anthropic.com/v1/messages',
                    data=_bnsfw_payload,
                    headers={'Content-Type': 'application/json', 'x-api-key': _bnsfw_key,
                             'anthropic-version': '2023-06-01'}, method='POST')
                with _bnsfw_ur.urlopen(_bnsfw_req, timeout=20) as _bnsfw_resp:
                    _bnsfw_result = _bnsfw_json.loads(_bnsfw_resp.read().decode('utf-8'))
                _bnsfw_raw = _bnsfw_result.get('content', [{}])[0].get('text', '{}')
                _bnsfw_raw = _bnsfw_raw.strip().lstrip('`').lstrip('json').strip('`').strip()
                _bnsfw_data = _bnsfw_json.loads(_bnsfw_raw)
                _bnsfw_reject = bool(_bnsfw_data.get('nudity', False))
                _bulk_nsfw_breastfeeding = bool(_bnsfw_data.get('breastfeeding', False))
                if _bulk_nsfw_breastfeeding: _bnsfw_reject = False
                app.logger.info(f'[bulk_upload_one] nsfw: nudity={_bnsfw_reject} breastfeeding={_bulk_nsfw_breastfeeding} uid={current_user.id}')
                if _bnsfw_reject:
                    if os.path.exists(thumb_path): os.remove(thumb_path)
                    return jsonify({'filename': file.filename, 'status': 'rejected — nudity or explicit content detected. Please re-upload a clean image.', 'score': None, 'tier': None}), 200
        except Exception as _bnsfw_err:
            app.logger.warning(f'[bulk_upload_one] nsfw check failed (non-fatal): {_bnsfw_err}')

        from models import Image as ImageModel
        img = ImageModel(
            user_id          = current_user.id,
            original_filename= filename,
            stored_filename  = os.path.basename(thumb_path),
            thumb_path       = thumb_path,
            thumb_url        = thumb_url,
            file_size_kb     = int(os.path.getsize(thumb_path) / 1024),
            width=w, height=h, format=fmt,
            asset_name       = auto_title(filename, genre),
            phash            = phash,
            genre            = genre,
            sub_genre        = sub_genre,
            photographer_name= photographer,
            camera_track     = getattr(current_user, 'subscription_track', None),
            location         = location,
            subject          = subject,
            species_hint     = species_hint,
            status           = 'pending',
            is_public        = is_public,
        )
        db.session.add(img)
        db.session.flush()

        if api_key:
            from engine.auto_score import auto_score, build_audit_data
            from engine.compositor import build_card1 as _build_card

            # ── Score anchor check ─────────────────────────────────────────
            _bulk_cached = None
            try:
                _bulk_cache_row = db.session.execute(
                    db.text(
                        "SELECT score, tier, dod_score, disruption_score, dm_score, "
                        "wonder_score, aq_score, archetype, soul_bonus, original_image_id "
                        "FROM scored_phash_cache "
                        "WHERE user_id = :uid AND phash = :ph AND genre = :genre "
                        "ORDER BY scored_at DESC LIMIT 1"
                    ),
                    {'uid': current_user.id, 'ph': phash, 'genre': genre}
                ).fetchone()
                if _bulk_cache_row:
                    _bulk_cached = dict(_bulk_cache_row._mapping)
            except Exception as _bce:
                app.logger.warning(f'[bulk_upload_one] cache lookup failed: {_bce}')

            # If cache hit but original has no audit_json — fall through to engine
            if _bulk_cached:
                _orig_id = _bulk_cached.get('original_image_id')
                _has_audit = False
                if _orig_id:
                    try:
                        _audit_check = db.session.execute(
                            db.text("SELECT audit_json FROM images WHERE id = :iid"),
                            {'iid': _orig_id}
                        ).fetchone()
                        if _audit_check and _audit_check[0]:
                            _has_audit = True
                    except Exception:
                        pass
                if not _has_audit:
                    app.logger.info(f'[bulk_upload_one] cache hit but no audit on original {_orig_id} — falling through to engine')
                    _bulk_cached = None

            if _bulk_cached:
                img.dod_score        = _bulk_cached.get('dod_score') or 0.0
                img.disruption_score = _bulk_cached.get('disruption_score') or 0.0
                img.dm_score         = _bulk_cached.get('dm_score') or 0.0
                img.wonder_score     = _bulk_cached.get('wonder_score') or 0.0
                img.aq_score         = _bulk_cached.get('aq_score') or 0.0
                img.score            = _bulk_cached.get('score') or 0.0
                img.tier             = _bulk_cached.get('tier') or get_tier(img.score)
                img.archetype        = _bulk_cached.get('archetype') or ''
                img.soul_bonus       = bool(_bulk_cached.get('soul_bonus', False))
                img.status           = 'scored'
                img.scored_at        = datetime.utcnow()
                # Copy audit_json from original image
                _orig_id = _bulk_cached.get('original_image_id')
                if _orig_id:
                    try:
                        _orig = Image.query.get(_orig_id)
                        if _orig and _orig.audit_json:
                            img.audit_json = _orig.audit_json
                    except Exception as _ae:
                        app.logger.warning(f'[bulk_upload_one] audit copy failed: {_ae}')
                result = {'filename': file.filename, 'score': img.score,
                          'tier': img.tier, 'status': 'scored (anchored)'}
                app.logger.info(f'[bulk_upload_one] score anchored: image={img.id} score={img.score}')
            else:
                scored = auto_score(image_path=img.thumb_path, genre=genre,
                                    sub_genre=img.sub_genre,
                                    title=img.asset_name, photographer=photographer)
                img.dod_score        = float(scored.get('dod', 0))
                img.disruption_score = float(scored.get('disruption', 0))
                img.dm_score         = float(scored.get('dm', 0))
                img.wonder_score     = float(scored.get('wonder', 0))
                img.aq_score         = float(scored.get('aq', 0))
                img.score            = float(scored.get('score', 0))
                img.tier             = get_tier(float(scored.get('score', 0)))
                img.archetype        = scored.get('archetype', '')
                img.soul_bonus       = scored.get('soul_bonus', False)
                img.status           = 'scored'
                img.scored_at        = datetime.utcnow()
                audit = build_audit_data(scored, img)
                img.set_audit(audit)
                card_fname = ('LL_' + date.today().strftime('%Y%m%d') + '_'
                              + secure_filename(photographer.replace(' ', ''))
                              + '_' + genre + '_' + str(img.score) + '.jpg')
                card_path  = os.path.join(app.config['UPLOAD_FOLDER'], 'cards', card_fname)
                _build_card(img.thumb_path, audit, card_path)
                img.card_path = card_path
                card_url = _r2_upload_card(card_path, uid + '_card')
                if card_url:
                    img.card_url = card_url
                result = {'filename': file.filename, 'score': img.score,
                          'tier': img.tier, 'status': 'scored'}
                # Write to cache
                try:
                    if img.phash and img.score and not getattr(img, 'is_flagged', False):
                        _bcs = (
                            "INSERT INTO scored_phash_cache "
                            "(user_id, phash, genre, score, tier, dod_score, disruption_score, "
                            " dm_score, wonder_score, aq_score, archetype, soul_bonus, "
                            " original_image_id, scored_at) "
                            "VALUES (:uid,:ph,:genre,:score,:tier,:dod,:dis,:dm,:wonder,:aq,:arch,:soul,:iid,NOW()) "
                            "ON CONFLICT (user_id, phash, genre) DO UPDATE SET "
                            " score=EXCLUDED.score, tier=EXCLUDED.tier, scored_at=NOW()"
                        )
                        db.session.execute(db.text(_bcs), {
                            'uid': img.user_id, 'ph': img.phash, 'genre': img.genre,
                            'score': img.score, 'tier': img.tier,
                            'dod': img.dod_score, 'dis': img.disruption_score,
                            'dm': img.dm_score, 'wonder': img.wonder_score,
                            'aq': img.aq_score, 'arch': img.archetype,
                            'soul': bool(img.soul_bonus), 'iid': img.id,
                        })
                except Exception as _bcwe:
                    app.logger.warning(f'[bulk_upload_one] cache write failed: {_bcwe}')
        else:
            img.status = 'pending'
            result = {'filename': file.filename, 'score': None,
                      'tier': None, 'status': 'uploaded'}

        # ── Breastfeeding flag ────────────────────────────────────────────────
        # bulk_upload_one scores synchronously so sub_genre is already known.
        # If engine detected lifestyle_intimate — auto-approve, no hold needed.
        # Any other sub-genre — hold for admin review.
        if _bulk_nsfw_breastfeeding:
            _bf_subgenre = (img.sub_genre or '').strip().lower()
            if _bf_subgenre == 'lifestyle_intimate':
                # Whitelisted — fine art documentary, respect user's visibility choice
                if img.is_public is not False:  # only make public if user didn't choose hidden
                    img.is_public = True
                app.logger.info(f'[bulk_upload_one] breastfeeding whitelisted: image={img.id} subgenre={_bf_subgenre}')
            else:
                img.needs_review   = True
                img.is_public      = False
                img.flagged_reason = f'Breastfeeding content detected — held for admin review. Sub-genre: {_bf_subgenre or "undetected"}.'
                img.flagged_at     = datetime.utcnow()
                app.logger.info(f'[bulk_upload_one] breastfeeding flag set: image={img.id} subgenre={_bf_subgenre}')
                # Send admin review email
                try:
                    _bfu_emails = _admin_notify_emails() or [ADMIN_NOTIFY_EMAIL]
                    _bfu_site   = os.getenv('SITE_URL', 'https://shutterleague.com')
                    _bfu_u      = User.query.get(img.user_id)
                    send_email(
                        _bfu_emails,
                        f'[Content Review] Breastfeeding Image — {img.asset_name or "Untitled"} (ID: {img.id})',
                        (
                            '<div style="font-family:Courier New,monospace;max-width:560px;margin:0 auto;padding:32px;">'
                            '<p style="color:#C8A84B;font-weight:700;font-size:15px;">CONTENT REVIEW REQUIRED — BREASTFEEDING IMAGE</p>'
                            f'<p>Image: <strong>{img.asset_name or "Untitled"}</strong> (ID: {img.id})<br>'
                            f'Photographer: {(_bfu_u.username if _bfu_u else "unknown")} ({(_bfu_u.email if _bfu_u else "unknown")})<br>'
                            f'Genre: {img.genre or "—"}<br>'
                            f'Sub-genre: <strong>{_bf_subgenre or "undetected"}</strong></p>'
                            '<p>This image has been held from public view pending your review.</p>'
                            f'<a href="{_bfu_site}/admin/image/{img.id}" '
                            'style="display:inline-block;background:#C8A84B;color:#1a1a18;'
                            'font-family:Courier New,monospace;font-size:13px;font-weight:700;'
                            'letter-spacing:1px;text-transform:uppercase;padding:12px 24px;'
                            'text-decoration:none;border-radius:4px;margin:16px 0;">'
                            'Review &amp; Approve &#8594;</a>'
                            '</div>'
                        )
                    )
                    app.logger.info(f'[bulk_upload_one] breastfeeding admin email sent: image={img.id}')
                except Exception as _bfu_email_err:
                    app.logger.warning(f'[bulk_upload_one] breastfeeding admin email failed: {_bfu_email_err}')

        db.session.commit()

    except Exception as e:
        try:
            db.session.rollback()
        except Exception:
            pass
        import traceback
        app.logger.error('bulk_upload_one error for ' + file.filename + ': ' + traceback.format_exc())
        result = {'filename': file.filename, 'status': 'error: ' + str(e)[:120],
                  'score': None, 'tier': None}

    return jsonify(result), 200

# ---------------------------------------------------------------------------
# Peer Rating Routes
# ---------------------------------------------------------------------------

def _moderate_eval_text(what_struck: str, improvement: str) -> dict:
    """
    Haiku moderation on peer evaluation text fields.
    Returns {ok: bool, reason: str|None}.
    Rejects: profanity, religious expressions, abusive language, off-topic content,
    meaningless filler. Supports English + common Indian languages.
    Fails open — returns ok=True if API call fails, to avoid blocking evaluators.
    """
    try:
        from auto_score import MODEL_HAIKU
        _mod_model = MODEL_HAIKU
    except ImportError:
        _mod_model = 'claude-haiku-4-5-20251001'

    _prompt = (
        "You are a moderation assistant for a photography peer evaluation platform. "
        "Two text fields from an evaluation are below. Decide if both are acceptable.\n\n"
        "REJECT if either field contains:\n"
        "- Profanity, cuss words, or abusive language (English or Indian languages: Hindi, Tamil, Kannada, Telugu, Marathi)\n"
        "- Religious expressions used as expletives or filler\n"
        "- Personal attacks on the photographer\n"
        "- Content unrelated to the photograph (gear complaints, platform feedback, social commentary)\n"
        "- Meaningless filler only: 'looks great', 'nice photo', 'perfect as is', 'nothing to improve'\n\n"
        "ACCEPT if both fields provide specific observations about the photograph's "
        "technical or compositional qualities — even if brief.\n\n"
        f"WHAT STRUCK THE EVALUATOR:\n{what_struck}\n\n"
        f"ONE THING TO IMPROVE:\n{improvement}\n\n"
        'Respond ONLY with JSON: {"ok": true, "reason": null} or {"ok": false, "reason": "short reason"}'
    )
    try:
        import anthropic as _ant
        _client = _ant.Anthropic()
        _resp = _client.messages.create(
            model=_mod_model, max_tokens=80,
            messages=[{'role': 'user', 'content': _prompt}]
        )
        import json as _json
        return _json.loads(_resp.content[0].text.strip())
    except Exception as _e:
        app.logger.warning(f'[eval_moderation] failed (non-fatal): {_e}')
        return {'ok': True, 'reason': None}


@app.route('/rate')
@login_required
def rate():
    """Blind peer rating queue page."""
    from datetime import date as _date
    from sqlalchemy import extract

    user = current_user
    user.reset_credits_if_needed()
    db.session.commit()

    is_subscriber = getattr(user, 'is_subscribed', False)
    credits       = user.rating_credits or 0
    lifetime      = user.lifetime_ratings_given or 0

    now = datetime.utcnow()
    month_given = PeerRating.query.filter(
        PeerRating.rater_id == user.id,
        extract('month', PeerRating.rated_at) == now.month,
        extract('year',  PeerRating.rated_at) == now.year,
    ).count()

    assignment      = None
    image           = None
    queue_remaining = 0

    if is_subscriber:
        # If a specific assignment_id is passed (from dashboard card), load that one
        _requested_assignment_id = request.args.get('assignment', type=int)
        if _requested_assignment_id:
            _req_a = RatingAssignment.query.filter_by(
                id=_requested_assignment_id, rater_id=user.id
            ).first()
            if _req_a and _req_a.status in ('assigned', 'started'):
                if _req_a.status == 'assigned':
                    _req_a.status = 'started'
                    _req_a.started_at = datetime.utcnow()
                    db.session.commit()
                assignment = _req_a
                image = _req_a.image
        if not assignment:
            # Direct assignment — no tier chain dependency (Session 112)
            try:
                from datetime import timedelta as _td2
                _already_rated = db.session.query(RatingAssignment.image_id).filter(
                    RatingAssignment.rater_id == user.id,
                ).subquery()
                _next_img = (
                    Image.query.join(User, Image.user_id == User.id)
                    .filter(
                        Image.status      == 'scored',
                        Image.is_public   == True,
                        Image.is_flagged  == False,
                        Image.needs_review == False,
                        Image.score       != None,
                        Image.genre       != None,
                        Image.user_id     != user.id,
                        User.is_subscribed == True,
                        Image.id.notin_(_already_rated),
                    )
                    .order_by(Image.peer_rating_count.asc().nullsfirst(), Image.scored_at.desc())
                    .first()
                )
                if _next_img:
                    assignment = RatingAssignment(
                        rater_id   = user.id,
                        image_id   = _next_img.id,
                        status     = 'started',
                        tier_slot  = 'any',
                        started_at = datetime.utcnow(),
                        expires_at = datetime.utcnow() + _td2(hours=72),
                    )
                    db.session.add(assignment)
                    db.session.flush()
                    try:
                        db.session.execute(db.text(
                            "UPDATE rating_assignments SET genre=:g WHERE id=:id"
                        ), {'g': _next_img.genre, 'id': assignment.id})
                    except Exception:
                        pass
                    db.session.commit()
                    image = assignment.image
            except Exception as _re:
                app.logger.warning(f'[rate] assignment error: {_re}')
                db.session.rollback()

        already = db.session.query(RatingAssignment.image_id).filter(
            RatingAssignment.rater_id == user.id,
        ).subquery()
        queue_remaining = (
            Image.query
            .join(User, Image.user_id == User.id)
            .filter(
                Image.status == 'scored', Image.is_public == True,
                Image.is_flagged == False, Image.needs_review == False,
                Image.score != None, Image.user_id != user.id,
                User.is_subscribed == True,
                Image.id.notin_(already),
            ).count()
        )

    today = _date.today()
    if today.month == 12:
        next_reset = _date(today.year + 1, 1, 1)
    else:
        next_reset = _date(today.year, today.month + 1, 1)

    return render_template('rate.html',
        is_subscriber   = is_subscriber,
        credits         = credits,
        lifetime_given  = lifetime,
        month_given     = month_given,
        assignment      = assignment,
        image           = image,
        queue_remaining = queue_remaining,
        next_reset      = next_reset.strftime('%-d %B'),
        bias_flag       = getattr(user, 'rating_bias_flag', False),
    )


@app.route('/rate/submit', methods=['POST'])
@login_required
def submit_rating():
    """Submit a completed peer rating."""
    assignment_id = request.form.get('assignment_id', type=int)
    if not assignment_id:
        flash('Invalid request.', 'error')
        return redirect(url_for('rate'))

    assignment = RatingAssignment.query.get(assignment_id)
    if not assignment or assignment.rater_id != current_user.id:
        flash('Rating assignment not found.', 'error')
        return redirect(url_for('rate'))

    if assignment.status == 'submitted':
        flash('You have already submitted this rating.', 'info')
        return redirect(url_for('rate'))

    current_user.reset_credits_if_needed()

    # Server-side time check  -  must be 13s (2s tolerance for network)
    client_start = request.form.get('client_start_ts', type=int)
    time_spent   = request.form.get('time_spent', type=int) or 0
    if client_start:
        server_elapsed = int((datetime.utcnow().timestamp() * 1000 - client_start) / 1000)
        if server_elapsed < 13:
            flash('Please spend more time viewing the image before rating.', 'warning')
            return redirect(url_for('rate'))

    try:
        dod        = float(request.form.get('dod', 5))
        disruption = float(request.form.get('disruption', 5))
        dm         = float(request.form.get('dm', 5))
        wonder     = float(request.form.get('wonder', 5))
        aq         = float(request.form.get('aq', 5))
    except (ValueError, TypeError):
        flash('Invalid scores submitted.', 'error')
        return redirect(url_for('rate'))

    def clamp(v):
        return max(1.0, min(10.0, round(v * 2) / 2))
    dod        = clamp(dod)
    disruption = clamp(disruption)
    dm         = clamp(dm)
    wonder     = clamp(wonder)
    aq         = clamp(aq)

    # ── Mandatory text fields ────────────────────────────────────────────────
    what_struck = (request.form.get('what_struck') or '').strip()
    improvement = (request.form.get('improvement') or '').strip()
    if len(what_struck) < 20:
        flash('Please describe what struck you about this image (at least 20 characters).', 'warning')
        return redirect(url_for('rate'))
    if len(improvement) < 20:
        flash('Please suggest one thing that would strengthen this image (at least 20 characters).', 'warning')
        return redirect(url_for('rate'))

    # ── Haiku moderation ─────────────────────────────────────────────────────
    _mod = _moderate_eval_text(what_struck, improvement)
    if not _mod.get('ok', True):
        _mod_reason = _mod.get('reason') or 'Please focus your feedback on the photograph itself.'
        flash(f'Your feedback was not accepted. {_mod_reason}', 'warning')
        return redirect(url_for('rate'))

    try:
        rating = submit_peer_rating(
            assignment  = assignment,
            dod         = dod,
            disruption  = disruption,
            dm          = dm,
            wonder      = wonder,
            aq          = aq,
            time_spent  = time_spent,
            what_struck = what_struck,
            improvement = improvement,
        )
        # Award base points (+2) + calibration bonus (+2 if within ±10%)
        _base_pts  = 2.0
        _bonus_pts = 0.0
        try:
            if current_user.is_subscribed:
                award_points(current_user, _base_pts, 'peer_rating')
                # Check if calibrated within ±10%
                _engine_score = assignment.image.score or 0
                if _engine_score > 0:
                    _delta_pct = abs(rating.peer_ll_score - _engine_score) / _engine_score * 100
                    if _delta_pct <= 10.0:
                        _bonus_pts = 2.0
                        award_points(current_user, _bonus_pts, 'peer_rating')
        except Exception as _pe:
            app.logger.error(f'[points hook] peer_rating error: {_pe}')

        _calibrated    = _bonus_pts > 0
        _peer_score_f  = rating.peer_ll_score if rating and rating.peer_ll_score else 0.0
        _engine_score_f = assignment.image.score or 0.0
        _pts_delta     = abs(_peer_score_f - _engine_score_f)
        if _calibrated:
            _flash_msg = (
                f'You have the eye of the judge \u2014 +2 bonus credited. '
                f'Your read: {_peer_score_f:.1f}\u00a0|\u00a0Engine: {_engine_score_f:.1f}'
            )
        else:
            _flash_msg = (
                f'You were {_pts_delta:.1f} points off. Keep judging to hone your eye. '
                f'Your read: {_peer_score_f:.1f}\u00a0|\u00a0Engine: {_engine_score_f:.1f}'
            )
        flash(_flash_msg, 'success')
        # Store last eval result in session for 24hr persistent dashboard block (P5)
        import time as _time_p5
        session['last_eval_result'] = {
            'calibrated':    _calibrated,
            'peer_score':    round(_peer_score_f, 1),
            'engine_score':  round(_engine_score_f, 1),
            'pts_delta':     round(_pts_delta, 1),
            'submitted_at':  int(_time_p5.time()),
        }

        # Zone notifications
        img = assignment.image
        photographer = User.query.get(img.user_id) if img else None
        if img and photographer:
            if img.needs_review and img.judge_referral and img.peer_avg_score is not None:
                delta = abs((img.peer_avg_score or 0) - (img.score or 0))
                # Zone 3 - notify photographer
                try:
                    send_email(
                        photographer.email,
                        'Your image is under peer review - Shutter League',
                        f'<div style="font-family:Georgia,serif;max-width:560px;margin:0 auto;padding:32px;color:#1a1a18;">'
                        f'<p style="font-family:Courier New,monospace;font-size:12px;letter-spacing:2px;text-transform:uppercase;color:#B8892A;">Shutter League</p>'
                        f'<h2 style="font-size:22px;font-weight:700;margin-bottom:16px;">Peer Review Triggered</h2>'
                        f'<p style="font-size:16px;line-height:1.7;color:#4A4840;">Your image <strong>"{img.asset_name or "Untitled"}"</strong> has received peer ratings that diverge significantly from its DDI score. Your DDI score of <strong style="color:#B8892A;">{img.score}</strong> is protected and unchanged.</p>'
                        f'<p style="font-size:16px;line-height:1.7;color:#4A4840;">This image has been referred to our jury for review. You will be notified once the review is complete. No action is required from you.</p>'
                        f'<p style="font-size:14px;color:#8A8478;margin-top:24px;">Questions? Contact <a href="mailto:'+CONTACT_EMAIL+'" style="color:#B8892A;">'+CONTACT_EMAIL+'</a></p>'
                        f'</div>'
                    )
                except Exception as mail_err:
                    app.logger.error(f'[zone3 photographer email] {mail_err}')
                # Zone 3 - notify admin
                try:
                    admin_emails = _admin_notify_emails()
                    if admin_emails:
                        send_email(
                            admin_emails,
                            f'[Zone 3] Peer divergence on image #{img.id} - {img.asset_name}',
                            f'<div style="font-family:Courier New,monospace;max-width:560px;margin:0 auto;padding:32px;color:#1a1a18;">'
                            f'<p style="font-size:14px;font-weight:700;color:#C0392B;">ZONE 3 - PEER DIVERGENCE ALERT</p>'
                            f'<p style="font-size:14px;line-height:1.7;">Image: <strong>{img.asset_name or "Untitled"}</strong> (ID: {img.id})<br>'
                            f'Photographer: {photographer.username} ({photographer.email})<br>'
                            f'DDI Score: {img.score}<br>'
                            f'Peer Average: {img.peer_avg_score}<br>'
                            f'Delta: {round(delta, 2)}<br>'
                            f'Peer Rating Count: {img.peer_rating_count}<br>'
                            f'Status: needs_review=True, judge_referral=True</p>'
                            f'<p style="font-size:13px;color:#8A8478;">DDI score is protected. Blended score not applied to POTY. Jury review triggered automatically.</p>'
                            f'</div>'
                        )
                except Exception as mail_err:
                    app.logger.error(f'[zone3 admin email] {mail_err}')

            elif getattr(img, 'peer_review_pending', False) and not img.needs_review:
                # Zone 2 - notify photographer only
                try:
                    send_email(
                        photographer.email,
                        'Peer review in progress on your image - Shutter League',
                        f'<div style="font-family:Georgia,serif;max-width:560px;margin:0 auto;padding:32px;color:#1a1a18;">'
                        f'<p style="font-family:Courier New,monospace;font-size:12px;letter-spacing:2px;text-transform:uppercase;color:#B8892A;">Shutter League</p>'
                        f'<h2 style="font-size:22px;font-weight:700;margin-bottom:16px;">Peer Review In Progress</h2>'
                        f'<p style="font-size:16px;line-height:1.7;color:#4A4840;">Your image <strong>"{img.asset_name or "Untitled"}"</strong> is receiving peer ratings that are being reviewed for consistency. Your DDI score of <strong style="color:#B8892A;">{img.score}</strong> stands and is unaffected.</p>'
                        f'<p style="font-size:16px;line-height:1.7;color:#4A4840;">This is an automated notice. No action is required from you. The peer review process will complete automatically.</p>'
                        f'<p style="font-size:14px;color:#8A8478;margin-top:24px;">Questions? Contact <a href="mailto:'+CONTACT_EMAIL+'" style="color:#B8892A;">'+CONTACT_EMAIL+'</a></p>'
                        f'</div>'
                    )
                except Exception as mail_err:
                    app.logger.error(f'[zone2 photographer email] {mail_err}')

            # ── P6: Owner notification — always send on every peer eval (Session 113) ──
            # Blind: evaluator tier shown, name never shown.
            # Sent regardless of zone — zone emails above are divergence alerts,
            # this is the learning loop notification.
            try:
                _rater_tier = getattr(current_user, 'tier', None) or 'Photographer'
                _genre      = img.genre or 'Photography'
                _img_url    = (os.getenv('SITE_URL', 'https://shutterleague.com')
                               + '/image/' + str(img.id))
                send_email(
                    photographer.email,
                    f'Your {_genre} image was evaluated by a {_rater_tier} photographer — Shutter League',
                    f'<div style="font-family:Georgia,serif;max-width:560px;margin:0 auto;padding:32px;color:#1a1a18;">'
                    f'<p style="font-family:Courier New,monospace;font-size:12px;letter-spacing:2px;'
                    f'text-transform:uppercase;color:#B8892A;">Shutter League · Peer Evaluation</p>'
                    f'<h2 style="font-size:22px;font-weight:700;margin:16px 0 8px;color:#1a1a18;">'
                    f'A {_rater_tier} photographer evaluated your {_genre} image</h2>'
                    f'<p style="font-size:15px;line-height:1.7;color:#4A4840;margin-bottom:24px;">'
                    f'Their read is below. The evaluator is anonymous — only their tier is shown.</p>'
                    f'<div style="background:#F8F7F3;border-left:3px solid #B8892A;border-radius:0 8px 8px 0;'
                    f'padding:16px 20px;margin-bottom:16px;">'
                    f'<p style="font-size:11px;font-weight:700;letter-spacing:2px;text-transform:uppercase;'
                    f'color:#B8892A;margin:0 0 8px;">What stood out</p>'
                    f'<p style="font-size:16px;line-height:1.7;color:#1a1a18;margin:0;">{what_struck}</p>'
                    f'</div>'
                    f'<div style="background:#F8F7F3;border-left:3px solid #4A4840;border-radius:0 8px 8px 0;'
                    f'padding:16px 20px;margin-bottom:24px;">'
                    f'<p style="font-size:11px;font-weight:700;letter-spacing:2px;text-transform:uppercase;'
                    f'color:#4A4840;margin:0 0 8px;">One thing to improve</p>'
                    f'<p style="font-size:16px;line-height:1.7;color:#1a1a18;margin:0;">{improvement}</p>'
                    f'</div>'
                    f'<a href="{_img_url}" style="display:inline-block;background:#B8892A;color:#fff;'
                    f'font-size:15px;font-weight:700;padding:12px 24px;border-radius:8px;'
                    f'text-decoration:none;margin-bottom:24px;">See your evaluation card →</a>'
                    f'<p style="font-size:13px;color:#8A8478;margin-top:8px;">'
                    f'Questions? Contact <a href="mailto:{CONTACT_EMAIL}" style="color:#B8892A;">'
                    f'{CONTACT_EMAIL}</a></p>'
                    f'</div>'
                )
                app.logger.info(f'[peer_eval_notify] owner={photographer.id} image={img.id} rater_tier={_rater_tier}')
            except Exception as _pen:
                app.logger.error(f'[peer_eval_notify] {_pen}')

    except Exception as e:
        db.session.rollback()
        app.logger.error(f'[submit_rating] {e}')
        flash('Upload failed. Please try again.', 'error')

    return redirect(url_for('rate'))


@app.route('/rate/skip', methods=['POST'])
@login_required
def skip_rating():
    """Skip a rating assignment  -  expires it, no credit cost."""
    assignment_id = request.form.get('assignment_id', type=int)
    if assignment_id:
        a = RatingAssignment.query.get(assignment_id)
        if a and a.rater_id == current_user.id and a.status != 'submitted':
            a.status = 'expired'
            db.session.commit()
    return redirect(url_for('rate'))


