# We use a lock file in /tmp — first worker to create it wins; others skip.
import fcntl as _fcntl
_sched_lock_path = '/tmp/sl_scheduler.lock'
_sched_lock_fh   = open(_sched_lock_path, 'w')
_sched_lock_held = False
try:
    _fcntl.flock(_sched_lock_fh, _fcntl.LOCK_EX | _fcntl.LOCK_NB)
    _sched_lock_held = True
except OSError:
    pass  # another worker already holds the lock

if _sched_lock_held:
    _scheduler = BackgroundScheduler(timezone='UTC')
    _scheduler.add_job(
        func             = auto_publish_weekly_challenge,
        trigger          = CronTrigger(day_of_week='mon', hour=13, minute=30, timezone='UTC'),
        id               = 'weekly_results',
        name             = 'Auto-publish weekly challenge results',
        replace_existing = True,
    )
    # Sprint 1 — annual 10% points reset (inactive users only) — 23:55 IST (18:25 UTC) on Dec 31
    _scheduler.add_job(
        func             = run_annual_points_expiry,
        trigger          = CronTrigger(month=12, day=31, hour=18, minute=25, timezone='UTC'),
        id               = 'annual_points_expiry',
        name             = 'Annual 10% points reset — inactive users only (Dec 31)',
        replace_existing = True,
    )
    # Points reset warning — Nov 1, 09:00 IST (03:30 UTC)
    _scheduler.add_job(
        func             = run_points_reset_warning_nov,
        trigger          = CronTrigger(month=11, day=1, hour=3, minute=30, timezone='UTC'),
        id               = 'points_warning_nov',
        name             = 'Points reset Nov 1 warning email — inactive users',
        replace_existing = True,
    )
    # Points reset final reminder — Dec 15, 09:00 IST (03:30 UTC)
    _scheduler.add_job(
        func             = run_points_reset_warning_dec,
        trigger          = CronTrigger(month=12, day=15, hour=3, minute=30, timezone='UTC'),
        id               = 'points_warning_dec',
        name             = 'Points reset Dec 15 final reminder — inactive users',
        replace_existing = True,
    )
    # Sprint 3 — monthly residency clock — 00:05 IST = 18:35 UTC on last day of month
    _scheduler.add_job(
        func             = run_monthly_residency_clock,
        trigger          = CronTrigger(day=1, hour=18, minute=35, timezone='UTC'),
        id               = 'monthly_residency_clock',
        name             = 'Monthly 6-6-12 residency clock increment',
        replace_existing = True,
    )
    # Re-engagement emailer — runs every hour
    _scheduler.add_job(
        func             = run_reengagement_emailer,
        trigger          = CronTrigger(minute=15, timezone='UTC'),
        id               = 'reengagement_emailer',
        name             = '24hr re-engagement email trigger',
        replace_existing = True,
    )
    # Daily signup digest — 09:00 IST = 03:30 UTC
    _scheduler.add_job(
        func             = run_daily_signup_digest,
        trigger          = CronTrigger(hour=3, minute=30, timezone='UTC'),
        id               = 'daily_signup_digest',
        name             = 'Daily admin digest — new member signups',
        replace_existing = True,
    )
    # Mentor 72hr reminder — runs every hour, fires when deadline < 24hrs away
    _scheduler.add_job(
        func             = run_mentor_reminders,
        trigger          = CronTrigger(minute=45, timezone='UTC'),
        id               = 'mentor_reminders',
        name             = 'Mentor review deadline reminders (24hr warning)',
        replace_existing = True,
    )
    # Item C — seasonal_shown_log prune (>60 days) — daily 03:45 UTC
    _scheduler.add_job(
        func             = run_seasonal_log_prune,
        trigger          = CronTrigger(hour=3, minute=45, timezone='UTC'),
        id               = 'seasonal_log_prune',
        name             = 'Prune seasonal_shown_log entries older than 60 days',
        replace_existing = True,
    )
    # Item D — seasonal auto-discovery — weekly, Sunday 04:00 UTC
    _scheduler.add_job(
        func             = run_seasonal_discovery_job,
        trigger          = CronTrigger(day_of_week='sun', hour=4, minute=0, timezone='UTC'),
        id               = 'seasonal_discovery',
        name             = 'Weekly seasonal calendar auto-discovery (item D)',
        replace_existing = True,
    )
    _scheduler.start()
    import atexit as _atexit
    _atexit.register(lambda: _scheduler.shutdown(wait=False))


if __name__ == '__main__':
    import sys
    if len(sys.argv) > 1 and sys.argv[1] == 'migrate':
        # Railway Pre-Deploy Command: `python app.py migrate`
        # Runs schema migrations + mentor seeding exactly once, in a single
        # dedicated process, before any Gunicorn worker exists. Exits clean
        # afterward -- never falls through to app.run() below.
        _run_startup_tasks()
        _seed_mentors()
    else:
        # Local development: `python app.py` (no args) -- unchanged behavior.
        app.run(debug=True)
